CREATE OR REPLACE FUNCTION "public"."anonymize_financial_records"("p_chef_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Temporarily disable ledger immutability triggers for anonymization
  ALTER TABLE ledger_entries DISABLE TRIGGER ALL;

  -- Anonymize ledger entries — keep amounts, dates, entry_type, sequence
  UPDATE ledger_entries
  SET description = 'REDACTED - Account Deleted',
      internal_notes = NULL
  WHERE tenant_id = p_chef_id;

  -- Re-enable ledger triggers
  ALTER TABLE ledger_entries ENABLE TRIGGER ALL;

  -- Anonymize events — keep financial data, dates, guest counts
  UPDATE events
  SET location_address = 'REDACTED',
      location_city = 'REDACTED',
      location_state = 'XX',
      location_zip = '00000',
      location_notes = NULL,
      access_instructions = NULL,
      special_requests = NULL,
      kitchen_notes = NULL,
      site_notes = NULL,
      cancellation_reason = CASE WHEN cancellation_reason IS NOT NULL
        THEN 'REDACTED' ELSE NULL END
  WHERE tenant_id = p_chef_id;

  -- Anonymize clients — keep IDs for FK integrity, strip PII
  UPDATE clients
  SET full_name = 'Deleted Client',
      email = 'deleted-' || id::text || '@redacted.local',
      phone = NULL,
      partner_name = NULL,
      children = NULL,
      address = NULL,
      parking_instructions = NULL,
      access_instructions = NULL,
      kitchen_size = NULL,
      kitchen_constraints = NULL,
      house_rules = NULL,
      vibe_notes = NULL,
      payment_behavior = NULL,
      tipping_pattern = NULL,
      what_they_care_about = NULL
  WHERE chef_id = p_chef_id;

EXCEPTION WHEN OTHERS THEN
  -- Always re-enable triggers even on failure
  ALTER TABLE ledger_entries ENABLE TRIGGER ALL;
  RAISE;
END;
$$;




COMMENT ON FUNCTION "public"."anonymize_financial_records"("p_chef_id" "uuid") IS 'Strips PII from financial records while preserving amounts/dates for 7-year retention. Called during account purge.';



CREATE OR REPLACE FUNCTION "public"."are_chefs_connected"("chef_a" "uuid", "chef_b" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM chef_connections
    WHERE status = 'accepted'
    AND (
      (requester_id = chef_a AND addressee_id = chef_b)
      OR
      (requester_id = chef_b AND addressee_id = chef_a)
    )
  )
$$;




COMMENT ON FUNCTION "public"."are_chefs_connected"("chef_a" "uuid", "chef_b" "uuid") IS 'Returns true if two chefs have an accepted connection. Works regardless of who sent the original request.';



CREATE OR REPLACE FUNCTION "public"."attach_menu_to_event_atomic"("p_event_id" "uuid", "p_menu_id" "uuid", "p_tenant_id" "uuid", "p_actor_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_course_count INTEGER;
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'chef' THEN
      RAISE EXCEPTION 'Chef role required';
    END IF;

    IF get_current_tenant_id() IS DISTINCT FROM p_tenant_id THEN
      RAISE EXCEPTION 'Tenant mismatch';
    END IF;

    IF auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  PERFORM 1
  FROM events
  WHERE id = p_event_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Event not found';
  END IF;

  PERFORM 1
  FROM menus
  WHERE id = p_menu_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Menu not found';
  END IF;

  SELECT COALESCE(get_menu_course_count(p_menu_id), 0) INTO v_course_count;

  UPDATE menus
  SET
    event_id = p_event_id,
    updated_by = p_actor_id,
    updated_at = NOW()
  WHERE id = p_menu_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL;

  UPDATE events
  SET
    menu_id = p_menu_id,
    course_count = GREATEST(v_course_count, 1),
    updated_by = p_actor_id,
    updated_at = NOW()
  WHERE id = p_event_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL;

  RETURN jsonb_build_object(
    'event_id', p_event_id,
    'menu_id', p_menu_id,
    'course_count', GREATEST(v_course_count, 1)
  );
END;
$$;




CREATE OR REPLACE FUNCTION "public"."check_client_tenant_match"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  client_tenant_id UUID;
BEGIN
  SELECT tenant_id INTO client_tenant_id
  FROM clients
  WHERE id = NEW.client_id;

  IF client_tenant_id IS NULL THEN
    RAISE EXCEPTION 'Client does not exist';
  END IF;

  IF client_tenant_id != NEW.tenant_id THEN
    RAISE EXCEPTION 'Client must belong to the same tenant';
  END IF;

  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."check_client_tenant_match"() IS 'Enforces tenant isolation - ensures client belongs to same tenant (used by future event tables)';



