CREATE OR REPLACE FUNCTION "public"."compute_menu_cost_cents"("p_menu_id" "uuid") RETURNS integer
    LANGUAGE "sql" STABLE
    AS $$
  SELECT COALESCE(SUM(
    compute_recipe_cost_cents(c.recipe_id)
  ), 0)
  FROM components c
  JOIN dishes d ON d.id = c.dish_id
  WHERE d.menu_id = p_menu_id AND c.recipe_id IS NOT NULL;
$$;




CREATE OR REPLACE FUNCTION "public"."compute_projected_food_cost_cents"("p_event_id" "uuid") RETURNS integer
    LANGUAGE "sql" STABLE
    AS $$
  SELECT compute_menu_cost_cents(m.id)
  FROM events e
  JOIN menus m ON m.event_id = e.id
  WHERE e.id = p_event_id;
$$;




CREATE OR REPLACE FUNCTION "public"."compute_recipe_cost_cents"("p_recipe_id" "uuid") RETURNS integer
    LANGUAGE "sql" STABLE
    AS $$
  WITH RECURSIVE all_recipe_costs AS (
    -- Base: the recipe itself, multiplier = 1
    SELECT
      p_recipe_id AS recipe_id,
      1.0::DECIMAL AS multiplier

    UNION ALL

    -- Sub-recipes: multiply by the sub-recipe's quantity
    SELECT
      rsr.child_recipe_id,
      arc.multiplier * rsr.quantity
    FROM recipe_sub_recipes rsr
    JOIN all_recipe_costs arc ON arc.recipe_id = rsr.parent_recipe_id
  )
  SELECT COALESCE(SUM(
    CASE
      WHEN COALESCE(i.cost_per_unit_cents, i.last_price_cents) IS NOT NULL THEN
        -- Cost = (unit_cost * quantity * multiplier) / (yield_pct / 100)
        (
          COALESCE(i.cost_per_unit_cents, i.last_price_cents)
          * ri.quantity
          * arc.multiplier
          * 100.0
          / COALESCE(NULLIF(ri.yield_pct, 0), NULLIF(i.default_yield_pct, 0), 100)
        )::INTEGER
      ELSE 0
    END
  ), 0)
  FROM all_recipe_costs arc
  JOIN recipe_ingredients ri ON ri.recipe_id = arc.recipe_id
  JOIN ingredients i ON i.id = ri.ingredient_id;
$$;




CREATE OR REPLACE FUNCTION "public"."create_cash_drawer_movement_from_payment"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_session_id UUID;
  v_amount_cents INTEGER;
BEGIN
  IF NEW.payment_method <> 'cash' THEN
    RETURN NEW;
  END IF;

  IF NEW.status NOT IN ('captured', 'settled') THEN
    RETURN NEW;
  END IF;

  IF NEW.sale_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT register_session_id
    INTO v_session_id
  FROM sales
  WHERE id = NEW.sale_id;

  IF v_session_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_amount_cents := NEW.amount_cents + COALESCE(NEW.tip_cents, 0);

  INSERT INTO cash_drawer_movements (
    tenant_id,
    register_session_id,
    movement_type,
    amount_cents,
    notes,
    metadata,
    commerce_payment_id,
    created_by,
    created_at,
    updated_at
  ) VALUES (
    NEW.tenant_id,
    v_session_id,
    'sale_payment',
    v_amount_cents,
    COALESCE(NEW.notes, 'Cash payment recorded'),
    jsonb_build_object(
      'sale_id', NEW.sale_id,
      'payment_status', NEW.status
    ),
    NEW.id,
    NEW.created_by,
    COALESCE(NEW.captured_at, NEW.created_at, now()),
    now()
  )
  ON CONFLICT (commerce_payment_id) DO NOTHING;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."create_cash_drawer_movement_from_refund"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_session_id UUID;
  v_payment_method payment_method;
BEGIN
  IF NEW.status <> 'processed' THEN
    RETURN NEW;
  END IF;

  SELECT s.register_session_id, p.payment_method
    INTO v_session_id, v_payment_method
  FROM commerce_payments p
  LEFT JOIN sales s ON s.id = p.sale_id
  WHERE p.id = NEW.payment_id;

  IF v_payment_method <> 'cash' THEN
    RETURN NEW;
  END IF;

  IF v_session_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO cash_drawer_movements (
    tenant_id,
    register_session_id,
    movement_type,
    amount_cents,
    notes,
    metadata,
    commerce_refund_id,
    created_by,
    created_at,
    updated_at
  ) VALUES (
    NEW.tenant_id,
    v_session_id,
    'refund',
    -1 * NEW.amount_cents,
    COALESCE(NEW.reason, 'Cash refund recorded'),
    jsonb_build_object(
      'payment_id', NEW.payment_id,
      'sale_id', NEW.sale_id
    ),
    NEW.id,
    NEW.created_by,
    COALESCE(NEW.processed_at, NEW.created_at, now()),
    now()
  )
  ON CONFLICT (commerce_refund_id) DO NOTHING;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."create_ledger_entry_from_commerce_payment"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_ledger_id UUID;
BEGIN
  -- Only create ledger entry for captured/settled payments with a client
  IF NEW.status NOT IN ('captured', 'settled') THEN
    RETURN NEW;
  END IF;

  IF NEW.client_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Skip if this payment already has a ledger entry (idempotency)
  IF NEW.ledger_entry_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO ledger_entries (
    tenant_id, client_id, entry_type, amount_cents,
    payment_method, description, event_id,
    transaction_reference, created_by
  ) VALUES (
    NEW.tenant_id,
    NEW.client_id,
    'payment',
    NEW.amount_cents,
    NEW.payment_method,
    COALESCE(NEW.notes, 'Payment via Commerce Engine'),
    NEW.event_id,
    NEW.transaction_reference,
    NEW.created_by
  )
  RETURNING id INTO v_ledger_id;

  -- Back-link the ledger entry
  NEW.ledger_entry_id := v_ledger_id;

  -- If there's a tip, create a separate ledger entry for it
  IF NEW.tip_cents > 0 THEN
    INSERT INTO ledger_entries (
      tenant_id, client_id, entry_type, amount_cents,
      payment_method, description, event_id,
      transaction_reference, created_by
    ) VALUES (
      NEW.tenant_id,
      NEW.client_id,
      'tip',
      NEW.tip_cents,
      NEW.payment_method,
      'Tip via Commerce Engine',
      NEW.event_id,
      CASE WHEN NEW.transaction_reference IS NOT NULL
        THEN NEW.transaction_reference || '_tip'
        ELSE NULL
      END,
      NEW.created_by
    );
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."create_ledger_entry_from_commerce_refund"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_payment RECORD;
  v_ledger_id UUID;
BEGIN
  IF NEW.status != 'processed' THEN
    RETURN NEW;
  END IF;

  -- Look up the original payment for context
  SELECT * INTO v_payment FROM commerce_payments WHERE id = NEW.payment_id;

  -- Only create ledger entry if the original payment has a client
  IF v_payment.client_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO ledger_entries (
    tenant_id, client_id, entry_type, amount_cents,
    payment_method, description, event_id,
    is_refund, refund_reason,
    transaction_reference, created_by
  ) VALUES (
    NEW.tenant_id,
    v_payment.client_id,
    'refund',
    -1 * NEW.amount_cents,   -- Refunds are negative in the ledger
    v_payment.payment_method,
    COALESCE(NEW.reason, 'Refund via Commerce Engine'),
    v_payment.event_id,
    true,
    NEW.reason,
    'refund_' || NEW.id::TEXT,
    NEW.created_by
  )
  RETURNING id INTO v_ledger_id;

  NEW.ledger_entry_id := v_ledger_id;
  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."current_chef_is_handoff_recipient"("p_handoff_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    get_current_user_role() = 'chef'
    AND EXISTS (
      SELECT 1
      FROM chef_handoff_recipients r
      WHERE r.handoff_id = p_handoff_id
        AND r.recipient_chef_id = get_current_tenant_id()
    );
$$;




COMMENT ON FUNCTION "public"."current_chef_is_handoff_recipient"("p_handoff_id" "uuid") IS 'Returns true when the current authenticated chef is a recipient of the given collaboration handoff. Uses SECURITY DEFINER to avoid recursive RLS checks.';



CREATE OR REPLACE FUNCTION "public"."current_chef_owns_handoff"("p_handoff_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    get_current_user_role() = 'chef'
    AND EXISTS (
      SELECT 1
      FROM chef_handoffs h
      WHERE h.id = p_handoff_id
        AND h.from_chef_id = get_current_tenant_id()
    );
$$;




COMMENT ON FUNCTION "public"."current_chef_owns_handoff"("p_handoff_id" "uuid") IS 'Returns true when the current authenticated chef authored the given collaboration handoff. Uses SECURITY DEFINER to avoid recursive RLS checks.';



CREATE OR REPLACE FUNCTION "public"."detach_menu_from_event_atomic"("p_menu_id" "uuid", "p_tenant_id" "uuid", "p_actor_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_event_id UUID;
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'chef' THEN
      RAISE EXCEPTION 'Chef role required';
    END IF;

    IF get_current_tenant_id() IS DISTINCT FROM p_tenant_id THEN
      RAISE EXCEPTION 'Tenant mismatch';
    END IF;

    IF auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  SELECT event_id
  INTO v_event_id
  FROM menus
  WHERE id = p_menu_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Menu not found';
  END IF;

  UPDATE menus
  SET
    event_id = NULL,
    updated_by = p_actor_id,
    updated_at = NOW()
  WHERE id = p_menu_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL;

  IF v_event_id IS NOT NULL THEN
    UPDATE events
    SET
      menu_id = NULL,
      updated_by = p_actor_id,
      updated_at = NOW()
    WHERE id = v_event_id
      AND tenant_id = p_tenant_id
      AND menu_id = p_menu_id;
  END IF;

  RETURN jsonb_build_object(
    'menu_id', p_menu_id,
    'event_id', v_event_id
  );
END;
$$;




CREATE OR REPLACE FUNCTION "public"."enforce_cannabis_control_packet_evidence_lock"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  is_locked BOOLEAN;
BEGIN
  SELECT finalization_locked
  INTO is_locked
  FROM cannabis_control_packet_snapshots
  WHERE id = OLD.snapshot_id;

  IF is_locked THEN
    RAISE EXCEPTION 'Cannot delete evidence from a finalized control packet';
  END IF;

  RETURN OLD;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."enforce_cannabis_control_packet_reconciliation_lock"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  is_locked BOOLEAN;
BEGIN
  SELECT finalization_locked
  INTO is_locked
  FROM cannabis_control_packet_snapshots
  WHERE id = COALESCE(NEW.snapshot_id, OLD.snapshot_id);

  IF TG_OP = 'DELETE' THEN
    IF is_locked THEN
      RAISE EXCEPTION 'Cannot delete reconciliation for a finalized control packet';
    END IF;
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF is_locked THEN
      RAISE EXCEPTION 'Cannot edit reconciliation for a finalized control packet';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."enforce_cannabis_control_packet_snapshot_immutability"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    RAISE EXCEPTION 'Control packet snapshots are immutable and cannot be deleted';
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.finalization_locked THEN
      RAISE EXCEPTION 'Finalized control packet snapshots cannot be modified';
    END IF;

    IF NEW.event_id IS DISTINCT FROM OLD.event_id
      OR NEW.tenant_id IS DISTINCT FROM OLD.tenant_id
      OR NEW.version_number IS DISTINCT FROM OLD.version_number
      OR NEW.generated_at IS DISTINCT FROM OLD.generated_at
      OR NEW.generated_by IS DISTINCT FROM OLD.generated_by
      OR NEW.guest_snapshot IS DISTINCT FROM OLD.guest_snapshot
      OR NEW.seating_snapshot IS DISTINCT FROM OLD.seating_snapshot
      OR NEW.participation_snapshot IS DISTINCT FROM OLD.participation_snapshot
      OR NEW.snapshot_json IS DISTINCT FROM OLD.snapshot_json
      OR NEW.course_count IS DISTINCT FROM OLD.course_count
      OR NEW.layout_type IS DISTINCT FROM OLD.layout_type
      OR NEW.layout_meta IS DISTINCT FROM OLD.layout_meta
      OR NEW.source_guest_updated_at IS DISTINCT FROM OLD.source_guest_updated_at
      OR NEW.created_at IS DISTINCT FROM OLD.created_at
    THEN
      RAISE EXCEPTION 'Snapshot payload is immutable. Generate a new version instead.';
    END IF;

    IF OLD.finalization_locked = false AND NEW.finalization_locked = true THEN
      IF NEW.finalized_at IS NULL THEN
        RAISE EXCEPTION 'Finalized snapshot requires finalized_at';
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."enforce_product_public_media_link_integrity"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  linked_product_tenant UUID;
  asset_approval_status TEXT;
BEGIN
  SELECT tenant_id
  INTO linked_product_tenant
  FROM public.product_projections
  WHERE id = NEW.product_id;

  IF linked_product_tenant IS NULL THEN
    RAISE EXCEPTION 'Product % not found for public media link', NEW.product_id;
  END IF;

  IF NEW.tenant_id IS DISTINCT FROM linked_product_tenant THEN
    RAISE EXCEPTION 'Product public media link tenant mismatch';
  END IF;

  SELECT approval_status
  INTO asset_approval_status
  FROM public.public_media_assets
  WHERE id = NEW.public_media_asset_id;

  IF asset_approval_status IS NULL THEN
    RAISE EXCEPTION 'Public media asset % not found', NEW.public_media_asset_id;
  END IF;

  IF asset_approval_status <> 'approved' THEN
    RAISE EXCEPTION 'Public media asset % must be approved before linking', NEW.public_media_asset_id;
  END IF;

  RETURN NEW;
END;
$$;




