CREATE OR REPLACE FUNCTION "public"."generate_order_number"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  today_count INTEGER;
  letter CHAR(1);
  num TEXT;
BEGIN
  -- Count today's orders for this tenant
  SELECT COUNT(*) + 1 INTO today_count
  FROM order_queue
  WHERE tenant_id = NEW.tenant_id
    AND created_at::date = CURRENT_DATE;

  -- Letter cycles A-Z based on day of month
  letter := CHR(64 + (EXTRACT(DOY FROM CURRENT_DATE)::integer % 26) + 1);

  -- 3-digit padded number
  num := LPAD(today_count::text, 3, '0');

  NEW.order_number := letter || '-' || num;
  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."generate_sale_number"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_year TEXT;
  v_count INTEGER;
BEGIN
  IF NEW.sale_number IS NOT NULL THEN
    RETURN NEW;
  END IF;

  v_year := EXTRACT(YEAR FROM COALESCE(NEW.created_at, NOW()))::TEXT;

  SELECT COUNT(*) + 1 INTO v_count
  FROM sales
  WHERE tenant_id = NEW.tenant_id
    AND EXTRACT(YEAR FROM created_at) = EXTRACT(YEAR FROM COALESCE(NEW.created_at, NOW()));

  NEW.sale_number := 'SL-' || v_year || '-' || LPAD(v_count::TEXT, 5, '0');
  RETURN NEW;
END;
$$;




