CREATE OR REPLACE FUNCTION "public"."log_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  tenant_id_value UUID;
  change_desc TEXT;
BEGIN
  -- Determine tenant_id if available
  IF TG_TABLE_NAME = 'chefs' THEN
    tenant_id_value := NULL;
  ELSIF TG_TABLE_NAME IN ('clients', 'inquiries', 'messages', 'response_templates') THEN
    IF TG_OP = 'DELETE' THEN
      tenant_id_value := OLD.tenant_id;
    ELSE
      tenant_id_value := NEW.tenant_id;
    END IF;
  ELSE
    tenant_id_value := NULL;
  END IF;

  -- Generate human-readable change summary
  IF TG_OP = 'INSERT' THEN
    change_desc := 'Created new ' || TG_TABLE_NAME || ' record';
  ELSIF TG_OP = 'UPDATE' THEN
    change_desc := 'Updated ' || TG_TABLE_NAME || ' record';
  ELSIF TG_OP = 'DELETE' THEN
    change_desc := 'Deleted ' || TG_TABLE_NAME || ' record';
  END IF;

  -- Insert audit record
  INSERT INTO audit_log (
    tenant_id,
    table_name,
    record_id,
    action,
    changed_by,
    changed_at,
    before_values,
    after_values,
    change_summary
  ) VALUES (
    tenant_id_value,
    TG_TABLE_NAME,
    COALESCE(NEW.id, OLD.id),
    TG_OP,
    auth.uid(),
    now(),
    CASE WHEN TG_OP IN ('UPDATE', 'DELETE') THEN row_to_json(OLD) ELSE NULL END,
    CASE WHEN TG_OP IN ('INSERT', 'UPDATE') THEN row_to_json(NEW) ELSE NULL END,
    change_desc
  );

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$$;




COMMENT ON FUNCTION "public"."log_audit"() IS 'Logs all mutations to audit_log table with before/after snapshots (extended for Layer 2 tables)';



