CREATE OR REPLACE FUNCTION "public"."prevent_circular_sub_recipe"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  has_cycle BOOLEAN;
BEGIN
  -- Walk from the child upward: does it eventually reach the parent?
  -- If so, adding parent→child would create a cycle.
  WITH RECURSIVE ancestors AS (
    -- Start: all recipes that are parents of the NEW parent_recipe_id
    SELECT parent_recipe_id AS recipe_id
    FROM recipe_sub_recipes
    WHERE child_recipe_id = NEW.parent_recipe_id

    UNION

    -- Walk upward
    SELECT rsr.parent_recipe_id
    FROM recipe_sub_recipes rsr
    JOIN ancestors a ON a.recipe_id = rsr.child_recipe_id
  )
  SELECT EXISTS (
    SELECT 1 FROM ancestors WHERE recipe_id = NEW.child_recipe_id
  ) INTO has_cycle;

  IF has_cycle THEN
    RAISE EXCEPTION 'Circular sub-recipe reference detected: adding % as sub-recipe of % would create a cycle',
      NEW.child_recipe_id, NEW.parent_recipe_id;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."prevent_event_allergy_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Allow changes only during draft and proposed phases.
  IF OLD.status NOT IN ('draft', 'proposed') THEN
    IF NEW.allergies IS DISTINCT FROM OLD.allergies THEN
      RAISE EXCEPTION
        'Event allergy information is immutable once accepted. '
        'The allergies field is safety-critical and cannot change '
        'when status is %. '
        'Event ID: %',
        OLD.status, OLD.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."prevent_event_allergy_mutation"() IS 'Food safety guard. Prevents allergy field modification after client acceptance. Enforces the schema comment: IMMUTABLE after event creation (safety-critical). Fires on UPDATE OF allergies.';



CREATE OR REPLACE FUNCTION "public"."prevent_event_price_mutation_after_acceptance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Pricing is mutable only during draft and proposed phases.
  -- Once a client accepts, all three fields are locked.
  IF OLD.status NOT IN ('draft', 'proposed') THEN
    IF (
      NEW.quoted_price_cents   IS DISTINCT FROM OLD.quoted_price_cents   OR
      NEW.deposit_amount_cents IS DISTINCT FROM OLD.deposit_amount_cents OR
      NEW.pricing_model        IS DISTINCT FROM OLD.pricing_model
    ) THEN
      RAISE EXCEPTION
        'Event pricing is immutable once accepted. '
        'quoted_price_cents, deposit_amount_cents, and pricing_model '
        'cannot be changed when status is %. '
        'Event ID: %',
        OLD.status, OLD.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."prevent_event_price_mutation_after_acceptance"() IS 'Financial integrity guard. Prevents pricing field modification after client acceptance. Complementary to the append-only ledger trigger. Fires on UPDATE OF quoted_price_cents, deposit_amount_cents, pricing_model.';



CREATE OR REPLACE FUNCTION "public"."prevent_event_pricing_drift_from_accepted_quote"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_quote quotes%ROWTYPE;
BEGIN
  -- Trigger is scoped to pricing fields only, so no-op check not needed.

  IF NEW.converting_quote_id IS NOT NULL THEN
    SELECT *
    INTO v_quote
    FROM quotes
    WHERE id = NEW.converting_quote_id
      AND tenant_id = NEW.tenant_id
      AND deleted_at IS NULL
      AND status = 'accepted';
  END IF;

  IF NOT FOUND THEN
    SELECT *
    INTO v_quote
    FROM quotes q
    WHERE q.event_id = NEW.id
      AND q.tenant_id = NEW.tenant_id
      AND q.deleted_at IS NULL
      AND q.status = 'accepted'
    ORDER BY q.accepted_at DESC NULLS LAST, q.created_at DESC
    LIMIT 1;
  END IF;

  IF FOUND THEN
    IF (
      NEW.quoted_price_cents IS DISTINCT FROM v_quote.total_quoted_cents
      OR NEW.deposit_amount_cents IS DISTINCT FROM v_quote.deposit_amount_cents
      OR NEW.pricing_model IS DISTINCT FROM v_quote.pricing_model
    ) THEN
      RAISE EXCEPTION
        'Event pricing must match accepted quote %. Update by revising and accepting a new quote.',
        v_quote.id;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."prevent_inquiry_transition_modification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RAISE EXCEPTION 'Inquiry state transitions are immutable. They form an audit trail.';
END;
$$;




COMMENT ON FUNCTION "public"."prevent_inquiry_transition_modification"() IS 'Enforces immutability on inquiry_state_transitions table';



CREATE OR REPLACE FUNCTION "public"."prevent_ledger_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RAISE EXCEPTION 'Ledger entries are immutable. Only INSERT allowed.';
END;
$$;




