CREATE OR REPLACE FUNCTION "public"."prevent_quote_mutation_after_acceptance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF OLD.snapshot_frozen = true AND OLD.status = NEW.status THEN
    -- Only status transitions allowed, no other changes
    IF (OLD.total_quoted_cents IS DISTINCT FROM NEW.total_quoted_cents
        OR OLD.pricing_model IS DISTINCT FROM NEW.pricing_model
        OR OLD.price_per_person_cents IS DISTINCT FROM NEW.price_per_person_cents
        OR OLD.deposit_amount_cents IS DISTINCT FROM NEW.deposit_amount_cents) THEN
      RAISE EXCEPTION 'Cannot modify frozen quote after acceptance';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."prevent_signed_contract_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF OLD.status = 'signed' AND (
    NEW.body_snapshot     != OLD.body_snapshot OR
    NEW.signature_data_url != OLD.signature_data_url OR
    NEW.signed_at          != OLD.signed_at OR
    NEW.signer_ip_address  != OLD.signer_ip_address
  ) THEN
    RAISE EXCEPTION 'Signed contracts cannot be altered';
  END IF;
  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."prevent_transition_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RAISE EXCEPTION 'State transitions are immutable audit records';
END;
$$;




CREATE OR REPLACE FUNCTION "public"."purge_old_cron_executions"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Delete records older than 30 days on every insert.
  -- Runs synchronously but is a single-index DELETE — fast.
  DELETE FROM cron_executions
  WHERE executed_at < now() - INTERVAL '30 days';
  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."purge_old_cron_executions"() IS 'Auto-purges cron_executions rows older than 30 days on each INSERT. Keeps the table lean without requiring a separate cleanup cron.';



CREATE OR REPLACE FUNCTION "public"."purge_old_public_data_source_logs"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  DELETE FROM public.public_data_source_logs
  WHERE fetched_at < NOW() - INTERVAL '90 days';
  RETURN NEW;
END;
$$;




