COMMENT ON FUNCTION "public"."purge_old_webhook_events"() IS 'Auto-purges webhook_events rows older than 90 days on each INSERT. Keeps the table lean without a separate cleanup cron.';



CREATE OR REPLACE FUNCTION "public"."recompute_and_store_recipe_cost"("p_recipe_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_total INTEGER;
  v_yield DECIMAL;
  v_per_serving INTEGER;
BEGIN
  v_total := compute_recipe_cost_cents(p_recipe_id);

  SELECT yield_quantity INTO v_yield FROM recipes WHERE id = p_recipe_id;

  IF v_yield IS NOT NULL AND v_yield > 0 THEN
    v_per_serving := (v_total / v_yield)::INTEGER;
  ELSE
    v_per_serving := NULL;
  END IF;

  UPDATE recipes
  SET
    total_cost_cents = v_total,
    cost_per_serving_cents = v_per_serving
  WHERE id = p_recipe_id;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."recompute_recipe_ingredient_costs"("p_recipe_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE recipe_ingredients ri
  SET computed_cost_cents = (
    CASE
      WHEN COALESCE(i.cost_per_unit_cents, i.last_price_cents) IS NOT NULL THEN
        (
          COALESCE(i.cost_per_unit_cents, i.last_price_cents)
          * ri.quantity
          * 100.0
          / COALESCE(NULLIF(ri.yield_pct, 0), NULLIF(i.default_yield_pct, 0), 100)
        )::INTEGER
      ELSE NULL
    END
  )
  FROM ingredients i
  WHERE i.id = ri.ingredient_id
    AND ri.recipe_id = p_recipe_id;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."redeem_incentive"("p_incentive_id" "uuid", "p_event_id" "uuid", "p_client_id" "uuid", "p_tenant_id" "uuid", "p_applied_cents" integer, "p_incentive_type" "text", "p_code" "text", "p_balance_before_cents" integer, "p_redeemed_by" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $_$
DECLARE
  v_ledger_id UUID;
  v_balance_after INTEGER;
  v_description TEXT;
BEGIN
  -- Build a clear description for the ledger entry
  v_description := 'Gift card/voucher ' || p_code || ' applied — $' ||
    TRIM(TO_CHAR(p_applied_cents::DECIMAL / 100, 'FM999999990.00'));

  -- 1. Insert the ledger credit entry (source of financial truth)
  INSERT INTO ledger_entries (
    tenant_id,
    client_id,
    event_id,
    entry_type,
    amount_cents,
    payment_method,
    description,
    internal_notes,
    created_by
  ) VALUES (
    p_tenant_id,
    p_client_id,
    p_event_id,
    'credit',
    p_applied_cents,
    'gift_card',
    v_description,
    'Incentive ID: ' || p_incentive_id::TEXT || ', type: ' || p_incentive_type,
    p_redeemed_by
  ) RETURNING id INTO v_ledger_id;

  -- 2. Update the incentive (decrement balance for gift cards, always increment redemptions_used)
  IF p_incentive_type = 'gift_card' THEN
    v_balance_after := p_balance_before_cents - p_applied_cents;
    UPDATE client_incentives
      SET remaining_balance_cents = v_balance_after,
          redemptions_used = redemptions_used + 1
      WHERE id = p_incentive_id;
  ELSE
    v_balance_after := NULL;
    UPDATE client_incentives
      SET redemptions_used = redemptions_used + 1
      WHERE id = p_incentive_id;
  END IF;

  -- 3. Insert the immutable redemption audit record
  INSERT INTO incentive_redemptions (
    incentive_id,
    tenant_id,
    event_id,
    client_id,
    code,
    type,
    applied_amount_cents,
    balance_before_cents,
    balance_after_cents,
    ledger_entry_id,
    redeemed_by_user_id
  ) VALUES (
    p_incentive_id,
    p_tenant_id,
    p_event_id,
    p_client_id,
    p_code,
    p_incentive_type,
    p_applied_cents,
    p_balance_before_cents,
    v_balance_after,
    v_ledger_id,
    p_redeemed_by
  );

  RETURN v_ledger_id;
END;
$_$;




COMMENT ON FUNCTION "public"."redeem_incentive"("p_incentive_id" "uuid", "p_event_id" "uuid", "p_client_id" "uuid", "p_tenant_id" "uuid", "p_applied_cents" integer, "p_incentive_type" "text", "p_code" "text", "p_balance_before_cents" integer, "p_redeemed_by" "uuid") IS 'Atomically applies a voucher/gift card to an event: inserts ledger credit, decrements gift card balance, inserts audit row. Must be called via supabase.rpc() from server-side code only.';



CREATE OR REPLACE FUNCTION "public"."respond_menu_approval_atomic"("p_request_id" "uuid", "p_client_id" "uuid", "p_new_status" "text", "p_revision_notes" "text" DEFAULT NULL::"text", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_request menu_approval_requests%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_notes TEXT := NULLIF(BTRIM(COALESCE(p_revision_notes, '')), '');
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'client' THEN
      RAISE EXCEPTION 'Client role required';
    END IF;

    IF get_current_client_id() IS DISTINCT FROM p_client_id THEN
      RAISE EXCEPTION 'Client mismatch';
    END IF;

    IF p_actor_id IS NOT NULL AND auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  IF p_new_status NOT IN ('approved', 'revision_requested') THEN
    RAISE EXCEPTION 'Unsupported menu approval response status: %', p_new_status;
  END IF;

  SELECT *
  INTO v_request
  FROM menu_approval_requests
  WHERE id = p_request_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Approval request not found';
  END IF;

  IF v_request.client_id IS DISTINCT FROM p_client_id THEN
    RAISE EXCEPTION 'Approval request does not belong to this client';
  END IF;

  IF v_request.status <> 'sent' THEN
    RAISE EXCEPTION 'This request is no longer pending';
  END IF;

  UPDATE menu_approval_requests
  SET
    status = p_new_status::menu_approval_status,
    responded_at = v_now,
    revision_notes = CASE
      WHEN p_new_status = 'revision_requested' THEN COALESCE(v_notes, '(No notes provided)')
      ELSE NULL
    END
  WHERE id = v_request.id;

  IF p_new_status = 'approved' THEN
    UPDATE events
    SET
      menu_approval_status = 'approved',
      menu_approved_at = v_now,
      menu_revision_notes = NULL,
      updated_by = COALESCE(p_actor_id, updated_by),
      updated_at = v_now
    WHERE id = v_request.event_id;
  ELSE
    UPDATE events
    SET
      menu_approval_status = 'revision_requested',
      menu_revision_notes = COALESCE(v_notes, '(No notes provided)'),
      updated_by = COALESCE(p_actor_id, updated_by),
      updated_at = v_now
    WHERE id = v_request.event_id;
  END IF;

  RETURN jsonb_build_object(
    'request_id', v_request.id,
    'event_id', v_request.event_id,
    'chef_id', v_request.chef_id,
    'client_id', v_request.client_id,
    'status', p_new_status
  );
END;
$$;




CREATE OR REPLACE FUNCTION "public"."respond_to_quote_atomic"("p_quote_id" "uuid", "p_client_id" "uuid", "p_new_status" "text", "p_actor_id" "uuid", "p_rejected_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote quotes%ROWTYPE;
  v_event events%ROWTYPE;
  v_inquiry inquiries%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_clean_reason TEXT := NULLIF(BTRIM(COALESCE(p_rejected_reason, '')), '');
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'client' THEN
      RAISE EXCEPTION 'Client role required';
    END IF;

    IF get_current_client_id() IS DISTINCT FROM p_client_id THEN
      RAISE EXCEPTION 'Client mismatch';
    END IF;

    IF auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  IF p_new_status NOT IN ('accepted', 'rejected') THEN
    RAISE EXCEPTION 'Unsupported quote response status: %', p_new_status;
  END IF;

  SELECT *
  INTO v_quote
  FROM quotes
  WHERE id = p_quote_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Quote not found';
  END IF;

  IF v_quote.client_id IS DISTINCT FROM p_client_id THEN
    RAISE EXCEPTION 'Quote does not belong to this client';
  END IF;

  IF v_quote.status <> 'sent' THEN
    RAISE EXCEPTION 'Quote is no longer pending review';
  END IF;

  IF p_new_status = 'accepted' THEN
    IF v_quote.event_id IS NOT NULL THEN
      PERFORM pg_advisory_xact_lock(91001, hashtext(v_quote.event_id::text));
    ELSIF v_quote.inquiry_id IS NOT NULL THEN
      PERFORM pg_advisory_xact_lock(91002, hashtext(v_quote.inquiry_id::text));
    ELSE
      PERFORM pg_advisory_xact_lock(91003, hashtext(v_quote.id::text));
    END IF;

    IF EXISTS (
      SELECT 1
      FROM quotes q
      WHERE q.id <> v_quote.id
        AND q.deleted_at IS NULL
        AND q.status = 'accepted'
        AND (
          (v_quote.event_id IS NOT NULL AND q.event_id = v_quote.event_id)
          OR (v_quote.inquiry_id IS NOT NULL AND q.inquiry_id = v_quote.inquiry_id)
        )
    ) THEN
      RAISE EXCEPTION 'Another quote is already accepted for this workflow';
    END IF;

    IF v_quote.event_id IS NOT NULL THEN
      SELECT *
      INTO v_event
      FROM events
      WHERE id = v_quote.event_id
        AND tenant_id = v_quote.tenant_id
        AND deleted_at IS NULL
      FOR UPDATE;

      IF FOUND THEN
        IF v_event.status IN ('draft', 'proposed') THEN
          UPDATE events
          SET
            quoted_price_cents = v_quote.total_quoted_cents,
            deposit_amount_cents = v_quote.deposit_amount_cents,
            pricing_model = v_quote.pricing_model,
            converting_quote_id = v_quote.id,
            scope_drift_acknowledged = FALSE,
            scope_drift_acknowledged_at = NULL,
            updated_by = p_actor_id,
            updated_at = v_now
          WHERE id = v_event.id
            AND tenant_id = v_quote.tenant_id;
        ELSE
          IF (
            v_event.quoted_price_cents IS DISTINCT FROM v_quote.total_quoted_cents
            OR v_event.deposit_amount_cents IS DISTINCT FROM v_quote.deposit_amount_cents
            OR v_event.pricing_model IS DISTINCT FROM v_quote.pricing_model
          ) THEN
            RAISE EXCEPTION
              'Cannot accept quote: linked event pricing is locked at status %',
              v_event.status;
          END IF;

          UPDATE events
          SET
            converting_quote_id = v_quote.id,
            scope_drift_acknowledged = FALSE,
            scope_drift_acknowledged_at = NULL,
            updated_by = p_actor_id,
            updated_at = v_now
          WHERE id = v_event.id
            AND tenant_id = v_quote.tenant_id;
        END IF;
      END IF;
    END IF;

    UPDATE quotes
    SET
      status = 'accepted',
      rejected_at = NULL,
      rejected_reason = NULL,
      updated_by = p_actor_id,
      updated_at = v_now
    WHERE id = v_quote.id;

    IF v_quote.inquiry_id IS NOT NULL THEN
      SELECT *
      INTO v_inquiry
      FROM inquiries
      WHERE id = v_quote.inquiry_id
        AND tenant_id = v_quote.tenant_id
      FOR UPDATE;

      IF FOUND THEN
        IF v_inquiry.status IN ('new', 'awaiting_client', 'awaiting_chef') THEN
          UPDATE inquiries
          SET
            status = 'quoted',
            updated_at = v_now
          WHERE id = v_inquiry.id;

          INSERT INTO inquiry_state_transitions (
            tenant_id,
            inquiry_id,
            from_status,
            to_status,
            transitioned_by,
            reason,
            metadata
          ) VALUES (
            v_quote.tenant_id,
            v_inquiry.id,
            v_inquiry.status,
            'quoted',
            p_actor_id,
            'quote_sent_sync',
            jsonb_build_object(
              'source', 'quote_client_acceptance',
              'quote_id', v_quote.id
            )
          );

          v_inquiry.status := 'quoted';
        END IF;

        IF v_inquiry.status = 'quoted' THEN
          UPDATE inquiries
          SET
            status = 'confirmed',
            updated_at = v_now
          WHERE id = v_inquiry.id;

          INSERT INTO inquiry_state_transitions (
            tenant_id,
            inquiry_id,
            from_status,
            to_status,
            transitioned_by,
            reason,
            metadata
          ) VALUES (
            v_quote.tenant_id,
            v_inquiry.id,
            'quoted',
            'confirmed',
            p_actor_id,
            'quote_accepted',
            jsonb_build_object(
              'source', 'quote_client_acceptance',
              'quote_id', v_quote.id
            )
          );
        END IF;
      END IF;
    END IF;
  ELSE
    UPDATE quotes
    SET
      status = 'rejected',
      rejected_at = v_now,
      rejected_reason = v_clean_reason,
      updated_by = p_actor_id,
      updated_at = v_now
    WHERE id = v_quote.id;
  END IF;

  RETURN jsonb_build_object(
    'quote_id', v_quote.id,
    'tenant_id', v_quote.tenant_id,
    'client_id', v_quote.client_id,
    'event_id', v_quote.event_id,
    'inquiry_id', v_quote.inquiry_id,
    'quote_name', v_quote.quote_name,
    'total_quoted_cents', v_quote.total_quoted_cents,
    'deposit_required', v_quote.deposit_required,
    'deposit_amount_cents', v_quote.deposit_amount_cents,
    'status', p_new_status,
    'converting_quote_id', CASE WHEN v_quote.event_id IS NOT NULL THEN v_quote.id ELSE NULL END
  );
END;
$$;




CREATE OR REPLACE FUNCTION "public"."send_menu_for_approval_atomic"("p_event_id" "uuid", "p_chef_id" "uuid", "p_menu_snapshot" "jsonb", "p_actor_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_event events%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_request_id UUID;
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'chef' THEN
      RAISE EXCEPTION 'Chef role required';
    END IF;

    IF get_current_tenant_id() IS DISTINCT FROM p_chef_id THEN
      RAISE EXCEPTION 'Chef mismatch';
    END IF;

    IF auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  SELECT *
  INTO v_event
  FROM events
  WHERE id = p_event_id
    AND tenant_id = p_chef_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Event not found';
  END IF;

  IF v_event.client_id IS NULL THEN
    RAISE EXCEPTION 'Event has no client';
  END IF;

  INSERT INTO menu_approval_requests (
    event_id,
    chef_id,
    client_id,
    menu_snapshot,
    sent_at,
    status
  )
  VALUES (
    v_event.id,
    p_chef_id,
    v_event.client_id,
    COALESCE(p_menu_snapshot, '[]'::jsonb),
    v_now,
    'sent'
  )
  RETURNING id INTO v_request_id;

  UPDATE events
  SET
    menu_approval_status = 'sent',
    menu_sent_at = v_now,
    updated_by = p_actor_id,
    updated_at = v_now
  WHERE id = v_event.id
    AND tenant_id = p_chef_id;

  RETURN jsonb_build_object(
    'request_id', v_request_id,
    'event_id', v_event.id,
    'chef_id', p_chef_id,
    'client_id', v_event.client_id
  );
END;
$$;




