CREATE OR REPLACE FUNCTION "public"."sync_event_cannabis_course_config_from_events"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  safe_course_count INTEGER;
BEGIN
  safe_course_count := GREATEST(COALESCE(NEW.course_count, 1), 1);

  IF COALESCE(NEW.cannabis_preference, false) = false THEN
    UPDATE event_cannabis_course_config
    SET
      is_active = false,
      archived_at = COALESCE(archived_at, now()),
      tenant_id = NEW.tenant_id,
      updated_at = now()
    WHERE event_id = NEW.id
      AND is_active = true;

    RETURN NEW;
  END IF;

  INSERT INTO event_cannabis_course_config (
    event_id,
    tenant_id,
    course_index,
    is_active,
    archived_at
  )
  SELECT
    NEW.id,
    NEW.tenant_id,
    gs.course_index,
    true,
    NULL
  FROM generate_series(1, safe_course_count) AS gs(course_index)
  ON CONFLICT (event_id, course_index)
  DO UPDATE
    SET tenant_id = EXCLUDED.tenant_id,
        is_active = true,
        archived_at = NULL,
        updated_at = now();

  UPDATE event_cannabis_course_config
  SET
    is_active = false,
    archived_at = COALESCE(archived_at, now()),
    tenant_id = NEW.tenant_id,
    updated_at = now()
  WHERE event_id = NEW.id
    AND course_index > safe_course_count
    AND is_active = true;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."sync_event_cannabis_settings_from_events"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  INSERT INTO event_cannabis_settings (
    event_id,
    tenant_id,
    cannabis_enabled,
    enabled_at
  )
  VALUES (
    NEW.id,
    NEW.tenant_id,
    COALESCE(NEW.cannabis_preference, false),
    CASE WHEN COALESCE(NEW.cannabis_preference, false) THEN now() ELSE NULL END
  )
  ON CONFLICT (event_id)
  DO UPDATE
    SET tenant_id = EXCLUDED.tenant_id,
        cannabis_enabled = EXCLUDED.cannabis_enabled,
        enabled_at = CASE
          WHEN EXCLUDED.cannabis_enabled THEN COALESCE(event_cannabis_settings.enabled_at, now())
          ELSE NULL
        END,
        updated_at = now();

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."transition_event_atomic"("p_event_id" "uuid", "p_to_status" "text", "p_from_status" "text", "p_transitioned_by" "uuid", "p_tenant_id" "uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  UPDATE events
  SET
    status     = p_to_status::event_status,
    updated_by = p_transitioned_by,
    cancelled_at = CASE
      WHEN p_to_status = 'cancelled' THEN NOW()
      ELSE cancelled_at
    END,
    cancellation_reason = CASE
      WHEN p_to_status = 'cancelled' THEN (p_metadata->>'reason')
      ELSE cancellation_reason
    END,
    cancellation_initiated_by = CASE
      WHEN p_to_status = 'cancelled' AND p_metadata->>'source' = 'system' THEN 'mutual'
      WHEN p_to_status = 'cancelled' AND p_metadata->>'actor_role' = 'chef'   THEN 'chef'
      WHEN p_to_status = 'cancelled' AND p_metadata->>'actor_role' = 'client' THEN 'client'
      ELSE cancellation_initiated_by
    END
  WHERE id = p_event_id AND tenant_id = p_tenant_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Event not found or tenant mismatch: %', p_event_id;
  END IF;

  INSERT INTO event_state_transitions (
    tenant_id,
    event_id,
    from_status,
    to_status,
    transitioned_by,
    metadata
  ) VALUES (
    p_tenant_id,
    p_event_id,
    p_from_status::event_status,
    p_to_status::event_status,
    p_transitioned_by,
    p_metadata || jsonb_build_object(
      'timestamp',   NOW(),
      'rpc_version', '2'
    )
  );

  v_result := jsonb_build_object(
    'success',     true,
    'from_status', p_from_status,
    'to_status',   p_to_status,
    'event_id',    p_event_id
  );

  RETURN v_result;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."transition_quote_atomic"("p_quote_id" "uuid", "p_tenant_id" "uuid", "p_actor_id" "uuid", "p_to_status" "text", "p_reason" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote quotes%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
BEGIN
  IF auth.role() <> 'service_role' AND auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF auth.role() <> 'service_role' THEN
    IF get_current_user_role() <> 'chef' THEN
      RAISE EXCEPTION 'Chef role required';
    END IF;

    IF get_current_tenant_id() IS DISTINCT FROM p_tenant_id THEN
      RAISE EXCEPTION 'Tenant mismatch';
    END IF;

    IF auth.uid() IS DISTINCT FROM p_actor_id THEN
      RAISE EXCEPTION 'Actor mismatch';
    END IF;
  END IF;

  IF p_to_status NOT IN ('draft', 'sent', 'expired') THEN
    RAISE EXCEPTION 'Unsupported quote transition status: %', p_to_status;
  END IF;

  SELECT *
  INTO v_quote
  FROM quotes
  WHERE id = p_quote_id
    AND tenant_id = p_tenant_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Quote not found';
  END IF;

  IF p_to_status = 'sent' AND v_quote.status <> 'draft' THEN
    RAISE EXCEPTION 'Invalid transition from % to %', v_quote.status, p_to_status;
  END IF;

  IF p_to_status = 'expired' AND v_quote.status <> 'sent' THEN
    RAISE EXCEPTION 'Invalid transition from % to %', v_quote.status, p_to_status;
  END IF;

  IF p_to_status = 'draft' AND v_quote.status <> 'expired' THEN
    RAISE EXCEPTION 'Invalid transition from % to %', v_quote.status, p_to_status;
  END IF;

  UPDATE quotes
  SET
    status = p_to_status::quote_status,
    sent_at = CASE
      WHEN p_to_status = 'sent' THEN v_now
      ELSE sent_at
    END,
    expired_at = CASE
      WHEN p_to_status = 'expired' THEN v_now
      WHEN p_to_status = 'draft' THEN NULL
      ELSE expired_at
    END,
    updated_by = p_actor_id,
    updated_at = v_now
  WHERE id = v_quote.id
    AND tenant_id = p_tenant_id;

  RETURN jsonb_build_object(
    'quote_id', v_quote.id,
    'status', p_to_status,
    'tenant_id', v_quote.tenant_id,
    'client_id', v_quote.client_id,
    'inquiry_id', v_quote.inquiry_id,
    'event_id', v_quote.event_id,
    'quote_name', v_quote.quote_name,
    'total_quoted_cents', v_quote.total_quoted_cents,
    'deposit_required', v_quote.deposit_required,
    'deposit_amount_cents', v_quote.deposit_amount_cents,
    'valid_until', v_quote.valid_until,
    'reason', NULLIF(BTRIM(COALESCE(p_reason, '')), ''),
    'metadata', COALESCE(p_metadata, '{}'::jsonb)
  );
END;
$$;




