    AS $$
BEGIN
  UPDATE clients
  SET
    lifetime_value_cents = (
      SELECT COALESCE(SUM(amount_cents), 0)
      FROM ledger_entries
      WHERE client_id = NEW.client_id AND is_refund = false
    ),
