CREATE OR REPLACE FUNCTION "public"."update_client_stats_on_event_completion"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
    UPDATE clients
    SET
      total_events_count = total_events_count + 1,
      last_event_date = NEW.event_date,
      first_event_date = COALESCE(first_event_date, NEW.event_date)
    WHERE id = NEW.client_id;
  END IF;
  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."update_conversation_last_message"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  preview TEXT;
BEGIN
  -- Build preview text based on message type
  CASE NEW.message_type
    WHEN 'text' THEN
      preview := LEFT(NEW.body, 100);
    WHEN 'image' THEN
      preview := COALESCE(LEFT(NEW.body, 80), '') ||
        CASE WHEN NEW.body IS NOT NULL AND LENGTH(NEW.body) > 0
          THEN ' [Photo]'
          ELSE '[Photo]'
        END;
    WHEN 'file' THEN
      preview := COALESCE(LEFT(NEW.body, 80), '') ||
        CASE WHEN NEW.body IS NOT NULL AND LENGTH(NEW.body) > 0
          THEN ' [File]'
          ELSE '[File: ' || COALESCE(LEFT(NEW.attachment_filename, 40), 'Document') || ']'
        END;
    WHEN 'link' THEN
      preview := COALESCE(LEFT(NEW.body, 80), NEW.link_url);
    WHEN 'event_ref' THEN
      preview := COALESCE(LEFT(NEW.body, 80), '[Event shared]');
    WHEN 'system' THEN
      preview := LEFT(NEW.body, 100);
    ELSE
      preview := LEFT(COALESCE(NEW.body, ''), 100);
  END CASE;

  UPDATE conversations SET
    last_message_at = NEW.created_at,
    last_message_preview = preview,
    last_message_sender_id = NEW.sender_id,
    updated_at = now()
  WHERE id = NEW.conversation_id;

  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."update_conversation_last_message"() IS 'Denormalizes last message info onto conversations table for efficient inbox queries';



