CREATE OR REPLACE FUNCTION "public"."validate_cannabis_control_packet_evidence"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  snap RECORD;
BEGIN
  SELECT id, event_id, tenant_id, finalization_locked
  INTO snap
  FROM cannabis_control_packet_snapshots
  WHERE id = NEW.snapshot_id;

  IF snap.id IS NULL THEN
    RAISE EXCEPTION 'Evidence snapshot does not exist';
  END IF;

  IF NEW.event_id <> snap.event_id OR NEW.tenant_id <> snap.tenant_id THEN
    RAISE EXCEPTION 'Evidence event/tenant must match snapshot';
  END IF;

  IF snap.finalization_locked THEN
    RAISE EXCEPTION 'Cannot add evidence after packet finalization';
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_cannabis_control_packet_reconciliation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  snap RECORD;
BEGIN
  SELECT id, event_id, tenant_id, version_number, finalization_locked
  INTO snap
  FROM cannabis_control_packet_snapshots
  WHERE id = NEW.snapshot_id;

  IF snap.id IS NULL THEN
    RAISE EXCEPTION 'Reconciliation snapshot does not exist';
  END IF;

  IF NEW.event_id <> snap.event_id OR NEW.tenant_id <> snap.tenant_id THEN
    RAISE EXCEPTION 'Reconciliation event/tenant must match snapshot';
  END IF;

  IF NEW.snapshot_version <> snap.version_number THEN
    RAISE EXCEPTION 'Reconciliation snapshot_version mismatch';
  END IF;

  IF snap.finalization_locked THEN
    RAISE EXCEPTION 'Snapshot is finalized and cannot be reconciled';
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_cannabis_control_packet_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  ev_tenant UUID;
  ev_cannabis BOOLEAN;
BEGIN
  SELECT tenant_id, COALESCE(cannabis_preference, false)
  INTO ev_tenant, ev_cannabis
  FROM events
  WHERE id = NEW.event_id;

  IF ev_tenant IS NULL THEN
    RAISE EXCEPTION 'Control packet event does not exist';
  END IF;

  IF ev_tenant <> NEW.tenant_id THEN
    RAISE EXCEPTION 'Control packet tenant mismatch for event';
  END IF;

  IF ev_cannabis = false THEN
    RAISE EXCEPTION 'Control packet can only be generated for cannabis-enabled events';
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_event_cannabis_course_config"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  ev_tenant UUID;
  ev_enabled BOOLEAN;
BEGIN
  SELECT
    e.tenant_id,
    COALESCE(s.cannabis_enabled, COALESCE(e.cannabis_preference, false))
  INTO ev_tenant, ev_enabled
  FROM events e
  LEFT JOIN event_cannabis_settings s ON s.event_id = e.id
  WHERE e.id = NEW.event_id;

  IF ev_tenant IS NULL THEN
    RAISE EXCEPTION 'Cannabis course config event does not exist';
  END IF;

  IF ev_tenant <> NEW.tenant_id THEN
    RAISE EXCEPTION 'Cannabis course config tenant mismatch for event';
  END IF;

  IF ev_enabled = false AND NEW.is_active THEN
    RAISE EXCEPTION 'Active cannabis course config requires a cannabis-enabled event';
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_event_cannabis_settings"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  ev_tenant UUID;
BEGIN
  SELECT tenant_id
  INTO ev_tenant
  FROM events
  WHERE id = NEW.event_id;

  IF ev_tenant IS NULL THEN
    RAISE EXCEPTION 'Cannabis settings event does not exist';
  END IF;

  IF ev_tenant <> NEW.tenant_id THEN
    RAISE EXCEPTION 'Cannabis settings tenant mismatch for event';
  END IF;

  IF NEW.cannabis_enabled THEN
    NEW.enabled_at := COALESCE(NEW.enabled_at, now());
  ELSE
    NEW.enabled_at := NULL;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_event_state_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Allow same-state (no-op)
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Validate allowed transitions
  IF NOT (
    (OLD.status = 'draft' AND NEW.status IN ('proposed', 'cancelled')) OR
    (OLD.status = 'proposed' AND NEW.status IN ('accepted', 'cancelled')) OR
    (OLD.status = 'accepted' AND NEW.status IN ('paid', 'cancelled')) OR
    (OLD.status = 'paid' AND NEW.status IN ('confirmed', 'cancelled')) OR
    (OLD.status = 'confirmed' AND NEW.status IN ('in_progress', 'cancelled')) OR
    (OLD.status = 'in_progress' AND NEW.status IN ('completed', 'cancelled')) OR
    (OLD.status = 'completed' AND FALSE) OR  -- Terminal state, no transitions
    (OLD.status = 'cancelled' AND FALSE)      -- Terminal state, no transitions
  ) THEN
    RAISE EXCEPTION 'Invalid event transition from % to %', OLD.status, NEW.status;
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_inquiry_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Allow initial state (from_status is NULL)
  IF NEW.from_status IS NULL THEN
    RETURN NEW;
  END IF;

  IF NOT (
    (NEW.from_status = 'new' AND NEW.to_status IN ('awaiting_client', 'quoted', 'declined')) OR
    (NEW.from_status = 'awaiting_client' AND NEW.to_status IN ('awaiting_chef', 'quoted', 'declined', 'expired')) OR
    (NEW.from_status = 'awaiting_chef' AND NEW.to_status IN ('awaiting_client', 'quoted', 'declined')) OR
    (NEW.from_status = 'quoted' AND NEW.to_status IN ('confirmed', 'declined', 'expired')) OR
    (NEW.from_status = 'expired' AND NEW.to_status IN ('new'))
  ) THEN
    RAISE EXCEPTION 'Invalid inquiry state transition: % -> %. This transition is not allowed.', NEW.from_status, NEW.to_status;
  END IF;

  RETURN NEW;
END;
$$;




COMMENT ON FUNCTION "public"."validate_inquiry_transition"() IS 'Validates inquiry state transitions against allowed state machine rules';



CREATE OR REPLACE FUNCTION "public"."validate_menu_state_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  valid_transition BOOLEAN := false;
BEGIN
  -- Allow same-state (no-op)
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Valid transitions:
  -- draft → shared, draft → archived
  -- shared → locked, shared → draft
  -- locked → archived
  IF OLD.status = 'draft' AND NEW.status IN ('shared', 'archived') THEN
    valid_transition := true;
  ELSIF OLD.status = 'shared' AND NEW.status IN ('locked', 'draft') THEN
    valid_transition := true;
  ELSIF OLD.status = 'locked' AND NEW.status = 'archived' THEN
    valid_transition := true;
  END IF;

  IF NOT valid_transition THEN
    RAISE EXCEPTION 'Invalid menu state transition: % → %', OLD.status, NEW.status;
  END IF;

  -- Set timestamp fields
  IF NEW.status = 'shared' AND OLD.status != 'shared' THEN
    NEW.shared_at := now();
  ELSIF NEW.status = 'locked' AND OLD.status != 'locked' THEN
    NEW.locked_at := now();
  ELSIF NEW.status = 'archived' AND OLD.status != 'archived' THEN
    NEW.archived_at := now();
  END IF;

  RETURN NEW;
END;
$$;




CREATE OR REPLACE FUNCTION "public"."validate_quote_state_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Allow same-state (no-op)
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Valid transitions
  IF (OLD.status = 'draft' AND NEW.status = 'sent')
     OR (OLD.status = 'sent' AND NEW.status IN ('accepted', 'rejected', 'expired')) THEN
    RETURN NEW;
  END IF;

  -- Invalid transition
  RAISE EXCEPTION 'Invalid quote state transition from % to %', OLD.status, NEW.status;
END;
$$;



