SET default_table_access_method = "heap";


CREATE TABLE IF NOT EXISTS "public"."ab_tests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "campaign_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "variant_a_subject" "text" NOT NULL,
    "variant_b_subject" "text" NOT NULL,
    "test_percent" integer DEFAULT 20 NOT NULL,
    "winner" "text",
    "resolved_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ab_tests_test_percent_check" CHECK ((("test_percent" >= 5) AND ("test_percent" <= 50))),
    CONSTRAINT "ab_tests_winner_check" CHECK ((("winner" IS NULL) OR ("winner" = ANY (ARRAY['a'::"text", 'b'::"text"]))))
);




CREATE TABLE IF NOT EXISTS "public"."account_deletion_audit" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "auth_user_id" "uuid" NOT NULL,
    "email" "text" NOT NULL,
    "business_name" "text" NOT NULL,
    "action" "text" NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "performed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "performed_by" "text" DEFAULT 'system'::"text" NOT NULL,
    CONSTRAINT "account_deletion_audit_action_check" CHECK (("action" = ANY (ARRAY['deletion_requested'::"text", 'deletion_cancelled'::"text", 'data_exported'::"text", 'grace_period_expired'::"text", 'financial_records_anonymized'::"text", 'pii_purged'::"text", 'storage_cleaned'::"text", 'auth_user_deleted'::"text", 'purge_completed'::"text"])))
);




COMMENT ON TABLE "public"."account_deletion_audit" IS 'Permanent audit trail for account deletion lifecycle. Not FK-linked to chefs — must survive deletion.';



CREATE TABLE IF NOT EXISTS "public"."activity_events" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "actor_type" "text" NOT NULL,
    "actor_id" "uuid",
    "client_id" "uuid",
    "event_type" "text" NOT NULL,
    "entity_type" "text",
