    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "activity_events_actor_type_check" CHECK (("actor_type" = ANY (ARRAY['client'::"text", 'chef'::"text", 'system'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."activity_events_archive" (
    "id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "actor_type" "text" NOT NULL,
    "actor_id" "uuid",
    "client_id" "uuid",
    "event_type" "text" NOT NULL,
    "entity_type" "text",
    "entity_id" "uuid",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    "created_at" timestamp with time zone NOT NULL,
    "archived_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."admin_audit_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "ts" timestamp with time zone DEFAULT "now"() NOT NULL,
    "actor_email" "text",
    "actor_user_id" "uuid",
    "action_type" "text" NOT NULL,
    "target_id" "text",
    "target_type" "text",
    "details" "jsonb",
    "ip_address" "text"
);




CREATE TABLE IF NOT EXISTS "public"."admin_time_logs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "category" "text" DEFAULT 'other'::"text" NOT NULL,
    "log_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "minutes" integer NOT NULL,
    "notes" "text",
    "event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "admin_time_logs_category_check" CHECK (("category" = ANY (ARRAY['email'::"text", 'calls'::"text", 'planning'::"text", 'bookkeeping'::"text", 'marketing'::"text", 'sourcing'::"text", 'travel_admin'::"text", 'other'::"text"]))),
    CONSTRAINT "admin_time_logs_minutes_check" CHECK (("minutes" > 0))
);




COMMENT ON TABLE "public"."admin_time_logs" IS 'Tracks administrative time outside of on-site event phases. Used to compute true hourly rate including all business overhead.';



COMMENT ON COLUMN "public"."admin_time_logs"."event_id" IS 'Optional. If set, this admin time is included in total time for that event''s effective hourly rate.';



CREATE TABLE IF NOT EXISTS "public"."after_action_reviews" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "calm_rating" integer NOT NULL,
    "preparation_rating" integer NOT NULL,
    "execution_rating" integer,
    "could_have_done_earlier" "text",
    "forgotten_items" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "what_went_well" "text",
    "what_went_wrong" "text",
    "would_do_differently" "text",
    "menu_performance_notes" "text",
    "client_behavior_notes" "text",
    "site_notes" "text",
    "general_notes" "text",
    "created_by" "uuid",
    "updated_by" "uuid",
    CONSTRAINT "after_action_reviews_calm_rating_check" CHECK ((("calm_rating" >= 1) AND ("calm_rating" <= 5))),
    CONSTRAINT "after_action_reviews_execution_rating_check" CHECK ((("execution_rating" >= 1) AND ("execution_rating" <= 5))),
    CONSTRAINT "after_action_reviews_preparation_rating_check" CHECK ((("preparation_rating" >= 1) AND ("preparation_rating" <= 5)))
);




COMMENT ON TABLE "public"."after_action_reviews" IS 'Post-event retrospective. One per event. The real KPIs: calm_rating and preparation_rating.';



CREATE TABLE IF NOT EXISTS "public"."ai_preferences" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "remy_enabled" boolean DEFAULT false NOT NULL,
    "onboarding_completed" boolean DEFAULT false NOT NULL,
    "onboarding_completed_at" timestamp with time zone,
    "data_retention_days" integer DEFAULT 90,
    "allow_memory" boolean DEFAULT true NOT NULL,
    "allow_suggestions" boolean DEFAULT true NOT NULL,
    "allow_document_drafts" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "remy_archetype" "text",
    "survey_state" "jsonb"
);




COMMENT ON COLUMN "public"."ai_preferences"."remy_archetype" IS 'Remy personality archetype: veteran, hype, zen, numbers, mentor, classic. NULL = veteran (default).';



COMMENT ON COLUMN "public"."ai_preferences"."survey_state" IS 'Remy conversational survey progress — JSON with status, currentGroup, currentQuestion, answered[], skipped[]';



CREATE TABLE IF NOT EXISTS "public"."ai_task_queue" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "task_type" "text" NOT NULL,
    "priority" integer DEFAULT 400 NOT NULL,
    "approval_tier" "text" DEFAULT 'auto'::"text" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "result" "jsonb",
    "target_endpoint" "text" DEFAULT 'auto'::"text" NOT NULL,
    "actual_endpoint" "text",
    "model_tier" "text" DEFAULT 'standard'::"text" NOT NULL,
    "scheduled_for" timestamp with time zone DEFAULT "now"() NOT NULL,
    "recurrence" "text",
    "attempts" integer DEFAULT 0 NOT NULL,
    "max_attempts" integer DEFAULT 3 NOT NULL,
    "last_error" "text",
    "next_retry_at" timestamp with time zone,
    "related_event_id" "uuid",
    "related_client_id" "uuid",
    "related_inquiry_id" "uuid",
    "approved_at" timestamp with time zone,
    "approved_by" "uuid",
    "rejection_reason" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ai_task_queue_approval_tier_check" CHECK (("approval_tier" = ANY (ARRAY['auto'::"text", 'draft'::"text", 'hold'::"text"]))),
    CONSTRAINT "ai_task_queue_model_tier_check" CHECK (("model_tier" = ANY (ARRAY['fast'::"text", 'standard'::"text", 'complex'::"text"]))),
    CONSTRAINT "ai_task_queue_priority_check" CHECK ((("priority" >= 0) AND ("priority" <= 1000))),
    CONSTRAINT "ai_task_queue_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'completed'::"text", 'awaiting_approval'::"text", 'approved'::"text", 'rejected'::"text", 'failed'::"text", 'dead'::"text"]))),
    CONSTRAINT "ai_task_queue_target_endpoint_check" CHECK (("target_endpoint" = ANY (ARRAY['auto'::"text", 'pc'::"text", 'pi'::"text"])))
);




