);




CREATE TABLE IF NOT EXISTS "public"."audit_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid",
    "table_name" "text" NOT NULL,
    "record_id" "uuid" NOT NULL,
    "action" "text" NOT NULL,
    "changed_by" "uuid",
    "changed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "before_values" "jsonb",
    "after_values" "jsonb",
    "change_summary" "text",
    CONSTRAINT "audit_log_action_check" CHECK (("action" = ANY (ARRAY['INSERT'::"text", 'UPDATE'::"text", 'DELETE'::"text"])))
);




COMMENT ON TABLE "public"."audit_log" IS 'General-purpose audit trail for all mutations (who changed what, when, before/after)';



COMMENT ON COLUMN "public"."audit_log"."tenant_id" IS 'Nullable - NULL for chef record mutations, populated for tenant-scoped records';



COMMENT ON COLUMN "public"."audit_log"."before_values" IS 'JSONB snapshot of record before change (NULL for INSERT)';



COMMENT ON COLUMN "public"."audit_log"."after_values" IS 'JSONB snapshot of record after change (NULL for DELETE)';



