    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "bakery_yield_records_quality_rating_check" CHECK ((("quality_rating" IS NULL) OR (("quality_rating" >= 1) AND ("quality_rating" <= 5)))),
    CONSTRAINT "bakery_yield_records_waste_reason_check" CHECK ((("waste_reason" IS NULL) OR ("waste_reason" = ANY (ARRAY['burnt'::"text", 'misshapen'::"text", 'underproofed'::"text", 'overbaked'::"text", 'dropped'::"text", 'other'::"text"]))))
);




