    "pending_review_sent_at" timestamp with time zone,
    "invited_sent_at" timestamp with time zone,
    "declined_sent_at" timestamp with time zone,
    "account_ready_sent_at" timestamp with time zone,
    "onboarding_reminder_sent_at" timestamp with time zone,
    "completed_sent_at" timestamp with time zone,
    "invited_at" timestamp with time zone,
    "account_created_at" timestamp with time zone,
    "declined_at" timestamp with time zone,
