    CONSTRAINT "beta_signup_trackers_current_status_check" CHECK (("current_status" = ANY (ARRAY['pending'::"text", 'invited'::"text", 'account_ready'::"text", 'onboarding'::"text", 'declined'::"text", 'completed'::"text"]))),
    CONSTRAINT "beta_signup_trackers_last_email_type_check" CHECK (("last_email_type" = ANY (ARRAY['pending_review'::"text", 'invited'::"text", 'account_ready'::"text", 'onboarding_reminder'::"text", 'declined'::"text", 'onboarding_complete'::"text"]))),
    CONSTRAINT "beta_signup_trackers_progress_percent_check" CHECK ((("progress_percent" >= 0) AND ("progress_percent" <= 100)))
);




COMMENT ON TABLE "public"."beta_signup_trackers" IS 'Tracks public beta signup lifecycle, email delivery milestones, and onboarding progression for chefs entering through the beta funnel.';



CREATE TABLE IF NOT EXISTS "public"."beta_signups" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
