    "invited_at" timestamp with time zone,
    "onboarded_at" timestamp with time zone,
    CONSTRAINT "beta_signups_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'invited'::"text", 'onboarded'::"text", 'declined'::"text"])))
);




COMMENT ON TABLE "public"."beta_signups" IS 'Beta interest signups from /beta public page. Managed by admin via /admin/beta. Accessed only via admin client.';



CREATE TABLE IF NOT EXISTS "public"."beta_survey_definitions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "slug" "text" NOT NULL,
    "title" "text" NOT NULL,
    "description" "text",
    "survey_type" "text" NOT NULL,
    "questions" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "beta_survey_definitions_survey_type_check" CHECK (("survey_type" = ANY (ARRAY['pre_beta'::"text", 'post_beta'::"text"])))
);




COMMENT ON TABLE "public"."beta_survey_definitions" IS 'Survey templates for pre-beta and post-beta feedback collection. Platform-level (no tenant scoping).';



COMMENT ON COLUMN "public"."beta_survey_definitions"."slug" IS 'URL-safe unique identifier, e.g. pre-beta-v1, post-beta-v1';



COMMENT ON COLUMN "public"."beta_survey_definitions"."questions" IS 'JSON array of question objects: [{id, type, label, options?, required, order}]. Types: single_select, multi_select, textarea, rating_scale, nps, yes_no, number';



COMMENT ON COLUMN "public"."beta_survey_definitions"."is_active" IS 'Only one survey per type should be active at a time. Controls banner visibility.';



CREATE TABLE IF NOT EXISTS "public"."beta_survey_invites" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "survey_id" "uuid" NOT NULL,
    "token" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text",
    "email" "text",
    "role" "text" DEFAULT 'tester'::"text" NOT NULL,
    "claimed_at" timestamp with time zone,
    "response_id" "uuid",
    "expires_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "beta_survey_invites_role_check" CHECK (("role" = ANY (ARRAY['chef'::"text", 'client'::"text", 'tester'::"text"])))
);




COMMENT ON TABLE "public"."beta_survey_invites" IS 'Invite tokens for external testers to access beta surveys without an account.';



COMMENT ON COLUMN "public"."beta_survey_invites"."token" IS 'UUID token used in the public URL: /beta-survey/{token}';



COMMENT ON COLUMN "public"."beta_survey_invites"."claimed_at" IS 'Set when the invite link is first opened.';



COMMENT ON COLUMN "public"."beta_survey_invites"."response_id" IS 'Linked to the response after the invite is used to submit.';



CREATE TABLE IF NOT EXISTS "public"."beta_survey_responses" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "survey_id" "uuid" NOT NULL,
    "auth_user_id" "uuid",
    "token" "uuid" DEFAULT "gen_random_uuid"(),
    "respondent_role" "text",
    "respondent_name" "text",
    "respondent_email" "text",
    "nps_score" smallint,
    "overall_satisfaction" smallint,
    "would_pay" boolean,
    "tech_comfort" smallint,
    "answers" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "submitted_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "beta_survey_responses_nps_score_check" CHECK ((("nps_score" >= 0) AND ("nps_score" <= 10))),
    CONSTRAINT "beta_survey_responses_overall_satisfaction_check" CHECK ((("overall_satisfaction" >= 1) AND ("overall_satisfaction" <= 10))),
    CONSTRAINT "beta_survey_responses_respondent_role_check" CHECK (("respondent_role" = ANY (ARRAY['chef'::"text", 'client'::"text", 'tester'::"text", 'staff'::"text", 'partner'::"text"]))),
    CONSTRAINT "beta_survey_responses_tech_comfort_check" CHECK ((("tech_comfort" >= 1) AND ("tech_comfort" <= 5)))
);




COMMENT ON TABLE "public"."beta_survey_responses" IS 'Stores all beta survey responses. Logged-in users identified by auth_user_id, external testers by token.';



COMMENT ON COLUMN "public"."beta_survey_responses"."token" IS 'Public access token for viewing/editing this response. Used for external tester links.';



COMMENT ON COLUMN "public"."beta_survey_responses"."answers" IS 'JSONB object keyed by question ID, e.g. {"role": "chef", "pain_points": "..."}';



COMMENT ON COLUMN "public"."beta_survey_responses"."submitted_at" IS 'NULL means the response is in progress (started but not finished).';



CREATE TABLE IF NOT EXISTS "public"."beverages" (
