    CONSTRAINT "bdc_max_per_week_pos" CHECK (("max_per_week" > 0))
);




CREATE TABLE IF NOT EXISTS "public"."booking_date_overrides" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
