CREATE TABLE IF NOT EXISTS "public"."booking_event_types" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "duration_minutes" integer DEFAULT 180 NOT NULL,
    "price_cents" integer,
    "guest_count_min" integer DEFAULT 1 NOT NULL,
    "guest_count_max" integer DEFAULT 50 NOT NULL,
    "buffer_before_minutes" integer DEFAULT 0 NOT NULL,
    "buffer_after_minutes" integer DEFAULT 0 NOT NULL,
    "min_notice_hours" integer DEFAULT 168 NOT NULL,
    "color" "text",
    "sort_order" integer DEFAULT 0 NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "bet_buffer_nonneg" CHECK ((("buffer_before_minutes" >= 0) AND ("buffer_after_minutes" >= 0))),
    CONSTRAINT "bet_duration_pos" CHECK ((("duration_minutes" > 0) AND ("duration_minutes" <= 1440))),
    CONSTRAINT "bet_guest_range" CHECK ((("guest_count_min" >= 1) AND ("guest_count_max" >= "guest_count_min"))),
    CONSTRAINT "bet_notice_nonneg" CHECK (("min_notice_hours" >= 0)),
    CONSTRAINT "bet_price_nonneg" CHECK ((("price_cents" IS NULL) OR ("price_cents" >= 0)))
);




