COMMENT ON TABLE "public"."campaign_recipients" IS 'Per-email delivery log for each campaign. Tracks open, click, and unsubscribe events.';



COMMENT ON COLUMN "public"."campaign_recipients"."resend_message_id" IS 'Resend email ID returned at send time. Used to match open/click webhook events.';



COMMENT ON COLUMN "public"."campaign_recipients"."bounced_at" IS 'Timestamp when Resend reported a bounce for this recipient. Set by the /api/webhooks/resend handler.';



COMMENT ON COLUMN "public"."campaign_recipients"."spam_at" IS 'Timestamp when Resend reported a spam complaint for this recipient. Set by the /api/webhooks/resend handler.';



