);




COMMENT ON TABLE "public"."campaign_templates" IS 'Reusable campaign message templates. is_system=true are app-seeded starters.';



CREATE TABLE IF NOT EXISTS "public"."cancellation_policies" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "name" "text" DEFAULT 'Standard Policy'::"text" NOT NULL,
    "is_default" boolean DEFAULT true NOT NULL,
    "tiers" "jsonb" DEFAULT '[{"label": "30+ days", "max_days": null, "min_days": 30, "refund_percent": 100}, {"label": "14-29 days", "max_days": 29, "min_days": 14, "refund_percent": 50}, {"label": "Less than 14 days", "max_days": 13, "min_days": 0, "refund_percent": 0}]'::"jsonb" NOT NULL,
    "grace_period_hours" integer DEFAULT 48 NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."cancellation_policies" IS 'Chef-defined cancellation policies with tiered refund percentages and grace periods.';



COMMENT ON COLUMN "public"."cancellation_policies"."tiers" IS 'JSON array of cancellation tiers. Each tier: {min_days, max_days, refund_percent, label}. max_days=null means unlimited.';



COMMENT ON COLUMN "public"."cancellation_policies"."grace_period_hours" IS 'Hours after booking during which client gets full refund regardless of tier.';



