    "claimed_at" timestamp with time zone,
    "expires_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "cannabis_tier_invitations_admin_approval_status_check" CHECK (("admin_approval_status" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'rejected'::"text"]))),
    CONSTRAINT "cannabis_tier_invitations_invited_by_user_type_check" CHECK (("invited_by_user_type" = ANY (ARRAY['chef'::"text", 'client'::"text", 'partner'::"text", 'admin'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."cannabis_tier_users" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
