    "granted_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "notes" "text",
    CONSTRAINT "cannabis_tier_users_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'suspended'::"text"]))),
    CONSTRAINT "cannabis_tier_users_user_type_check" CHECK (("user_type" = ANY (ARRAY['chef'::"text", 'client'::"text", 'partner'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."cash_drawer_movements" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "register_session_id" "uuid" NOT NULL,
    "movement_type" "public"."cash_drawer_movement_type" NOT NULL,
    "amount_cents" integer NOT NULL,
    "notes" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "commerce_payment_id" "uuid",
    "commerce_refund_id" "uuid",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "cash_drawer_movements_amount_cents_check" CHECK (("amount_cents" <> 0)),
    CONSTRAINT "cash_drawer_movements_check" CHECK (((("commerce_payment_id" IS NOT NULL) AND ("commerce_refund_id" IS NULL)) OR (("commerce_payment_id" IS NULL) AND ("commerce_refund_id" IS NOT NULL)) OR (("commerce_payment_id" IS NULL) AND ("commerce_refund_id" IS NULL)))),
    CONSTRAINT "cash_drawer_movements_check1" CHECK (
CASE "movement_type"
    WHEN 'sale_payment'::"public"."cash_drawer_movement_type" THEN ("amount_cents" > 0)
    WHEN 'refund'::"public"."cash_drawer_movement_type" THEN ("amount_cents" < 0)
    WHEN 'paid_in'::"public"."cash_drawer_movement_type" THEN ("amount_cents" > 0)
    WHEN 'paid_out'::"public"."cash_drawer_movement_type" THEN ("amount_cents" < 0)
    ELSE true
END)
);




