COMMENT ON COLUMN "public"."charity_hours"."ein" IS 'IRS Employer Identification Number from ProPublica Nonprofit Explorer. NULL if not verified.';



COMMENT ON COLUMN "public"."charity_hours"."is_verified_501c" IS 'True if the organization was found in ProPublica IRS database as a 501(c) nonprofit.';



COMMENT ON COLUMN "public"."charity_hours"."hours" IS 'Decimal hours worked (e.g. 2.5 for two and a half hours). Max 24 per entry.';



