CREATE TABLE IF NOT EXISTS "public"."chef_automation_settings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "follow_up_reminders_enabled" boolean DEFAULT true NOT NULL,
    "follow_up_reminder_interval_hours" integer DEFAULT 48 NOT NULL,
    "no_response_alerts_enabled" boolean DEFAULT true NOT NULL,
    "no_response_threshold_days" integer DEFAULT 3 NOT NULL,
    "event_approaching_alerts_enabled" boolean DEFAULT true NOT NULL,
    "event_approaching_hours" integer DEFAULT 48 NOT NULL,
    "inquiry_auto_expiry_enabled" boolean DEFAULT true NOT NULL,
    "inquiry_expiry_days" integer DEFAULT 30 NOT NULL,
    "quote_auto_expiry_enabled" boolean DEFAULT true NOT NULL,
    "client_event_reminders_enabled" boolean DEFAULT true NOT NULL,
    "time_tracking_reminders_enabled" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "receipt_upload_reminders_enabled" boolean DEFAULT true NOT NULL,
    "closure_deadline_alerts_enabled" boolean DEFAULT true NOT NULL,
    "closure_deadline_days" integer DEFAULT 3 NOT NULL,
    "weekly_summary_enabled" boolean DEFAULT false NOT NULL,
    "inquiry_auto_response_template" "text",
    "auto_response_template_enabled" boolean DEFAULT false NOT NULL,
    "payment_reminder_enabled" boolean DEFAULT true NOT NULL,
    "payment_reminder_days_before" integer DEFAULT 2 NOT NULL,
    "payment_overdue_alert_enabled" boolean DEFAULT true NOT NULL,
    "payment_overdue_alert_days_after" integer DEFAULT 1 NOT NULL,
    "default_deposit_enabled" boolean DEFAULT false NOT NULL,
    "default_deposit_type" "text" DEFAULT 'percentage'::"text" NOT NULL,
    "default_deposit_percentage" integer DEFAULT 0 NOT NULL,
    "default_deposit_amount_cents" integer DEFAULT 0 NOT NULL,
    "event_reminder_30d_enabled" boolean DEFAULT true NOT NULL,
    "event_reminder_14d_enabled" boolean DEFAULT true NOT NULL,
    "event_reminder_7d_enabled" boolean DEFAULT true NOT NULL,
    "event_reminder_2d_enabled" boolean DEFAULT true NOT NULL,
    "event_reminder_1d_enabled" boolean DEFAULT true NOT NULL,
    CONSTRAINT "chef_automation_settings_default_deposit_amount_cents_check" CHECK (("default_deposit_amount_cents" >= 0)),
    CONSTRAINT "chef_automation_settings_default_deposit_percentage_check" CHECK ((("default_deposit_percentage" >= 0) AND ("default_deposit_percentage" <= 100))),
    CONSTRAINT "chef_automation_settings_default_deposit_type_check" CHECK (("default_deposit_type" = ANY (ARRAY['percentage'::"text", 'fixed'::"text"]))),
    CONSTRAINT "chef_automation_settings_event_approaching_hours_check" CHECK ((("event_approaching_hours" >= 1) AND ("event_approaching_hours" <= 168))),
    CONSTRAINT "chef_automation_settings_follow_up_reminder_interval_hour_check" CHECK ((("follow_up_reminder_interval_hours" >= 1) AND ("follow_up_reminder_interval_hours" <= 336))),
    CONSTRAINT "chef_automation_settings_inquiry_expiry_days_check" CHECK ((("inquiry_expiry_days" >= 7) AND ("inquiry_expiry_days" <= 365))),
    CONSTRAINT "chef_automation_settings_no_response_threshold_days_check" CHECK ((("no_response_threshold_days" >= 1) AND ("no_response_threshold_days" <= 30)))
);




COMMENT ON COLUMN "public"."chef_automation_settings"."receipt_upload_reminders_enabled" IS 'Alert chef when a completed/in-progress event has no receipts uploaded within 24 hours.';



COMMENT ON COLUMN "public"."chef_automation_settings"."closure_deadline_alerts_enabled" IS 'Alert chef when a completed event has not been closed out within N days.';



COMMENT ON COLUMN "public"."chef_automation_settings"."closure_deadline_days" IS 'Days after completion before closure deadline alert fires (default 3).';



COMMENT ON COLUMN "public"."chef_automation_settings"."weekly_summary_enabled" IS 'Send a weekly digest of upcoming events, pending follow-ups, and key financials.';



COMMENT ON COLUMN "public"."chef_automation_settings"."inquiry_auto_response_template" IS 'Chef-written template that pre-fills the reply box on new inquiries. AI policy: draft only, chef must send.';



COMMENT ON COLUMN "public"."chef_automation_settings"."auto_response_template_enabled" IS 'When true, the auto-response template appears pre-filled when composing a reply to a new inquiry.';



COMMENT ON COLUMN "public"."chef_automation_settings"."payment_reminder_enabled" IS 'Send reminder N days before balance is due';



COMMENT ON COLUMN "public"."chef_automation_settings"."payment_reminder_days_before" IS 'Days before event to send payment reminder (default 2)';



COMMENT ON COLUMN "public"."chef_automation_settings"."payment_overdue_alert_enabled" IS 'Alert chef when balance goes overdue';



COMMENT ON COLUMN "public"."chef_automation_settings"."payment_overdue_alert_days_after" IS 'Days after event date before flagging as overdue (default 1)';



COMMENT ON COLUMN "public"."chef_automation_settings"."default_deposit_enabled" IS 'When true, new events auto-fill deposit from these defaults. Chef can always override or remove.';



COMMENT ON COLUMN "public"."chef_automation_settings"."default_deposit_type" IS 'Whether the default deposit is a percentage of quoted price or a fixed dollar amount.';



COMMENT ON COLUMN "public"."chef_automation_settings"."default_deposit_percentage" IS 'Default deposit as a percentage (0-100) of quoted price. Used when default_deposit_type = percentage.';



COMMENT ON COLUMN "public"."chef_automation_settings"."default_deposit_amount_cents" IS 'Default deposit as a fixed amount in cents. Used when default_deposit_type = fixed.';



COMMENT ON COLUMN "public"."chef_automation_settings"."event_reminder_30d_enabled" IS 'When false, the 30-day pre-event client email is skipped.';



COMMENT ON COLUMN "public"."chef_automation_settings"."event_reminder_14d_enabled" IS 'When false, the 14-day pre-event client email is skipped.';



COMMENT ON COLUMN "public"."chef_automation_settings"."event_reminder_7d_enabled" IS 'When false, the 7-day prepare email is skipped.';



COMMENT ON COLUMN "public"."chef_automation_settings"."event_reminder_2d_enabled" IS 'When false, the 2-day reminder email is skipped.';



COMMENT ON COLUMN "public"."chef_automation_settings"."event_reminder_1d_enabled" IS 'When false, the 1-day reminder email is skipped.';



