    "default_prep_hours" numeric(4,1) DEFAULT 4.0 NOT NULL,
    "default_travel_minutes" integer DEFAULT 60 NOT NULL,
    "default_shopping_hours" numeric(4,1) DEFAULT 2.0 NOT NULL,
    "default_cleanup_hours" numeric(4,1) DEFAULT 1.5 NOT NULL,
    "buffer_between_events_minutes" integer DEFAULT 120 NOT NULL,
    "blocked_days" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chk_buffer_minutes" CHECK ((("buffer_between_events_minutes" >= 0) AND ("buffer_between_events_minutes" <= 480))),
    CONSTRAINT "chk_cleanup_hours" CHECK ((("default_cleanup_hours" >= (0)::numeric) AND ("default_cleanup_hours" <= (24)::numeric))),
    CONSTRAINT "chk_max_events_day" CHECK ((("max_events_per_day" >= 1) AND ("max_events_per_day" <= 10))),
    CONSTRAINT "chk_max_events_week" CHECK ((("max_events_per_week" >= 1) AND ("max_events_per_week" <= 50))),
    CONSTRAINT "chk_prep_hours" CHECK ((("default_prep_hours" >= (0)::numeric) AND ("default_prep_hours" <= (24)::numeric))),
    CONSTRAINT "chk_shopping_hours" CHECK ((("default_shopping_hours" >= (0)::numeric) AND ("default_shopping_hours" <= (24)::numeric))),
    CONSTRAINT "chk_travel_minutes" CHECK ((("default_travel_minutes" >= 0) AND ("default_travel_minutes" <= 480)))
);




COMMENT ON TABLE "public"."chef_capacity_settings" IS 'Per-chef capacity planning defaults: time blocks for prep, travel, shopping, cleanup, plus daily/weekly limits and blocked days.';



CREATE TABLE IF NOT EXISTS "public"."chef_certifications" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "cert_type" "text" DEFAULT 'other'::"text" NOT NULL,
    "name" "text" NOT NULL,
    "issuing_body" "text",
    "issued_date" "date",
    "expiry_date" "date",
    "reminder_days_before" integer DEFAULT 30 NOT NULL,
    "cert_number" "text",
    "document_url" "text",
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "tenant_id" "uuid",
    "cert_name" "text",
    "issue_date" "date",
    "renewal_url" "text",
    "notes" "text",
    "is_active" boolean DEFAULT true,
    "issuer" "text",
    "issued_at" "date",
    "expires_at" "date",
    CONSTRAINT "chef_certifications_cert_type_check" CHECK (("cert_type" = ANY (ARRAY['servsafe'::"text", 'food_handler'::"text", 'servsafe_manager'::"text", 'allergen_awareness'::"text", 'business_license'::"text", 'health_permit'::"text", 'liability_insurance'::"text", 'workers_comp'::"text", 'auto_insurance'::"text", 'llc'::"text", 'cottage_food'::"text", 'other'::"text"]))),
    CONSTRAINT "chef_certifications_reminder_days_before_check" CHECK (("reminder_days_before" >= 0)),
    CONSTRAINT "chef_certifications_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'expiring_soon'::"text", 'expired'::"text", 'pending_renewal'::"text"])))
);




COMMENT ON TABLE "public"."chef_certifications" IS 'Chef professional certifications and licenses with expiry tracking.';



COMMENT ON COLUMN "public"."chef_certifications"."reminder_days_before" IS 'How many days before expiry to trigger a reminder notification.';



