);




CREATE TABLE IF NOT EXISTS "public"."chef_connections" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "requester_id" "uuid" NOT NULL,
    "addressee_id" "uuid" NOT NULL,
    "status" "public"."chef_connection_status" DEFAULT 'pending'::"public"."chef_connection_status" NOT NULL,
    "request_message" "text",
