);




COMMENT ON TABLE "public"."chef_connections" IS 'Cross-tenant chef-to-chef connections. NOT scoped to a single tenant - spans across tenants by design.';



COMMENT ON COLUMN "public"."chef_connections"."requester_id" IS 'The chef who initiated the connection request';



COMMENT ON COLUMN "public"."chef_connections"."addressee_id" IS 'The chef who received the connection request';



COMMENT ON COLUMN "public"."chef_connections"."request_message" IS 'Optional personal message sent with the request';



