CREATE TABLE IF NOT EXISTS "public"."chef_feedback" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid",
    "event_id" "uuid",
    "source" "text" NOT NULL,
    "rating" integer,
    "feedback_text" "text" NOT NULL,
    "source_url" "text",
    "feedback_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "logged_by" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reviewer_name" "text",
    "public_display" boolean DEFAULT false NOT NULL,
    CONSTRAINT "chef_feedback_rating_check" CHECK ((("rating" IS NULL) OR (("rating" >= 1) AND ("rating" <= 5)))),
    CONSTRAINT "chef_feedback_source_check" CHECK (("source" = ANY (ARRAY['verbal'::"text", 'google'::"text", 'yelp'::"text", 'email'::"text", 'social_media'::"text", 'text_message'::"text", 'other'::"text", 'airbnb'::"text", 'facebook'::"text", 'tripadvisor'::"text", 'thumbtack'::"text", 'bark'::"text", 'gigsalad'::"text", 'taskrabbit'::"text", 'houzz'::"text", 'angi'::"text", 'nextdoor'::"text", 'instagram'::"text", 'yelp_guest'::"text"])))
);




COMMENT ON TABLE "public"."chef_feedback" IS 'Chef-logged external feedback: verbal, Google reviews, Yelp, social media, etc. Separate from client_reviews (client-submitted).';



COMMENT ON COLUMN "public"."chef_feedback"."reviewer_name" IS 'Name of the external reviewer for platform-imported reviews (Airbnb, Facebook, etc.).
   NULL when client_id is set (reviewer is a known ChefFlow client).
   Populated manually for all non-ChefFlow platform sources.';



COMMENT ON COLUMN "public"."chef_feedback"."public_display" IS 'When true, this feedback entry is visible on the chef public profile page.
   Defaults to false — chefs must opt-in each entry for public display.';



