    "tracking_method" "text" DEFAULT 'auto'::"text" NOT NULL,
    CONSTRAINT "chef_goals_nudge_level_check" CHECK (("nudge_level" = ANY (ARRAY['gentle'::"text", 'standard'::"text", 'aggressive'::"text"]))),
    CONSTRAINT "chef_goals_period_order" CHECK (("period_start" <= "period_end")),
    CONSTRAINT "chef_goals_target_value_check" CHECK (("target_value" >= 0)),
    CONSTRAINT "chef_goals_tracking_method_check" CHECK (("tracking_method" = ANY (ARRAY['auto'::"text", 'manual_count'::"text"])))
);




