    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_handoff_events_event_type_check" CHECK (("event_type" = ANY (ARRAY['created'::"text", 'viewed'::"text", 'accepted'::"text", 'rejected'::"text", 'withdrawn'::"text", 'converted'::"text", 'cancelled'::"text", 'status_recomputed'::"text"])))
);




COMMENT ON TABLE "public"."chef_handoff_events" IS 'Append-only timeline for handoff lifecycle actions.';



CREATE TABLE IF NOT EXISTS "public"."chef_handoff_recipients" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
