    "converted_event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_handoff_recipients_status_check" CHECK (("status" = ANY (ARRAY['sent'::"text", 'viewed'::"text", 'accepted'::"text", 'rejected'::"text", 'withdrawn'::"text", 'converted'::"text"])))
);




COMMENT ON TABLE "public"."chef_handoff_recipients" IS 'Per-recipient response state for a handoff.';



CREATE TABLE IF NOT EXISTS "public"."chef_handoffs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "from_chef_id" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "handoff_type" "text" NOT NULL,
    "source_entity_type" "text",
    "source_entity_id" "uuid",
    "occasion" "text",
    "event_date" "date",
    "guest_count" integer,
    "location_text" "text",
    "budget_cents" integer,
    "client_context" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "private_note" "text",
    "visibility_scope" "text" DEFAULT 'trusted_circle'::"text" NOT NULL,
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "expires_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_handoffs_budget_cents_check" CHECK ((("budget_cents" IS NULL) OR ("budget_cents" >= 0))),
    CONSTRAINT "chef_handoffs_guest_count_check" CHECK ((("guest_count" IS NULL) OR (("guest_count" >= 1) AND ("guest_count" <= 2000)))),
    CONSTRAINT "chef_handoffs_handoff_type_check" CHECK (("handoff_type" = ANY (ARRAY['lead'::"text", 'event_backup'::"text", 'client_referral'::"text"]))),
    CONSTRAINT "chef_handoffs_source_entity_type_check" CHECK (("source_entity_type" = ANY (ARRAY['inquiry'::"text", 'event'::"text", 'manual'::"text"]))),
    CONSTRAINT "chef_handoffs_status_check" CHECK (("status" = ANY (ARRAY['open'::"text", 'partially_accepted'::"text", 'closed'::"text", 'cancelled'::"text", 'expired'::"text"]))),
    CONSTRAINT "chef_handoffs_title_check" CHECK ((("char_length"("title") >= 3) AND ("char_length"("title") <= 200))),
    CONSTRAINT "chef_handoffs_visibility_scope_check" CHECK (("visibility_scope" = ANY (ARRAY['trusted_circle'::"text", 'selected_chefs'::"text", 'connections'::"text"])))
);




COMMENT ON TABLE "public"."chef_handoffs" IS 'Structured collaboration handoffs (lead swaps, backup requests, referrals).';



COMMENT ON COLUMN "public"."chef_handoffs"."client_context" IS 'Structured context without mandatory PII (budget notes, constraints, scope).';



