    CONSTRAINT "chef_journal_media_url_length" CHECK ((("char_length"(TRIM(BOTH FROM "media_url")) >= 8) AND ("char_length"(TRIM(BOTH FROM "media_url")) <= 2000)))
);




COMMENT ON TABLE "public"."chef_journal_media" IS 'Media memories for a chef journal: photos, videos, and document references.';



CREATE TABLE IF NOT EXISTS "public"."chef_journal_recipe_links" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "journey_id" "uuid" NOT NULL,
    "entry_id" "uuid",
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "recipe_id" "uuid" NOT NULL,
