);




COMMENT ON TABLE "public"."chef_journal_recipe_links" IS 'Links journal moments to concrete recipes, tests, ratings, and progression notes.';



CREATE TABLE IF NOT EXISTS "public"."chef_journey_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "journey_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "entry_type" "public"."chef_journey_entry_type" DEFAULT 'reflection'::"public"."chef_journey_entry_type" NOT NULL,
    "entry_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "location_label" "text" DEFAULT ''::"text" NOT NULL,
    "title" "text" NOT NULL,
    "narrative" "text" DEFAULT ''::"text" NOT NULL,
    "favorite_meal" "text" DEFAULT ''::"text" NOT NULL,
    "favorite_experience" "text" DEFAULT ''::"text" NOT NULL,
    "what_i_learned" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "inspiration_taken" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "dishes_to_explore" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "source_links" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "is_highlight" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "formatted_address" "text" DEFAULT ''::"text" NOT NULL,
    "latitude" double precision,
    "longitude" double precision,
    "mistakes_made" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "proud_moments" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "what_to_change_next_time" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    CONSTRAINT "chef_journey_entries_title_length" CHECK ((("char_length"(TRIM(BOTH FROM "title")) >= 3) AND ("char_length"(TRIM(BOTH FROM "title")) <= 180)))
);




COMMENT ON TABLE "public"."chef_journey_entries" IS 'Detailed chronological entries inside a chef journey (meals, lessons, reflections, techniques).';



COMMENT ON COLUMN "public"."chef_journey_entries"."what_i_learned" IS 'Concrete lessons extracted from the entry.';



COMMENT ON COLUMN "public"."chef_journey_entries"."formatted_address" IS 'Optional structured address for map rendering and historical context.';



COMMENT ON COLUMN "public"."chef_journey_entries"."mistakes_made" IS 'What went wrong in this moment so chefs can learn and improve over time.';



COMMENT ON COLUMN "public"."chef_journey_entries"."proud_moments" IS 'Wins worth celebrating and revisiting to reinforce growth.';



CREATE TABLE IF NOT EXISTS "public"."chef_journey_ideas" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "journey_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "source_entry_id" "uuid",
    "created_by" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "concept_notes" "text" DEFAULT ''::"text" NOT NULL,
    "application_area" "public"."chef_journey_idea_area" DEFAULT 'menu'::"public"."chef_journey_idea_area" NOT NULL,
    "status" "public"."chef_journey_idea_status" DEFAULT 'backlog'::"public"."chef_journey_idea_status" NOT NULL,
    "priority" smallint DEFAULT 3 NOT NULL,
    "expected_impact" "text" DEFAULT ''::"text" NOT NULL,
    "test_plan" "text" DEFAULT ''::"text" NOT NULL,
    "first_test_date" "date",
    "adopted_on" "date",
    "adopted_recipe_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_journey_ideas_adopted_requires_date" CHECK ((("status" <> 'adopted'::"public"."chef_journey_idea_status") OR ("adopted_on" IS NOT NULL))),
    CONSTRAINT "chef_journey_ideas_priority_range" CHECK ((("priority" >= 1) AND ("priority" <= 5))),
    CONSTRAINT "chef_journey_ideas_title_length" CHECK ((("char_length"(TRIM(BOTH FROM "title")) >= 3) AND ("char_length"(TRIM(BOTH FROM "title")) <= 180)))
);




COMMENT ON TABLE "public"."chef_journey_ideas" IS 'Idea pipeline derived from journey learnings, tracked from backlog to adoption.';



CREATE TABLE IF NOT EXISTS "public"."chef_journeys" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "destination_city" "text",
    "destination_region" "text",
    "destination_country" "text",
    "started_on" "date",
    "ended_on" "date",
    "status" "public"."chef_journey_status" DEFAULT 'planning'::"public"."chef_journey_status" NOT NULL,
    "trip_summary" "text" DEFAULT ''::"text" NOT NULL,
    "favorite_meal" "text" DEFAULT ''::"text" NOT NULL,
    "favorite_experience" "text" DEFAULT ''::"text" NOT NULL,
    "key_learnings" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "inspiration_ideas" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "culinary_focus_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
