);




COMMENT ON TABLE "public"."chef_journeys" IS 'Chef-authored culinary journeys (trips, stages, research tours) used to capture growth over time.';



COMMENT ON COLUMN "public"."chef_journeys"."key_learnings" IS 'Short bullet learnings from the journey; powers the chef learning repertoire.';



COMMENT ON COLUMN "public"."chef_journeys"."inspiration_ideas" IS 'High-level ideas chefs want to bring back into their own practice.';



CREATE TABLE IF NOT EXISTS "public"."chef_marketplace_profiles" (
