);




COMMENT ON TABLE "public"."chef_network_feature_preferences" IS 'Per-chef opt-in / opt-out settings for network feed feature categories.';



COMMENT ON COLUMN "public"."chef_network_feature_preferences"."event_collaboration" IS 'When false, this chef cannot receive event collaboration invitations.';



COMMENT ON COLUMN "public"."chef_network_feature_preferences"."recipe_sharing" IS 'When false, this chef cannot receive recipe share requests.';



CREATE TABLE IF NOT EXISTS "public"."chef_network_posts" (
