);




COMMENT ON TABLE "public"."chef_network_posts" IS 'Cross-tenant chef network feed posts. Visible to self + accepted connections.';



COMMENT ON COLUMN "public"."chef_network_posts"."author_chef_id" IS 'Chef who authored the post.';



COMMENT ON COLUMN "public"."chef_network_posts"."feature_key" IS 'Feature category for the post (availability, referral ask, sourcing intel, etc).';



