    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_post_comments_content_check" CHECK ((("char_length"("content") >= 1) AND ("char_length"("content") <= 2000))),
    CONSTRAINT "chef_post_comments_reactions_count_check" CHECK (("reactions_count" >= 0)),
    CONSTRAINT "chef_post_comments_replies_count_check" CHECK (("replies_count" >= 0))
);




