    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_post_reactions_reaction_type_check" CHECK (("reaction_type" = ANY (ARRAY['like'::"text", 'fire'::"text", 'clap'::"text", 'wow'::"text", 'hungry'::"text", 'insightful'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."chef_post_saves" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "post_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "collection_name" "text" DEFAULT 'Saved'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_post_saves_collection_name_check" CHECK (("char_length"("collection_name") <= 50))
);




CREATE TABLE IF NOT EXISTS "public"."chef_preferences" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "home_address" "text",
    "home_city" "text",
    "home_state" "text" DEFAULT 'MA'::"text",
    "home_zip" "text",
    "default_grocery_store" "text",
    "default_grocery_address" "text",
    "default_liquor_store" "text",
    "default_liquor_address" "text",
    "default_specialty_stores" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "default_buffer_minutes" integer DEFAULT 30 NOT NULL,
    "default_prep_hours" numeric(4,1) DEFAULT 3.0 NOT NULL,
    "default_shopping_minutes" integer DEFAULT 60 NOT NULL,
    "default_packing_minutes" integer DEFAULT 30 NOT NULL,
    "target_margin_percent" numeric(5,2) DEFAULT 60.00 NOT NULL,
    "shop_day_before" boolean DEFAULT true NOT NULL,
    "wake_time_earliest" "text" DEFAULT '08:00'::"text" NOT NULL,
    "wake_time_latest" "text" DEFAULT '10:00'::"text" NOT NULL,
    "network_discoverable" boolean DEFAULT true NOT NULL,
    "revenue_goal_program_enabled" boolean DEFAULT false NOT NULL,
    "target_monthly_revenue_cents" integer DEFAULT 1000000 NOT NULL,
    "target_annual_revenue_cents" integer,
    "revenue_goal_custom" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "revenue_goal_nudge_level" "text" DEFAULT 'gentle'::"text" NOT NULL,
    "dashboard_widgets" "jsonb" DEFAULT '[{"id": "onboarding_accelerator", "enabled": true}, {"id": "todays_schedule", "enabled": true}, {"id": "next_action", "enabled": true}, {"id": "week_strip", "enabled": true}, {"id": "priority_queue", "enabled": true}, {"id": "prep_prompts", "enabled": true}, {"id": "service_quality", "enabled": true}, {"id": "business_snapshot", "enabled": true}, {"id": "career_growth", "enabled": true}, {"id": "hours", "enabled": true}, {"id": "activity", "enabled": true}]'::"jsonb" NOT NULL,
    "sms_notify_phone" "text",
    "sms_opt_in" boolean DEFAULT false NOT NULL,
    "sms_opt_in_at" timestamp with time zone,
    "primary_nav_hrefs" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "is_business" boolean DEFAULT false NOT NULL,
    "business_legal_name" "text",
    "business_address" "text",
    "max_events_per_month" integer,
    "owner_hourly_rate_cents" integer,
    "enabled_goal_categories" "text"[] DEFAULT ARRAY['financial'::"text", 'business_growth'::"text"] NOT NULL,
    "category_nudge_levels" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "activity_log_enabled" boolean DEFAULT true NOT NULL,
    "enabled_modules" "text"[] DEFAULT ARRAY['dashboard'::"text", 'pipeline'::"text", 'events'::"text", 'culinary'::"text", 'calendar'::"text", 'clients'::"text", 'finance'::"text"],
    "archetype" "text",
    "saved_custom_nav_hrefs" "jsonb",
    "notification_quiet_hours_enabled" boolean DEFAULT false NOT NULL,
    "notification_quiet_hours_start" time without time zone,
    "notification_quiet_hours_end" time without time zone,
    "notification_digest_enabled" boolean DEFAULT false NOT NULL,
    "notification_digest_interval_minutes" integer DEFAULT 15 NOT NULL,
    "visitor_alerts_enabled" boolean DEFAULT true NOT NULL,
    "print_preferences" "jsonb" DEFAULT '{"custom_footer": null, "attribution_name": null, "show_attribution": true, "default_print_mode": "standard"}'::"jsonb" NOT NULL,
    "focus_mode" boolean DEFAULT true,
    "locked_event_id" "uuid",
    "sms_enabled" boolean DEFAULT false,
    "twilio_account_sid" "text",
    "twilio_auth_token" "text",
    "twilio_phone_number" "text",
    "food_cost_target_percent" integer DEFAULT 30,
    CONSTRAINT "chef_preferences_archetype_check" CHECK ((("archetype" IS NULL) OR ("archetype" = ANY (ARRAY['private-chef'::"text", 'caterer'::"text", 'meal-prep'::"text", 'restaurant'::"text", 'food-truck'::"text", 'bakery'::"text"])))),
    CONSTRAINT "chef_preferences_dashboard_widgets_array" CHECK (("jsonb_typeof"("dashboard_widgets") = 'array'::"text")),
    CONSTRAINT "chef_preferences_max_events_per_month_check" CHECK (("max_events_per_month" > 0)),
    CONSTRAINT "chef_preferences_notification_digest_interval_minutes_range" CHECK ((("notification_digest_interval_minutes" >= 5) AND ("notification_digest_interval_minutes" <= 120))),
    CONSTRAINT "chef_preferences_owner_hourly_rate_cents_check" CHECK (("owner_hourly_rate_cents" > 0)),
    CONSTRAINT "chef_preferences_primary_nav_hrefs_array" CHECK (("jsonb_typeof"("primary_nav_hrefs") = 'array'::"text")),
    CONSTRAINT "chef_preferences_revenue_goal_custom_array" CHECK (("jsonb_typeof"("revenue_goal_custom") = 'array'::"text")),
    CONSTRAINT "chef_preferences_revenue_goal_nudge_level_valid" CHECK (("revenue_goal_nudge_level" = ANY (ARRAY['gentle'::"text", 'standard'::"text", 'aggressive'::"text"]))),
    CONSTRAINT "chef_preferences_target_annual_revenue_nonnegative" CHECK ((("target_annual_revenue_cents" IS NULL) OR ("target_annual_revenue_cents" >= 0))),
    CONSTRAINT "chef_preferences_target_monthly_revenue_nonnegative" CHECK (("target_monthly_revenue_cents" >= 0)),
    CONSTRAINT "prefs_buffer_positive" CHECK ((("default_buffer_minutes" >= 0) AND ("default_buffer_minutes" <= 120))),
    CONSTRAINT "prefs_margin_range" CHECK ((("target_margin_percent" >= (0)::numeric) AND ("target_margin_percent" <= (100)::numeric))),
    CONSTRAINT "prefs_packing_positive" CHECK ((("default_packing_minutes" >= 10) AND ("default_packing_minutes" <= 120))),
    CONSTRAINT "prefs_prep_positive" CHECK ((("default_prep_hours" >= 0.5) AND ("default_prep_hours" <= (12)::numeric))),
    CONSTRAINT "prefs_shopping_positive" CHECK ((("default_shopping_minutes" >= 15) AND ("default_shopping_minutes" <= 240)))
);




COMMENT ON COLUMN "public"."chef_preferences"."network_discoverable" IS 'When true, this chef appears in network search results. When false, completely hidden from discovery.';



COMMENT ON COLUMN "public"."chef_preferences"."sms_notify_phone" IS 'E.164 phone number for SMS notifications. May differ from business phone.';



COMMENT ON COLUMN "public"."chef_preferences"."sms_opt_in" IS 'Explicit SMS consent flag. SMS is never sent without this being true.';



COMMENT ON COLUMN "public"."chef_preferences"."sms_opt_in_at" IS 'Timestamp when chef opted in to SMS.';



COMMENT ON COLUMN "public"."chef_preferences"."is_business" IS 'Chef has opted into business-mode features. When false, tax workflow, compliance, and legal name fields are hidden. Defaults to false so new chefs see a personal-first experience.';



COMMENT ON COLUMN "public"."chef_preferences"."business_legal_name" IS 'Legal registered business name (e.g. "Jane Smith LLC"). Separate from display name.';



COMMENT ON COLUMN "public"."chef_preferences"."business_address" IS 'Primary business mailing address for invoices and tax documents.';



COMMENT ON COLUMN "public"."chef_preferences"."max_events_per_month" IS 'Chef-configured capacity ceiling: maximum events they can take per calendar month. Used to compute capacity utilization %.';



COMMENT ON COLUMN "public"."chef_preferences"."owner_hourly_rate_cents" IS 'Chef''s own imputed hourly rate in cents. Used to compute true labor cost per event (owner hours × rate) for net profit after labor calculations.';



COMMENT ON COLUMN "public"."chef_preferences"."enabled_goal_categories" IS 'Goal category slugs the chef has opted into. Core categories (financial, business_growth) are always included.';



COMMENT ON COLUMN "public"."chef_preferences"."category_nudge_levels" IS 'Per-category nudge intensity override. Keys are category slugs; values are gentle|standard|aggressive. Missing keys fall back to the goal-level nudge_level.';



COMMENT ON COLUMN "public"."chef_preferences"."activity_log_enabled" IS 'When true (default), chef actions are recorded to chef_activity_log. When false, logChefActivity() skips writes. Existing log entries are preserved regardless.';



COMMENT ON COLUMN "public"."chef_preferences"."archetype" IS 'Chef persona preset — controls default nav layout. NULL = not yet selected.';



COMMENT ON COLUMN "public"."chef_preferences"."saved_custom_nav_hrefs" IS 'Chef-saved custom nav layout they can restore anytime.';



COMMENT ON COLUMN "public"."chef_preferences"."notification_quiet_hours_enabled" IS 'When true, non-critical in-app toasts are suppressed during configured quiet window.';



COMMENT ON COLUMN "public"."chef_preferences"."notification_quiet_hours_start" IS 'Quiet window start time in local chef timezone (HH:MM).';



COMMENT ON COLUMN "public"."chef_preferences"."notification_quiet_hours_end" IS 'Quiet window end time in local chef timezone (HH:MM).';



COMMENT ON COLUMN "public"."chef_preferences"."notification_digest_enabled" IS 'When true, non-critical in-app notifications are batched into digest toasts.';



COMMENT ON COLUMN "public"."chef_preferences"."notification_digest_interval_minutes" IS 'Digest flush interval in minutes for non-critical in-app notifications.';



COMMENT ON COLUMN "public"."chef_preferences"."visitor_alerts_enabled" IS 'When true, chef receives email + push alerts when clients visit the portal';



COMMENT ON COLUMN "public"."chef_preferences"."print_preferences" IS 'Print/document preferences. Keys: show_attribution (bool), attribution_name (string|null, defaults to business_name), default_print_mode (standard|thermal-80|thermal-58), custom_footer (string|null)';



COMMENT ON COLUMN "public"."chef_preferences"."focus_mode" IS 'Progressive disclosure: when true, sidebar shows only core modules. All features remain accessible when turned off.';



COMMENT ON COLUMN "public"."chef_preferences"."locked_event_id" IS 'When set, chef is in event lock-in mode. Nav shows only event-relevant sections.';



CREATE TABLE IF NOT EXISTS "public"."chef_preferred_stores" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "store_name" "text" NOT NULL,
    "store_type" "text" DEFAULT 'supermarket'::"text" NOT NULL,
    "address" "text",
    "notes" "text",
    "is_default" boolean DEFAULT false,
    "sort_order" integer DEFAULT 0,
    "created_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "chef_preferred_stores_store_type_check" CHECK (("store_type" = ANY (ARRAY['supermarket'::"text", 'costco_wholesale'::"text", 'farmers_market'::"text", 'specialty'::"text", 'butcher'::"text", 'fishmonger'::"text", 'bakery'::"text", 'international'::"text", 'online'::"text", 'other'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."chef_profiles" (
