    "related_client_id" "uuid",
    "related_inquiry_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_reminders_reminder_type_check" CHECK (("reminder_type" = ANY (ARRAY['general'::"text", 'follow_up'::"text", 'prep'::"text", 'inquiry'::"text", 'birthday'::"text", 'event'::"text", 'payment'::"text"]))),
    CONSTRAINT "chef_reminders_source_check" CHECK (("source" = ANY (ARRAY['auto'::"text", 'manual'::"text", 'remy'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."chef_scheduling_rules" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "blocked_days_of_week" integer[] DEFAULT '{}'::integer[] NOT NULL,
    "max_events_per_week" integer,
    "max_events_per_month" integer,
    "min_buffer_days" integer DEFAULT 0 NOT NULL,
    "min_lead_days" integer DEFAULT 0 NOT NULL,
    "preferred_days_of_week" integer[] DEFAULT '{}'::integer[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "csr_buffer_days_nonneg" CHECK (("min_buffer_days" >= 0)),
    CONSTRAINT "csr_lead_days_nonneg" CHECK (("min_lead_days" >= 0)),
    CONSTRAINT "csr_max_month_pos" CHECK ((("max_events_per_month" IS NULL) OR ("max_events_per_month" > 0))),
    CONSTRAINT "csr_max_week_pos" CHECK ((("max_events_per_week" IS NULL) OR ("max_events_per_week" > 0)))
);




CREATE TABLE IF NOT EXISTS "public"."chef_seasonal_availability" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "season_name" "text" NOT NULL,
