CREATE TABLE IF NOT EXISTS "public"."chef_service_types" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "pricing_model" "text" DEFAULT 'flat_rate'::"text" NOT NULL,
    "base_price_cents" integer DEFAULT 0 NOT NULL,
    "per_person_cents" integer DEFAULT 0 NOT NULL,
    "typical_guest_count" integer DEFAULT 2 NOT NULL,
    "min_guests" integer,
    "max_guests" integer,
    "is_active" boolean DEFAULT true NOT NULL,
    "sort_order" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_service_types_base_price_cents_check" CHECK (("base_price_cents" >= 0)),
    CONSTRAINT "chef_service_types_check" CHECK ((("max_guests" IS NULL) OR ("max_guests" >= COALESCE("min_guests", 1)))),
    CONSTRAINT "chef_service_types_min_guests_check" CHECK ((("min_guests" IS NULL) OR ("min_guests" > 0))),
    CONSTRAINT "chef_service_types_name_check" CHECK ((("char_length"("name") >= 1) AND ("char_length"("name") <= 100))),
    CONSTRAINT "chef_service_types_per_person_cents_check" CHECK (("per_person_cents" >= 0)),
    CONSTRAINT "chef_service_types_pricing_model_check" CHECK (("pricing_model" = ANY (ARRAY['flat_rate'::"text", 'per_person'::"text", 'hybrid'::"text"]))),
    CONSTRAINT "chef_service_types_typical_guest_count_check" CHECK (("typical_guest_count" > 0))
);




CREATE TABLE IF NOT EXISTS "public"."chef_social_channels" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "slug" "text" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "icon" "text",
    "color" "text",
    "category" "text" DEFAULT 'general'::"text" NOT NULL,
    "is_official" boolean DEFAULT false NOT NULL,
    "created_by_chef_id" "uuid",
    "member_count" integer DEFAULT 0 NOT NULL,
    "post_count" integer DEFAULT 0 NOT NULL,
    "visibility" "text" DEFAULT 'public'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chef_social_channels_category_check" CHECK (("category" = ANY (ARRAY['cuisine'::"text", 'technique'::"text", 'business'::"text", 'tools'::"text", 'community'::"text", 'general'::"text"]))),
    CONSTRAINT "chef_social_channels_color_check" CHECK (("color" ~ '^#[0-9a-fA-F]{6}$'::"text")),
    CONSTRAINT "chef_social_channels_description_check" CHECK (("char_length"("description") <= 500)),
    CONSTRAINT "chef_social_channels_icon_check" CHECK (("char_length"("icon") <= 10)),
    CONSTRAINT "chef_social_channels_member_count_check" CHECK (("member_count" >= 0)),
    CONSTRAINT "chef_social_channels_name_check" CHECK ((("char_length"("name") >= 2) AND ("char_length"("name") <= 60))),
    CONSTRAINT "chef_social_channels_post_count_check" CHECK (("post_count" >= 0)),
    CONSTRAINT "chef_social_channels_slug_check" CHECK (("slug" ~ '^[a-z0-9][a-z0-9\-]{1,48}[a-z0-9]$'::"text")),
    CONSTRAINT "chef_social_channels_visibility_check" CHECK (("visibility" = ANY (ARRAY['public'::"text", 'private'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."chef_social_hashtags" (
