    CONSTRAINT "chef_social_notifications_notification_type_check" CHECK (("notification_type" = ANY (ARRAY['new_follower'::"text", 'post_reaction'::"text", 'post_comment'::"text", 'comment_reply'::"text", 'comment_reaction'::"text", 'post_share'::"text", 'mention_post'::"text", 'mention_comment'::"text", 'channel_post'::"text", 'story_reaction'::"text", 'story_view'::"text", 'connection_accepted'::"text", 'collab_handoff_received'::"text", 'collab_handoff_accepted'::"text", 'collab_handoff_rejected'::"text", 'collab_handoff_converted'::"text", 'collab_handoff_cancelled'::"text"])))
