    CONSTRAINT "chef_social_posts_location_tag_check" CHECK (("char_length"("location_tag") <= 100)),
    CONSTRAINT "chef_social_posts_poll_question_check" CHECK (("char_length"("poll_question") <= 200)),
    CONSTRAINT "chef_social_posts_post_type_check" CHECK (("post_type" = ANY (ARRAY['text'::"text", 'photo'::"text", 'video'::"text", 'reel'::"text", 'poll'::"text", 'share'::"text"]))),
    CONSTRAINT "chef_social_posts_reactions_count_check" CHECK (("reactions_count" >= 0)),
    CONSTRAINT "chef_social_posts_saves_count_check" CHECK (("saves_count" >= 0)),
    CONSTRAINT "chef_social_posts_share_comment_check" CHECK (("char_length"("share_comment") <= 1000)),
    CONSTRAINT "chef_social_posts_shares_count_check" CHECK (("shares_count" >= 0)),
    CONSTRAINT "chef_social_posts_visibility_check" CHECK (("visibility" = ANY (ARRAY['public'::"text", 'followers'::"text", 'connections'::"text", 'private'::"text"])))
);




