);




COMMENT ON TABLE "public"."chef_trusted_circle" IS 'Private list of high-trust chef relationships used for handoff prioritization.';



CREATE TABLE IF NOT EXISTS "public"."chefs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "auth_user_id" "uuid" NOT NULL,
    "business_name" "text" NOT NULL,
    "email" "text" NOT NULL,
    "phone" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "google_review_url" "text",
    "display_name" "text",
    "bio" "text",
    "profile_image_url" "text",
    "slug" "text",
    "tagline" "text",
    "portal_primary_color" "text",
    "portal_background_color" "text",
    "portal_background_image_url" "text",
    "website_url" "text",
    "show_website_on_public_profile" boolean DEFAULT true NOT NULL,
    "preferred_inquiry_destination" "text" DEFAULT 'both'::"text" NOT NULL,
    "cancellation_cutoff_days" integer DEFAULT 15 NOT NULL,
    "deposit_refundable" boolean DEFAULT false NOT NULL,
    "show_availability_signals" boolean DEFAULT false NOT NULL,
    "onboarding_completed_at" timestamp with time zone,
    "stripe_account_id" "text",
    "stripe_onboarding_complete" boolean DEFAULT false NOT NULL,
    "logo_url" "text",
    "account_status" "text" DEFAULT 'active'::"text" NOT NULL,
    "current_closure_streak" integer DEFAULT 0 NOT NULL,
    "longest_closure_streak" integer DEFAULT 0 NOT NULL,
    "last_closure_date" "date",
    "booking_slug" "text",
    "booking_enabled" boolean DEFAULT false NOT NULL,
    "booking_headline" "text",
    "booking_bio_short" "text",
    "booking_min_notice_days" integer DEFAULT 7 NOT NULL,
    "booking_deposit_percent" integer DEFAULT 0 NOT NULL,
    "timezone" "text" DEFAULT 'America/New_York'::"text" NOT NULL,
    "portfolio_enabled" boolean DEFAULT false,
    "portfolio_layout" "text" DEFAULT 'grid'::"text",
    "booking_model" "text" DEFAULT 'inquiry_first'::"text",
    "booking_base_price_cents" integer,
    "booking_pricing_type" "text" DEFAULT 'flat_rate'::"text",
    "booking_deposit_type" "text" DEFAULT 'percent'::"text",
    "booking_deposit_fixed_cents" integer DEFAULT 0,
    "platform_fee_percent" numeric(5,2) DEFAULT 0.00 NOT NULL,
    "platform_fee_fixed_cents" integer DEFAULT 0 NOT NULL,
    "gratuity_mode" "text" DEFAULT 'discretionary'::"text" NOT NULL,
    "gratuity_service_fee_pct" numeric(5,2),
    "gratuity_display_label" "text",
    "stripe_customer_id" "text",
    "stripe_subscription_id" "text",
    "subscription_status" "text",
    "trial_ends_at" timestamp with time zone,
    "subscription_current_period_end" timestamp with time zone,
    "max_events_per_week" integer,
    "max_events_per_month" integer,
    "max_consecutive_working_days" integer DEFAULT 7,
    "min_rest_days_per_week" integer DEFAULT 1,
    "max_hours_per_week" integer,
    "off_hours_start" time without time zone,
    "off_hours_end" time without time zone,
    "off_days" "text"[] DEFAULT '{}'::"text"[],
    "business_continuity_plan" "jsonb" DEFAULT '{}'::"jsonb",
    "remy_blocked_until" timestamp with time zone,
    "directory_approved" boolean DEFAULT false NOT NULL,
    "deletion_requested_at" timestamp with time zone,
    "deletion_scheduled_for" timestamp with time zone,
    "deletion_reason" "text",
    "deletion_reactivation_token" "uuid",
    "is_deleted" boolean DEFAULT false NOT NULL,
    "ical_feed_token" "uuid" DEFAULT "gen_random_uuid"(),
    "ical_feed_enabled" boolean DEFAULT false,
    "apple_pay_enabled" boolean DEFAULT true,
    "google_pay_enabled" boolean DEFAULT true,
    "dismissed_recall_ids" "text"[] DEFAULT '{}'::"text"[],
    "prep_timeline_visibility" "jsonb" DEFAULT '{"setup": true, "travel": true, "cleanup": true, "cooking": true, "packing": true, "serving": true, "complete": true, "prep_work": true, "menu_planning": true, "ingredient_sourcing": true}'::"jsonb" NOT NULL,
    "show_dietary_confirmation" boolean DEFAULT true NOT NULL,
    "default_show_cost_breakdown" boolean DEFAULT false NOT NULL,
    "default_exclusions_note" "text",
    "live_tracker_visibility" "jsonb" DEFAULT '{"arrived": true, "cleanup": false, "dessert": true, "complete": true, "en_route": true, "setting_up": false, "main_course": true, "first_course": true, "prep_underway": false}'::"jsonb" NOT NULL,
    "show_guest_details_to_host" boolean DEFAULT true NOT NULL,
    "preferred_currency" "text" DEFAULT 'USD'::"text" NOT NULL,
    "preferred_locale" "text" DEFAULT 'en-US'::"text" NOT NULL,
    "ical_feed_expires_at" timestamp with time zone DEFAULT ("now"() + '90 days'::interval),
    "ical_feed_last_accessed_at" timestamp with time zone,
    "kds_pin" "text",
    CONSTRAINT "chefs_account_status_check" CHECK (("account_status" = ANY (ARRAY['active'::"text", 'suspended'::"text"]))),
    CONSTRAINT "chefs_booking_deposit_pct_range" CHECK ((("booking_deposit_percent" >= 0) AND ("booking_deposit_percent" <= 100))),
    CONSTRAINT "chefs_booking_deposit_type_check" CHECK (("booking_deposit_type" = ANY (ARRAY['percent'::"text", 'fixed'::"text"]))),
    CONSTRAINT "chefs_booking_min_notice_range" CHECK ((("booking_min_notice_days" >= 0) AND ("booking_min_notice_days" <= 90))),
    CONSTRAINT "chefs_booking_model_check" CHECK (("booking_model" = ANY (ARRAY['inquiry_first'::"text", 'instant_book'::"text"]))),
    CONSTRAINT "chefs_booking_pricing_type_check" CHECK (("booking_pricing_type" = ANY (ARRAY['flat_rate'::"text", 'per_person'::"text"]))),
    CONSTRAINT "chefs_booking_slug_format" CHECK ((("booking_slug" IS NULL) OR ("booking_slug" ~ '^[a-z0-9][a-z0-9\-]*[a-z0-9]$'::"text"))),
    CONSTRAINT "chefs_platform_fee_fixed_cents_range" CHECK (("platform_fee_fixed_cents" >= 0)),
    CONSTRAINT "chefs_platform_fee_percent_range" CHECK ((("platform_fee_percent" >= (0)::numeric) AND ("platform_fee_percent" <= (100)::numeric))),
    CONSTRAINT "chefs_portfolio_layout_check" CHECK (("portfolio_layout" = ANY (ARRAY['grid'::"text", 'masonry'::"text", 'carousel'::"text"]))),
    CONSTRAINT "chefs_preferred_inquiry_destination_check" CHECK (("preferred_inquiry_destination" = ANY (ARRAY['website_only'::"text", 'chefflow_only'::"text", 'both'::"text"]))),
    CONSTRAINT "chefs_timezone_nonempty" CHECK (("timezone" <> ''::"text"))
);




COMMENT ON TABLE "public"."chefs" IS 'Tenant owners - private chef businesses (multi-tenant root). Chef records are never deleted, only cascade-deleted if auth.users is deleted.';



COMMENT ON COLUMN "public"."chefs"."auth_user_id" IS 'Foreign key to Supabase auth.users';



COMMENT ON COLUMN "public"."chefs"."google_review_url" IS 'Chef Google Business review URL - clients are redirected here after leaving internal feedback';



COMMENT ON COLUMN "public"."chefs"."display_name" IS 'Public display name for chef network (defaults to business_name if NULL)';



COMMENT ON COLUMN "public"."chefs"."bio" IS 'Short bio shown in chef network directory';



COMMENT ON COLUMN "public"."chefs"."profile_image_url" IS 'Profile image URL for chef network directory';



COMMENT ON COLUMN "public"."chefs"."slug" IS 'URL-safe slug for public chef profile page (e.g., chef-david → /chef/chef-david). Unique across all chefs.';



COMMENT ON COLUMN "public"."chefs"."tagline" IS 'Short subtitle shown on public profile hero section';



COMMENT ON COLUMN "public"."chefs"."portal_primary_color" IS 'Hex color used for public chef portal primary actions';



COMMENT ON COLUMN "public"."chefs"."portal_background_color" IS 'Hex color used as public chef portal page background';



COMMENT ON COLUMN "public"."chefs"."portal_background_image_url" IS 'Optional background image URL for public chef portal';



COMMENT ON COLUMN "public"."chefs"."website_url" IS 'Chef official website URL shown on profile when enabled.';



COMMENT ON COLUMN "public"."chefs"."show_website_on_public_profile" IS 'When true and website_url is set, display external website link on public chef profile.';



COMMENT ON COLUMN "public"."chefs"."preferred_inquiry_destination" IS 'Lead routing preference: website_only | chefflow_only | both.';



COMMENT ON COLUMN "public"."chefs"."cancellation_cutoff_days" IS 'Days before event where full balance refund applies (default 15). Within this window: no refund.';



COMMENT ON COLUMN "public"."chefs"."deposit_refundable" IS 'Whether deposits are refundable at all. Default false (non-refundable).';



COMMENT ON COLUMN "public"."chefs"."show_availability_signals" IS 'When true, chef''s public target_booking calendar entries appear on their public profile page as "Seeking bookings for these dates".';



COMMENT ON COLUMN "public"."chefs"."account_status" IS 'active = normal access; suspended = portal login blocked by admin.';



COMMENT ON COLUMN "public"."chefs"."current_closure_streak" IS 'Consecutive events financially closed within 48h of completion';



COMMENT ON COLUMN "public"."chefs"."longest_closure_streak" IS 'All-time longest closure streak';



COMMENT ON COLUMN "public"."chefs"."last_closure_date" IS 'Date of most recent event financial close (used for gap detection)';



COMMENT ON COLUMN "public"."chefs"."booking_model" IS 'inquiry_first: client submits request; instant_book: client pays deposit and auto-books';



COMMENT ON COLUMN "public"."chefs"."booking_base_price_cents" IS 'Base event price for instant-book (required when model=instant_book)';



COMMENT ON COLUMN "public"."chefs"."booking_pricing_type" IS 'flat_rate: fixed price regardless of guests; per_person: price multiplied by guest count';



COMMENT ON COLUMN "public"."chefs"."booking_deposit_type" IS 'percent: deposit is % of total; fixed: deposit is a fixed amount in cents';



COMMENT ON COLUMN "public"."chefs"."booking_deposit_fixed_cents" IS 'Fixed deposit amount in cents (used when deposit_type=fixed)';



COMMENT ON COLUMN "public"."chefs"."platform_fee_percent" IS 'Platform commission percentage (e.g. 5.00 = 5%). Applied as application_fee_amount on Stripe destination charges.';



COMMENT ON COLUMN "public"."chefs"."platform_fee_fixed_cents" IS 'Fixed platform fee in cents added on top of percentage fee per transaction. Default 0.';



COMMENT ON COLUMN "public"."chefs"."gratuity_mode" IS 'How gratuity is handled: discretionary | auto_service_fee | included_in_rate | none';



COMMENT ON COLUMN "public"."chefs"."gratuity_service_fee_pct" IS 'Percentage for auto_service_fee mode, e.g. 20.00 for 20%';



COMMENT ON COLUMN "public"."chefs"."gratuity_display_label" IS 'Label shown on proposals/invoices, e.g. "20% service charge"';



COMMENT ON COLUMN "public"."chefs"."remy_blocked_until" IS 'If set and > now(), user is temporarily blocked from using Remy due to repeated policy violations.';



COMMENT ON COLUMN "public"."chefs"."directory_approved" IS 'Admin-controlled flag: only chefs with directory_approved=true appear in the public directory. Founder is always listed.';



COMMENT ON COLUMN "public"."chefs"."deletion_requested_at" IS 'Timestamp when chef requested account deletion. NULL = active account.';



COMMENT ON COLUMN "public"."chefs"."deletion_scheduled_for" IS 'When the final purge will happen (30 days after request). NULL = no pending deletion.';



COMMENT ON COLUMN "public"."chefs"."deletion_reason" IS 'Optional reason the chef chose when requesting deletion.';



COMMENT ON COLUMN "public"."chefs"."deletion_reactivation_token" IS 'One-time UUID token the chef can use to cancel deletion during the 30-day grace period.';



COMMENT ON COLUMN "public"."chefs"."is_deleted" IS 'TRUE after final purge completes. Chef row is kept for anonymized financial records. FALSE = active or pending.';



COMMENT ON COLUMN "public"."chefs"."dismissed_recall_ids" IS 'FDA recall IDs dismissed by this chef — prevents showing dismissed recalls again';



COMMENT ON COLUMN "public"."chefs"."kds_pin" IS 'Optional 4-6 digit PIN for unauthenticated KDS monitor access at /kds/[tenantId]';



CREATE TABLE IF NOT EXISTS "public"."class_registrations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "class_id" "uuid" NOT NULL,
    "attendee_name" "text" NOT NULL,
    "attendee_email" "text" NOT NULL,
    "allergies" "text"[],
    "dietary_restrictions" "text"[],
    "status" "text" DEFAULT 'registered'::"text" NOT NULL,
    "amount_paid_cents" integer DEFAULT 0,
    "payment_status" "text" DEFAULT 'unpaid'::"text",
    "notes" "text",
    "registered_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "class_registrations_status_check" CHECK (("status" = ANY (ARRAY['registered'::"text", 'waitlisted'::"text", 'confirmed'::"text", 'cancelled'::"text", 'no_show'::"text"])))
);




COMMENT ON TABLE "public"."class_registrations" IS 'Registration records for cooking classes with dietary info and payment tracking.';



CREATE TABLE IF NOT EXISTS "public"."client_allergy_records" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "allergen" "text" NOT NULL,
    "severity" "text" DEFAULT 'allergy'::"text" NOT NULL,
    "source" "text" DEFAULT 'chef_entered'::"text" NOT NULL,
    "confirmed_by_chef" boolean DEFAULT false NOT NULL,
    "confirmed_at" timestamp with time zone,
    "notes" "text",
    "detected_in_message_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_allergy_records_severity_check" CHECK (("severity" = ANY (ARRAY['preference'::"text", 'intolerance'::"text", 'allergy'::"text", 'anaphylaxis'::"text"]))),
    CONSTRAINT "client_allergy_records_source_check" CHECK (("source" = ANY (ARRAY['chef_entered'::"text", 'ai_detected'::"text", 'intake_form'::"text", 'client_stated'::"text"])))
);




COMMENT ON TABLE "public"."client_allergy_records" IS 'Structured per-allergen records for clients. Severity-classified, source-tracked, and confirmation-gated. AI-detected records require chef confirmation before they influence planning and document generation.';



COMMENT ON COLUMN "public"."client_allergy_records"."severity" IS 'preference=dislike only; intolerance=GI discomfort; allergy=immune response; anaphylaxis=life-threatening (hard block in documents)';



COMMENT ON COLUMN "public"."client_allergy_records"."confirmed_by_chef" IS 'false = AI suggestion or unreviewed; true = chef explicitly confirmed this record';



CREATE TABLE IF NOT EXISTS "public"."client_connections" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_a_id" "uuid" NOT NULL,
    "client_b_id" "uuid" NOT NULL,
    "relationship_type" "text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chk_no_self_connection" CHECK (("client_a_id" <> "client_b_id"))
);




CREATE OR REPLACE VIEW "public"."client_financial_summary" AS
SELECT
    NULL::"uuid" AS "client_id",
    NULL::"uuid" AS "tenant_id",
    NULL::integer AS "lifetime_value_cents",
    NULL::integer AS "total_events_count",
    NULL::bigint AS "total_events_completed",
    NULL::bigint AS "total_events_cancelled",
    NULL::bigint AS "average_spend_per_event",
    NULL::bigint AS "total_tips_given_cents",
    NULL::numeric AS "average_tip_percentage",
    NULL::bigint AS "outstanding_balance_cents",
    NULL::"date" AS "last_event_date",
    NULL::"date" AS "first_event_date",
    NULL::integer AS "days_since_last_event",
    NULL::boolean AS "is_dormant";




CREATE TABLE IF NOT EXISTS "public"."client_followup_rules" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "trigger_type" "text" NOT NULL,
    "action" "text" NOT NULL,
    "template_text" "text",
    "enabled" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_followup_rules_action_check" CHECK (("action" = ANY (ARRAY['reminder'::"text", 'email_draft'::"text", 'gift_suggestion'::"text"]))),
    CONSTRAINT "client_followup_rules_trigger_type_check" CHECK (("trigger_type" = ANY (ARRAY['post_event'::"text", 'birthday'::"text", 'anniversary'::"text", 'no_booking_30d'::"text", 'no_booking_60d'::"text", 'no_booking_90d'::"text", 'holiday'::"text", 'milestone_event_count'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."client_gift_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "gift_type" "text" NOT NULL,
    "occasion" "text" DEFAULT ''::"text" NOT NULL,
    "description" "text" DEFAULT ''::"text" NOT NULL,
    "cost_cents" integer DEFAULT 0 NOT NULL,
    "sent_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "delivery_method" "text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_gift_log_delivery_method_check" CHECK (("delivery_method" = ANY (ARRAY['hand_delivered'::"text", 'shipped'::"text", 'digital'::"text", 'with_service'::"text"]))),
    CONSTRAINT "client_gift_log_gift_type_check" CHECK (("gift_type" = ANY (ARRAY['thank_you'::"text", 'birthday'::"text", 'holiday'::"text", 'milestone'::"text", 'apology'::"text", 'custom'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."client_incentives" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "type" "public"."incentive_type" NOT NULL,
    "code" "text" NOT NULL,
    "title" "text" NOT NULL,
    "note" "text",
    "currency_code" "text" DEFAULT 'USD'::"text" NOT NULL,
    "amount_cents" integer,
    "discount_percent" integer,
    "expires_at" timestamp with time zone,
    "max_redemptions" integer DEFAULT 1 NOT NULL,
    "redemptions_used" integer DEFAULT 0 NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "target_client_id" "uuid",
    "created_by_user_id" "uuid",
    "created_by_role" "public"."user_role" NOT NULL,
    "created_by_client_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "remaining_balance_cents" integer,
    "purchase_stripe_payment_intent_id" "text",
    "purchase_status" "text" DEFAULT 'issued'::"text" NOT NULL,
    "purchased_by_user_id" "uuid",
    "purchased_by_email" "text",
    CONSTRAINT "chk_client_incentives_code_length" CHECK ((("char_length"("code") >= 4) AND ("char_length"("code") <= 32))),
    CONSTRAINT "chk_client_incentives_creator_role_shape" CHECK (((("created_by_role" = 'chef'::"public"."user_role") AND ("created_by_client_id" IS NULL)) OR (("created_by_role" = 'client'::"public"."user_role") AND ("created_by_client_id" IS NOT NULL)) OR (("created_by_role" = 'system'::"public"."user_role") AND ("created_by_user_id" IS NULL) AND ("created_by_client_id" IS NULL)))),
    CONSTRAINT "chk_client_incentives_redemption_bounds" CHECK ((("max_redemptions" > 0) AND ("redemptions_used" >= 0) AND ("redemptions_used" <= "max_redemptions"))),
    CONSTRAINT "chk_client_incentives_title_not_blank" CHECK (("char_length"(TRIM(BOTH FROM "title")) > 0)),
    CONSTRAINT "chk_client_incentives_value_shape" CHECK (((("type" = 'gift_card'::"public"."incentive_type") AND ("amount_cents" > 0) AND ("discount_percent" IS NULL)) OR (("type" = 'voucher'::"public"."incentive_type") AND ((("amount_cents" > 0) AND ("discount_percent" IS NULL)) OR ((("discount_percent" >= 1) AND ("discount_percent" <= 100)) AND ("amount_cents" IS NULL)))))),
    CONSTRAINT "chk_incentive_purchase_status" CHECK (("purchase_status" = ANY (ARRAY['issued'::"text", 'pending_payment'::"text", 'paid'::"text"])))
);




COMMENT ON TABLE "public"."client_incentives" IS 'Voucher and gift card records. Can be created by chefs and clients within tenant rules.';



COMMENT ON COLUMN "public"."client_incentives"."code" IS 'Human-facing share code for voucher or gift card.';



COMMENT ON COLUMN "public"."client_incentives"."target_client_id" IS 'Optional intended recipient client in the same tenant.';



COMMENT ON COLUMN "public"."client_incentives"."created_by_role" IS 'chef = created by chef in dashboard; client = created by a registered client;
   system = created by webhook or automated process (e.g. Stripe gift card purchase by guest).';



COMMENT ON COLUMN "public"."client_incentives"."remaining_balance_cents" IS 'For gift cards: remaining redeemable value in cents. Decremented on each partial redemption. NULL for vouchers.';



COMMENT ON COLUMN "public"."client_incentives"."purchase_status" IS 'issued = chef created; pending_payment = Stripe session open; paid = purchased by client via Stripe.';



COMMENT ON COLUMN "public"."client_incentives"."purchased_by_user_id" IS 'Auth user who bought this gift card (vs. the recipient).';



COMMENT ON COLUMN "public"."client_incentives"."purchased_by_email" IS 'Email of the buyer (for confirmation emails even if not an auth user).';



