CREATE TABLE IF NOT EXISTS "public"."client_meal_prep_preferences" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "dietary_restrictions" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "allergies" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "dislikes" "text" DEFAULT ''::"text" NOT NULL,
    "spice_tolerance" "text" DEFAULT 'medium'::"text" NOT NULL,
    "favorite_cuisines" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "dietary_protocols" "text" DEFAULT ''::"text" NOT NULL,
    "household_size" integer DEFAULT 1 NOT NULL,
    "adults" integer DEFAULT 1 NOT NULL,
    "children" integer DEFAULT 0 NOT NULL,
    "meals_per_week" integer DEFAULT 5 NOT NULL,
    "preferred_proteins" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "avoid_proteins" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "carb_preference" "text" DEFAULT 'normal'::"text" NOT NULL,
    "portion_size" "text" DEFAULT 'regular'::"text" NOT NULL,
    "delivery_address" "text" DEFAULT ''::"text" NOT NULL,
    "delivery_instructions" "text" DEFAULT ''::"text" NOT NULL,
    "preferred_delivery_day" integer DEFAULT 1 NOT NULL,
    "delivery_window" "text" DEFAULT 'morning'::"text" NOT NULL,
    "container_preference" "text" DEFAULT 'reusable'::"text" NOT NULL,
    "weekly_budget_cents" integer,
    "notes" "text" DEFAULT ''::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_meal_prep_preferences_carb_preference_check" CHECK (("carb_preference" = ANY (ARRAY['normal'::"text", 'low_carb'::"text", 'no_carb'::"text"]))),
    CONSTRAINT "client_meal_prep_preferences_container_preference_check" CHECK (("container_preference" = ANY (ARRAY['reusable'::"text", 'disposable'::"text"]))),
    CONSTRAINT "client_meal_prep_preferences_delivery_window_check" CHECK (("delivery_window" = ANY (ARRAY['morning'::"text", 'afternoon'::"text", 'evening'::"text"]))),
    CONSTRAINT "client_meal_prep_preferences_portion_size_check" CHECK (("portion_size" = ANY (ARRAY['small'::"text", 'regular'::"text", 'large'::"text"]))),
    CONSTRAINT "client_meal_prep_preferences_preferred_delivery_day_check" CHECK ((("preferred_delivery_day" >= 0) AND ("preferred_delivery_day" <= 6))),
    CONSTRAINT "client_meal_prep_preferences_spice_tolerance_check" CHECK (("spice_tolerance" = ANY (ARRAY['none'::"text", 'mild'::"text", 'medium'::"text", 'hot'::"text"])))
);




