);




CREATE TABLE IF NOT EXISTS "public"."client_preferences" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "client_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "dashboard_widgets" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "item_type" "public"."client_preference_item_type",
    "item_name" "text",
    "item_id" "uuid",
    "rating" "public"."client_preference_rating" DEFAULT 'neutral'::"public"."client_preference_rating",
    "notes" "text",
    "event_id" "uuid",
    "observed_at" timestamp with time zone DEFAULT "now"()
);




CREATE TABLE IF NOT EXISTS "public"."client_quick_requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "requested_date" "date" NOT NULL,
    "requested_time" "text",
    "guest_count" integer DEFAULT 2 NOT NULL,
    "notes" "text",
    "preferred_menu_id" "uuid",
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "decline_reason" "text",
    "converted_event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_quick_requests_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'confirmed'::"text", 'declined'::"text", 'converted'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."client_referrals" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "referrer_client_id" "uuid" NOT NULL,
    "referred_client_id" "uuid",
    "inquiry_id" "uuid",
    "converted_event_id" "uuid",
    "referral_code" "text" NOT NULL,
    "reward_points_awarded" integer DEFAULT 0 NOT NULL,
    "reward_awarded_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "revenue_generated_cents" integer DEFAULT 0 NOT NULL,
    "notes" "text",
    "referral_source" "text",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_referrals_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'contacted'::"text", 'booked'::"text", 'completed'::"text"])))
);




COMMENT ON TABLE "public"."client_referrals" IS 'Tracks client-to-client referrals created from QR/share links.';



CREATE TABLE IF NOT EXISTS "public"."client_reviews" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "rating" integer NOT NULL,
    "feedback_text" "text",
    "what_they_loved" "text",
    "what_could_improve" "text",
    "display_consent" boolean DEFAULT false NOT NULL,
    "google_review_clicked" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "food_quality_rating" integer,
    "presentation_rating" integer,
    "communication_rating" integer,
    "punctuality_rating" integer,
    "cleanup_rating" integer,
    "would_book_again" boolean,
    "chef_response" "text",
    "responded_at" timestamp with time zone,
    CONSTRAINT "client_reviews_cleanup_rating_check" CHECK ((("cleanup_rating" >= 1) AND ("cleanup_rating" <= 5))),
    CONSTRAINT "client_reviews_communication_rating_check" CHECK ((("communication_rating" >= 1) AND ("communication_rating" <= 5))),
    CONSTRAINT "client_reviews_food_quality_rating_check" CHECK ((("food_quality_rating" >= 1) AND ("food_quality_rating" <= 5))),
    CONSTRAINT "client_reviews_presentation_rating_check" CHECK ((("presentation_rating" >= 1) AND ("presentation_rating" <= 5))),
    CONSTRAINT "client_reviews_punctuality_rating_check" CHECK ((("punctuality_rating" >= 1) AND ("punctuality_rating" <= 5))),
    CONSTRAINT "client_reviews_rating_check" CHECK ((("rating" >= 1) AND ("rating" <= 5)))
);




COMMENT ON TABLE "public"."client_reviews" IS 'Post-event client feedback - internal survey with optional public display consent';



COMMENT ON COLUMN "public"."client_reviews"."food_quality_rating" IS 'Client rating for food quality on a 1-5 scale.';



COMMENT ON COLUMN "public"."client_reviews"."presentation_rating" IS 'Client rating for food presentation on a 1-5 scale.';



COMMENT ON COLUMN "public"."client_reviews"."communication_rating" IS 'Client rating for communication on a 1-5 scale.';



COMMENT ON COLUMN "public"."client_reviews"."punctuality_rating" IS 'Client rating for punctuality on a 1-5 scale.';



COMMENT ON COLUMN "public"."client_reviews"."cleanup_rating" IS 'Client rating for cleanup on a 1-5 scale.';



COMMENT ON COLUMN "public"."client_reviews"."would_book_again" IS 'Whether the client said they would book this chef again.';



COMMENT ON COLUMN "public"."client_reviews"."chef_response" IS 'The chef''s written response to this client review.';



COMMENT ON COLUMN "public"."client_reviews"."responded_at" IS 'When the chef responded to this review.';



CREATE TABLE IF NOT EXISTS "public"."client_satisfaction_surveys" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "event_id" "uuid" NOT NULL,
    "client_id" "uuid",
    "token" "text" DEFAULT ("gen_random_uuid"())::"text" NOT NULL,
    "sent_at" timestamp with time zone,
    "responded_at" timestamp with time zone,
    "reminder_sent_at" timestamp with time zone,
    "nps_score" smallint,
    "overall_rating" smallint,
    "food_quality_rating" smallint,
    "service_rating" smallint,
    "value_rating" smallint,
    "presentation_rating" smallint,
    "would_rebook" boolean,
    "highlight_text" "text",
    "improvement_text" "text",
    "testimonial_text" "text",
    "consent_to_display" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_satisfaction_surveys_food_quality_rating_check" CHECK ((("food_quality_rating" >= 1) AND ("food_quality_rating" <= 5))),
    CONSTRAINT "client_satisfaction_surveys_nps_score_check" CHECK ((("nps_score" >= 0) AND ("nps_score" <= 10))),
    CONSTRAINT "client_satisfaction_surveys_overall_rating_check" CHECK ((("overall_rating" >= 1) AND ("overall_rating" <= 5))),
    CONSTRAINT "client_satisfaction_surveys_presentation_rating_check" CHECK ((("presentation_rating" >= 1) AND ("presentation_rating" <= 5))),
    CONSTRAINT "client_satisfaction_surveys_service_rating_check" CHECK ((("service_rating" >= 1) AND ("service_rating" <= 5))),
    CONSTRAINT "client_satisfaction_surveys_value_rating_check" CHECK ((("value_rating" >= 1) AND ("value_rating" <= 5)))
);




COMMENT ON TABLE "public"."client_satisfaction_surveys" IS 'Post-event satisfaction surveys sent to clients. Captures NPS, multi-dimension ratings, and open feedback. Token-authenticated so no client login required.';



COMMENT ON COLUMN "public"."client_satisfaction_surveys"."token" IS 'Unique hex token for the survey link. Allows clients to respond without logging in.';



COMMENT ON COLUMN "public"."client_satisfaction_surveys"."nps_score" IS '0–10 Net Promoter Score. 0–6 = detractor, 7–8 = passive, 9–10 = promoter.';



CREATE TABLE IF NOT EXISTS "public"."client_segments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "filters" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "color" "text" DEFAULT '#6366f1'::"text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"()
);




CREATE TABLE IF NOT EXISTS "public"."client_tags" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "client_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "tag" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "client_tags_tag_check" CHECK ((("char_length"("tag") >= 1) AND ("char_length"("tag") <= 50)))
);




CREATE TABLE IF NOT EXISTS "public"."clients" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "auth_user_id" "uuid",
    "tenant_id" "uuid",
    "full_name" "text" NOT NULL,
    "email" "text" NOT NULL,
    "phone" "text",
    "preferred_contact_method" "public"."contact_method",
    "referral_source" "public"."referral_source",
    "referral_source_detail" "text",
    "partner_name" "text",
    "children" "text"[],
    "regular_guests" "jsonb" DEFAULT '[]'::"jsonb",
    "dietary_restrictions" "text"[],
    "allergies" "text"[],
    "dislikes" "text"[],
    "spice_tolerance" "public"."spice_tolerance",
    "favorite_cuisines" "text"[],
    "favorite_dishes" "text"[],
    "wine_beverage_preferences" "text",
    "address" "text",
    "parking_instructions" "text",
    "access_instructions" "text",
    "kitchen_size" "text",
    "kitchen_constraints" "text",
    "house_rules" "text",
    "equipment_available" "text"[],
    "equipment_must_bring" "text"[],
    "vibe_notes" "text",
    "payment_behavior" "text",
    "tipping_pattern" "text",
    "farewell_style" "text",
    "what_they_care_about" "text",
    "personal_milestones" "jsonb" DEFAULT '[]'::"jsonb",
    "lifetime_value_cents" integer DEFAULT 0,
    "total_events_count" integer DEFAULT 0,
    "average_spend_cents" integer DEFAULT 0,
    "loyalty_points" integer DEFAULT 0,
    "status" "public"."client_status" DEFAULT 'active'::"public"."client_status" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "total_payments_received_cents" integer DEFAULT 0,
    "first_event_date" "date",
    "last_event_date" "date",
    "total_guests_served" integer DEFAULT 0,
    "total_events_completed" integer DEFAULT 0,
    "loyalty_tier" "public"."loyalty_tier" DEFAULT 'bronze'::"public"."loyalty_tier" NOT NULL,
    "preferred_name" "text",
    "partner_preferred_name" "text",
    "additional_addresses" "jsonb" DEFAULT '[]'::"jsonb",
    "family_notes" "text",
    "automated_emails_enabled" boolean DEFAULT true NOT NULL,
    "fun_qa_answers" "jsonb" DEFAULT '{}'::"jsonb",
    "marketing_unsubscribed" boolean DEFAULT false NOT NULL,
    "marketing_unsubscribed_at" timestamp with time zone,
    "availability_signal_notifications" boolean DEFAULT true NOT NULL,
    "has_received_welcome_points" boolean DEFAULT false NOT NULL,
    "is_demo" boolean DEFAULT false NOT NULL,
    "portal_access_token" "text",
    "portal_token_created_at" timestamp with time zone,
    "kitchen_oven_notes" "text",
    "kitchen_burner_notes" "text",
    "kitchen_counter_notes" "text",
    "kitchen_refrigeration_notes" "text",
    "kitchen_plating_notes" "text",
    "kitchen_sink_notes" "text",
    "kitchen_profile_updated_at" timestamp with time zone,
    "dietary_protocols" "text"[] DEFAULT '{}'::"text"[],
    "nda_active" boolean DEFAULT false,
    "nda_coverage" "text",
    "nda_effective_date" "date",
    "nda_expiry_date" "date",
    "nda_document_url" "text",
    "photo_permission" "text" DEFAULT 'none'::"text",
    "stripe_customer_id" "text",
    "instagram_handle" "text",
    "social_media_links" "jsonb" DEFAULT '[]'::"jsonb",
    "occupation" "text",
    "company_name" "text",
    "birthday" "date",
    "anniversary" "date",
    "pets" "jsonb" DEFAULT '[]'::"jsonb",
    "gate_code" "text",
    "wifi_password" "text",
    "security_notes" "text",
    "preferred_service_style" "text",
    "typical_guest_count" "text",
    "preferred_event_days" "text"[] DEFAULT '{}'::"text"[],
    "budget_range_min_cents" integer,
    "budget_range_max_cents" integer,
    "cleanup_expectations" "text",
    "leftovers_preference" "text",
    "has_dishwasher" boolean,
    "outdoor_cooking_notes" "text",
    "nearest_grocery_store" "text",
    "water_quality_notes" "text",
    "available_place_settings" integer,
    "formality_level" "text",
    "communication_style_notes" "text",
    "complaint_handling_notes" "text",
    "wow_factors" "text",
    "referral_potential" "text",
    "red_flags" "text",
    "acquisition_cost_cents" integer,
    "deleted_at" timestamp with time zone,
    "deleted_by" "uuid",
    "recurring_pricing_model" "text",
    "recurring_price_cents" integer,
    "recurring_pricing_notes" "text",
    "referral_code" "text",
    "account_deletion_requested_at" timestamp with time zone,
    "account_deletion_scheduled_for" timestamp with time zone,
    "account_deletion_cancelled_at" timestamp with time zone,
    "deletion_reason" "text",
    "important_dates" "jsonb" DEFAULT '[]'::"jsonb",
    CONSTRAINT "clients_formality_level_check" CHECK ((("formality_level" IS NULL) OR ("formality_level" = ANY (ARRAY['casual'::"text", 'semi_formal'::"text", 'formal'::"text"])))),
    CONSTRAINT "clients_photo_permission_check" CHECK (("photo_permission" = ANY (ARRAY['none'::"text", 'portfolio_only'::"text", 'public_with_approval'::"text", 'public_freely'::"text"]))),
    CONSTRAINT "clients_recurring_price_cents_check" CHECK ((("recurring_price_cents" IS NULL) OR ("recurring_price_cents" >= 0))),
    CONSTRAINT "clients_recurring_pricing_model_check" CHECK ((("recurring_pricing_model" IS NULL) OR ("recurring_pricing_model" = ANY (ARRAY['none'::"text", 'flat_rate'::"text", 'per_person'::"text"])))),
    CONSTRAINT "clients_referral_potential_check" CHECK ((("referral_potential" IS NULL) OR ("referral_potential" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text"]))))
);




COMMENT ON TABLE "public"."clients" IS 'Complete client relationship records - identity, household, preferences, site notes, relationship intelligence (Part 10). IMPORTANT: Client records are NEVER hard-deleted. To remove a client, set status to "dormant". Deletion is only via CASCADE if auth.users or chefs is deleted.';



COMMENT ON COLUMN "public"."clients"."auth_user_id" IS 'Nullable - client can exist before they have an account';



COMMENT ON COLUMN "public"."clients"."tenant_id" IS 'Optional at signup. NULL means standalone client account not yet attached to a chef tenant.';



COMMENT ON COLUMN "public"."clients"."regular_guests" IS 'Array of objects: [{name: "Evan", relationship: "friend", notes: "picky eater"}]';



COMMENT ON COLUMN "public"."clients"."allergies" IS 'CRITICAL - prominently displayed, e.g., ["nuts", "shellfish"]';



COMMENT ON COLUMN "public"."clients"."personal_milestones" IS 'Array of objects: [{type: "birthday", date: "1985-06-15", description: ""}]';



COMMENT ON COLUMN "public"."clients"."lifetime_value_cents" IS 'Total revenue from this client (computed from events/payments)';



COMMENT ON COLUMN "public"."clients"."total_events_count" IS 'Number of events cooked for this client (computed)';



COMMENT ON COLUMN "public"."clients"."average_spend_cents" IS 'Average spend per event (computed)';



COMMENT ON COLUMN "public"."clients"."automated_emails_enabled" IS 'When false, this client is excluded from all automated system emails (e.g. day-before reminders). Chef-controlled only.';



COMMENT ON COLUMN "public"."clients"."fun_qa_answers" IS 'Optional fun Q&A answers submitted by the client. Keyed by stable question identifiers. Used by the chef to personalise communication and encourage rebookings.';



COMMENT ON COLUMN "public"."clients"."marketing_unsubscribed" IS 'Client has opted out of marketing emails from this chef. Still receives transactional emails (quotes, contracts, etc.)';



COMMENT ON COLUMN "public"."clients"."availability_signal_notifications" IS 'When true, client receives a notification when their chef posts a new public availability signal (target booking date). Client can opt-out.';



COMMENT ON COLUMN "public"."clients"."has_received_welcome_points" IS 'Prevents double-awarding welcome points. Set to true after first welcome bonus.';



COMMENT ON COLUMN "public"."clients"."portal_access_token" IS 'Opaque token used for magic-link client portal access. Generated by the chef and shared with the client.';



COMMENT ON COLUMN "public"."clients"."portal_token_created_at" IS 'Timestamp when the portal token was last generated/rotated.';



COMMENT ON COLUMN "public"."clients"."kitchen_oven_notes" IS 'Oven reliability, quirks, temperature accuracy';



COMMENT ON COLUMN "public"."clients"."kitchen_burner_notes" IS 'Number of working burners, gas vs induction, BTU notes';



COMMENT ON COLUMN "public"."clients"."kitchen_counter_notes" IS 'Counter space availability, prep surface quality';



COMMENT ON COLUMN "public"."clients"."kitchen_refrigeration_notes" IS 'Fridge/freezer space, cooler availability';



COMMENT ON COLUMN "public"."clients"."kitchen_plating_notes" IS 'Surfaces available for plating and staging dishes';



COMMENT ON COLUMN "public"."clients"."kitchen_sink_notes" IS 'Sink access, hot water reliability, drainage notes';



COMMENT ON COLUMN "public"."clients"."kitchen_profile_updated_at" IS 'When kitchen notes were last updated — helps chef know if notes are stale';



COMMENT ON COLUMN "public"."clients"."stripe_customer_id" IS 'Stripe Customer ID for retainer billing. Created on-demand when a retainer subscription is set up.';



COMMENT ON COLUMN "public"."clients"."instagram_handle" IS 'Public Instagram handle for tagging/DMing';



COMMENT ON COLUMN "public"."clients"."social_media_links" IS 'Array of {platform, url} objects';



COMMENT ON COLUMN "public"."clients"."birthday" IS 'Top-level DATE for birthday reminders (queryable)';



COMMENT ON COLUMN "public"."clients"."anniversary" IS 'Top-level DATE for anniversary reminders (queryable)';



COMMENT ON COLUMN "public"."clients"."pets" IS 'Array of {name, type, notes} — important for in-home cooking safety';



COMMENT ON COLUMN "public"."clients"."gate_code" IS 'Chef-only internal field. NEVER expose to client portal.';



COMMENT ON COLUMN "public"."clients"."wifi_password" IS 'Chef-only internal field. NEVER expose to client portal.';



COMMENT ON COLUMN "public"."clients"."security_notes" IS 'Chef-only internal field. Alarm system, doorman, etc.';



COMMENT ON COLUMN "public"."clients"."preferred_service_style" IS 'Free text: plated, family-style, buffet, tasting, etc.';



COMMENT ON COLUMN "public"."clients"."typical_guest_count" IS 'Free text: "4-6", "8-12", "20+"';



COMMENT ON COLUMN "public"."clients"."cleanup_expectations" IS 'Full kitchen reset, cooking mess only, etc.';



COMMENT ON COLUMN "public"."clients"."leftovers_preference" IS 'Package up, compost, donate, etc.';



COMMENT ON COLUMN "public"."clients"."outdoor_cooking_notes" IS 'Grill, smoker, pizza oven, fire pit, etc.';



COMMENT ON COLUMN "public"."clients"."nearest_grocery_store" IS 'Name and distance — for last-minute runs';



COMMENT ON COLUMN "public"."clients"."water_quality_notes" IS 'Well, city, filtered, etc.';



COMMENT ON COLUMN "public"."clients"."formality_level" IS 'Chef-only. Casual, semi-formal, or formal.';



COMMENT ON COLUMN "public"."clients"."communication_style_notes" IS 'Chef-only. How they prefer to communicate.';



COMMENT ON COLUMN "public"."clients"."complaint_handling_notes" IS 'Chef-only. How they handle issues. NEVER expose to client portal.';



COMMENT ON COLUMN "public"."clients"."wow_factors" IS 'Chef-only. What impresses them. "Loves tableside flambe"';



COMMENT ON COLUMN "public"."clients"."referral_potential" IS 'Chef-only internal field. NEVER expose to client portal.';



COMMENT ON COLUMN "public"."clients"."red_flags" IS 'Chef-only internal field. NEVER expose to client portal.';



COMMENT ON COLUMN "public"."clients"."acquisition_cost_cents" IS 'Chef-only. Cost to acquire this client (marketing spend).';



COMMENT ON COLUMN "public"."clients"."recurring_pricing_model" IS 'Optional recurring pricing strategy for repeat clients: none, flat_rate, or per_person.';



COMMENT ON COLUMN "public"."clients"."recurring_price_cents" IS 'Default recurring price in cents. Flat total or per-person based on recurring_pricing_model.';



COMMENT ON COLUMN "public"."clients"."recurring_pricing_notes" IS 'Optional chef notes about recurring pricing terms (e.g., groceries billed separately).';



COMMENT ON COLUMN "public"."clients"."account_deletion_requested_at" IS 'When the client requested account deletion from the client portal.';



COMMENT ON COLUMN "public"."clients"."account_deletion_scheduled_for" IS 'When the client account should be purged after the 30-day grace period.';



COMMENT ON COLUMN "public"."clients"."account_deletion_cancelled_at" IS 'When a pending client account deletion request was cancelled.';



COMMENT ON COLUMN "public"."clients"."deletion_reason" IS 'Optional reason supplied by the client when requesting account deletion.';



COMMENT ON COLUMN "public"."clients"."important_dates" IS 'Array of {label, date} objects for custom reminders (kids birthdays, wedding anniversary, etc.)';



CREATE TABLE IF NOT EXISTS "public"."clipboard_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "station_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "component_id" "uuid" NOT NULL,
    "entry_date" "date" NOT NULL,
    "on_hand" numeric(10,2) DEFAULT 0,
    "made" numeric(10,2) DEFAULT 0,
    "made_at" timestamp with time zone,
    "need_to_make" numeric(10,2) DEFAULT 0,
    "need_to_order" numeric(10,2) DEFAULT 0,
    "waste_qty" numeric(10,2) DEFAULT 0,
    "waste_reason_code" "public"."waste_reason",
    "location" "text",
    "is_86d" boolean DEFAULT false NOT NULL,
    "eighty_sixed_at" timestamp with time zone,
    "notes" "text",
    "updated_by" "uuid",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "clipboard_entries_location_check" CHECK ((("location" IS NULL) OR ("location" = ANY (ARRAY['line'::"text", 'backup'::"text"]))))
);




COMMENT ON TABLE "public"."clipboard_entries" IS 'Daily station clipboard: par, on-hand, made, need-to-make, need-to-order, waste, 86 status. One row per component per station per day.';



