COMMENT ON TABLE "public"."commerce_dining_tables" IS 'Physical tables used for dine-in service and open checks.';



CREATE TABLE IF NOT EXISTS "public"."commerce_dining_zones" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
