);




CREATE OR REPLACE VIEW "public"."communication_inbox_items" AS
 WITH "latest_event" AS (
         SELECT DISTINCT ON ("ce"."thread_id") "ce"."id" AS "communication_event_id",
            "ce"."tenant_id",
            "ce"."thread_id",
            "ce"."timestamp",
            "ce"."sender_identity",
            "ce"."source",
            "ce"."direction",
            "ce"."raw_content",
            "ce"."normalized_content",
            "ce"."status" AS "communication_status",
            "ce"."linked_entity_type",
            "ce"."linked_entity_id",
            "ce"."resolved_client_id"
           FROM "public"."communication_events" "ce"
          ORDER BY "ce"."thread_id", "ce"."timestamp" DESC, "ce"."created_at" DESC
        ), "overdue_timer" AS (
         SELECT "fut"."thread_id",
            "min"("fut"."due_at") AS "next_due_at",
            "bool_or"((("fut"."status" = 'active'::"public"."follow_up_timer_status") AND ("fut"."due_at" <= "now"()))) AS "has_overdue"
           FROM "public"."follow_up_timers" "fut"
          GROUP BY "fut"."thread_id"
        ), "pending_links" AS (
         SELECT "sl"."communication_event_id",
            "count"(*) FILTER (WHERE ("sl"."status" = 'pending'::"public"."suggested_link_status")) AS "pending_link_count",
            "max"("sl"."confidence_score") FILTER (WHERE ("sl"."status" = 'pending'::"public"."suggested_link_status")) AS "top_pending_confidence"
           FROM "public"."suggested_links" "sl"
          GROUP BY "sl"."communication_event_id"
        )
 SELECT "ct"."id" AS "thread_id",
    "ct"."tenant_id",
    "ct"."client_id",
    "ct"."last_activity_at",
    "ct"."state" AS "thread_state",
    "ct"."snoozed_until",
    "le"."communication_event_id",
    "le"."timestamp" AS "event_timestamp",
    "le"."sender_identity",
    "le"."source",
    "le"."direction",
    "le"."raw_content",
    "le"."normalized_content",
    "le"."communication_status",
    "le"."linked_entity_type",
    "le"."linked_entity_id",
    "le"."resolved_client_id",
    COALESCE("ot"."next_due_at", NULL::timestamp with time zone) AS "next_follow_up_due_at",
    COALESCE("ot"."has_overdue", false) AS "has_overdue_follow_up",
    COALESCE("pl"."pending_link_count", (0)::bigint) AS "pending_link_count",
    COALESCE("pl"."top_pending_confidence", (0)::numeric) AS "top_pending_confidence",
        CASE
            WHEN (("ct"."state" = 'snoozed'::"public"."conversation_thread_state") AND (("ct"."snoozed_until" IS NULL) OR ("ct"."snoozed_until" > "now"()))) THEN 'snoozed'::"text"
            WHEN (("le"."communication_status" = 'resolved'::"public"."communication_event_status") OR ("ct"."state" = 'closed'::"public"."conversation_thread_state")) THEN 'resolved'::"text"
            WHEN ("le"."communication_status" = 'unlinked'::"public"."communication_event_status") THEN 'unlinked'::"text"
            ELSE 'needs_attention'::"text"
        END AS "tab",
    (((COALESCE("ot"."has_overdue", false) = true) AND ("ct"."state" = 'active'::"public"."conversation_thread_state")) OR (("le"."communication_status" = 'unlinked'::"public"."communication_event_status") AND ("ct"."state" = 'active'::"public"."conversation_thread_state")) OR ((COALESCE("pl"."pending_link_count", (0)::bigint) > 0) AND ("ct"."state" = 'active'::"public"."conversation_thread_state"))) AS "needs_attention",
    "ct"."is_starred"
   FROM ((("public"."conversation_threads" "ct"
     JOIN "latest_event" "le" ON (("le"."thread_id" = "ct"."id")))
     LEFT JOIN "overdue_timer" "ot" ON (("ot"."thread_id" = "ct"."id")))
     LEFT JOIN "pending_links" "pl" ON (("pl"."communication_event_id" = "le"."communication_event_id")));




