    "sort_order" integer DEFAULT 0 NOT NULL,
    "is_make_ahead" boolean DEFAULT false NOT NULL,
    "make_ahead_window_hours" integer,
    "storage_notes" "text",
    "execution_notes" "text",
    "scale_factor" numeric(5,2) DEFAULT 1.0 NOT NULL,
    "created_by" "uuid",
    "updated_by" "uuid",
    "transport_category" "text" DEFAULT 'room_temp'::"text",
    "portion_quantity" numeric(8,3),
    "portion_unit" "text",
    "prep_day_offset" integer DEFAULT 0,
    "prep_time_of_day" "text",
    "prep_station" "text",
    CONSTRAINT "components_portion_quantity_positive" CHECK ((("portion_quantity" IS NULL) OR ("portion_quantity" > (0)::numeric))),
    CONSTRAINT "components_prep_day_offset_valid" CHECK ((("prep_day_offset" IS NULL) OR ("prep_day_offset" <= 0))),
    CONSTRAINT "components_prep_time_of_day_valid" CHECK ((("prep_time_of_day" IS NULL) OR ("prep_time_of_day" = ANY (ARRAY['early_morning'::"text", 'morning'::"text", 'afternoon'::"text", 'evening'::"text", 'service'::"text"])))),
