);




COMMENT ON COLUMN "public"."components"."transport_category" IS 'Packing transport zone for make-ahead components. cold = cooler/perishable, frozen = cooler/pack-last, room_temp = dry goods bag, fragile = own padded container, liquid = lidded upright in cooler. Only relevant for is_make_ahead = true components.';



COMMENT ON COLUMN "public"."components"."portion_quantity" IS 'Amount of this component per plate/guest. E.g. 120 (grams) or 4 (oz).';



COMMENT ON COLUMN "public"."components"."portion_unit" IS 'Unit for portion_quantity. E.g. "g", "oz", "ml", "pieces". Free text.';



COMMENT ON COLUMN "public"."components"."prep_day_offset" IS 'Days before service when this component should be prepped. 0 = day-of service. -1 = one day before. -3 = three days before.';



COMMENT ON COLUMN "public"."components"."prep_time_of_day" IS 'When during the prep day: early_morning (6-9am), morning (9am-12pm), afternoon (12-4pm), evening (4-8pm), service (during service/à la minute).';



COMMENT ON COLUMN "public"."components"."prep_station" IS 'Kitchen station assignment. Free text: e.g. "sauté", "grill", "pastry", "cold", "prep".';



