    "client_id" "uuid",
    "program_id" "uuid",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "container_transactions_quantity_check" CHECK (("quantity" > 0)),
    CONSTRAINT "container_transactions_transaction_type_check" CHECK (("transaction_type" = ANY (ARRAY['purchase'::"text", 'deploy'::"text", 'return'::"text", 'retire'::"text", 'lost'::"text"])))
);




