    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."contract_templates" IS 'Chef-owned reusable contract templates. Body uses Markdown with {{merge_field}} placeholders.';



COMMENT ON COLUMN "public"."contract_templates"."is_default" IS 'If true, this template is pre-selected when generating a contract.';



COMMENT ON COLUMN "public"."contract_templates"."version" IS 'Incremented on each edit so event_contracts can reference the version used.';



CREATE TABLE IF NOT EXISTS "public"."contractor_payments" (
