    CONSTRAINT "contractor_payments_payment_method_check" CHECK (("payment_method" = ANY (ARRAY['check'::"text", 'venmo'::"text", 'zelle'::"text", 'cash'::"text", 'direct_deposit'::"text", 'other'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."contractor_service_agreements" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
