    CONSTRAINT "contractor_service_agreements_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'expired'::"text", 'not_on_file'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."conversation_participants" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
