CREATE TABLE IF NOT EXISTS "public"."conversation_thread_reads" (
    "tenant_id" "uuid" NOT NULL,
    "thread_id" "uuid" NOT NULL,
    "last_read_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."conversations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "context_type" "public"."conversation_context_type" DEFAULT 'standalone'::"public"."conversation_context_type" NOT NULL,
    "inquiry_id" "uuid",
    "event_id" "uuid",
    "last_message_at" timestamp with time zone,
    "last_message_preview" "text",
    "last_message_sender_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "valid_context" CHECK (((("context_type" = 'standalone'::"public"."conversation_context_type") AND ("inquiry_id" IS NULL) AND ("event_id" IS NULL)) OR (("context_type" = 'inquiry'::"public"."conversation_context_type") AND ("inquiry_id" IS NOT NULL)) OR (("context_type" = 'event'::"public"."conversation_context_type") AND ("event_id" IS NOT NULL))))
);




COMMENT ON TABLE "public"."conversations" IS 'Groups messages between participants. Optionally linked to an inquiry or event.';



CREATE TABLE IF NOT EXISTS "public"."cooking_classes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "description" "text",
    "class_date" timestamp with time zone NOT NULL,
