    "max_capacity" integer DEFAULT 10,
    "price_per_person_cents" integer NOT NULL,
    "location" "text",
    "menu_id" "uuid",
    "skill_level" "text",
    "cuisine_type" "text",
    "what_to_bring" "text"[],
    "what_included" "text"[],
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "registration_deadline" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    CONSTRAINT "cooking_classes_skill_level_check" CHECK (("skill_level" = ANY (ARRAY['beginner'::"text", 'intermediate'::"text", 'advanced'::"text", 'all_levels'::"text"]))),
    CONSTRAINT "cooking_classes_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'published'::"text", 'full'::"text", 'completed'::"text", 'cancelled'::"text"])))
);




COMMENT ON TABLE "public"."cooking_classes" IS 'Cooking classes offered by a chef, with capacity and registration tracking.';



CREATE TABLE IF NOT EXISTS "public"."copilot_actions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "run_id" "uuid",
    "recommendation_id" "uuid",
    "action_key" "text" NOT NULL,
    "action_mode" "text" NOT NULL,
    "status" "text" DEFAULT 'success'::"text" NOT NULL,
    "actor_auth_user_id" "uuid",
    "idempotency_key" "text",
    "request_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "result_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "error" "text",
    "executed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "copilot_actions_action_mode_check" CHECK (("action_mode" = ANY (ARRAY['suggested'::"text", 'manual_execute'::"text", 'auto_execute'::"text"]))),
    CONSTRAINT "copilot_actions_status_check" CHECK (("status" = ANY (ARRAY['success'::"text", 'failed'::"text", 'skipped'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."copilot_recommendations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "run_id" "uuid" NOT NULL,
    "recommendation_type" "text" NOT NULL,
    "title" "text" NOT NULL,
    "body" "text",
    "severity" "text" DEFAULT 'normal'::"text" NOT NULL,
    "confidence" numeric(5,4),
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "resolved_at" timestamp with time zone,
    CONSTRAINT "copilot_recommendations_confidence_check" CHECK ((("confidence" IS NULL) OR (("confidence" >= (0)::numeric) AND ("confidence" <= (1)::numeric)))),
    CONSTRAINT "copilot_recommendations_severity_check" CHECK (("severity" = ANY (ARRAY['critical'::"text", 'high'::"text", 'normal'::"text", 'low'::"text"]))),
    CONSTRAINT "copilot_recommendations_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'dismissed'::"text", 'executed'::"text", 'failed'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."copilot_run_errors" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "run_id" "uuid" NOT NULL,
    "error_scope" "text" NOT NULL,
    "error_message" "text" NOT NULL,
    "error_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."copilot_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "run_source" "text" DEFAULT 'scheduled'::"text" NOT NULL,
    "status" "text" DEFAULT 'success'::"text" NOT NULL,
    "autonomy_level" integer DEFAULT 0 NOT NULL,
    "plan_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "summary" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "completed_at" timestamp with time zone,
    "duration_ms" integer,
    CONSTRAINT "copilot_runs_autonomy_level_check" CHECK (("autonomy_level" = ANY (ARRAY[0, 1, 2]))),
    CONSTRAINT "copilot_runs_run_source_check" CHECK (("run_source" = ANY (ARRAY['scheduled'::"text", 'manual'::"text"]))),
    CONSTRAINT "copilot_runs_status_check" CHECK (("status" = ANY (ARRAY['success'::"text", 'partial'::"text", 'failed'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."cron_executions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "cron_name" "text" NOT NULL,
    "executed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "text" DEFAULT 'success'::"text" NOT NULL,
    "duration_ms" integer,
    "result" "jsonb",
    "error_text" "text",
    CONSTRAINT "cron_executions_status_check" CHECK (("status" = ANY (ARRAY['success'::"text", 'error'::"text"])))
);




COMMENT ON TABLE "public"."cron_executions" IS 'Heartbeat log for all scheduled cron jobs. Each successful cron run inserts one row. Read by /api/scheduled/monitor to detect stale or failing jobs.';



COMMENT ON COLUMN "public"."cron_executions"."cron_name" IS 'Identifier matching the cron path in vercel.json, e.g. ''lifecycle'', ''follow-ups'', ''loyalty-expiry''.';



COMMENT ON COLUMN "public"."cron_executions"."duration_ms" IS 'Optional: elapsed milliseconds from start to heartbeat call. Useful for detecting slow crons approaching Vercel''s 25s limit.';



