);




COMMENT ON TABLE "public"."device_events" IS 'Audit log for kiosk device actions: paired, heartbeat, reset, submitted_inquiry, etc.';



COMMENT ON COLUMN "public"."device_events"."type" IS 'Event type: paired, heartbeat, reset, hard_reset, submitted_inquiry, disabled, revoked, pin_verified, pin_failed, session_ended';



CREATE TABLE IF NOT EXISTS "public"."device_sessions" (
