    "ip" "text",
    CONSTRAINT "device_sessions_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'ended'::"text"])))
);




COMMENT ON TABLE "public"."device_sessions" IS 'Tracks individual staff sessions on kiosk devices.';



CREATE TABLE IF NOT EXISTS "public"."devices" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "location_name" "text",
    "device_type" "public"."device_type" DEFAULT 'browser'::"public"."device_type" NOT NULL,
    "status" "public"."device_status" DEFAULT 'pending_pair'::"public"."device_status" NOT NULL,
    "mode" "public"."device_mode" DEFAULT 'kiosk'::"public"."device_mode" NOT NULL,
    "kiosk_flow" "public"."kiosk_flow" DEFAULT 'inquiry'::"public"."kiosk_flow" NOT NULL,
    "pairing_code_hash" "text",
    "pairing_expires_at" timestamp with time zone,
    "token_hash" "text",
    "claimed_at" timestamp with time zone,
    "last_seen_at" timestamp with time zone,
    "last_ip" "text",
    "app_version" "text",
    "idle_timeout_seconds" integer DEFAULT 90 NOT NULL,
    "require_staff_pin" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "devices_idle_timeout_seconds_check" CHECK (("idle_timeout_seconds" >= 10))
);




COMMENT ON TABLE "public"."devices" IS 'Fleet registry of kiosk devices owned by a tenant.';



COMMENT ON COLUMN "public"."devices"."pairing_code_hash" IS 'SHA-256 hash of the short pairing code. Expires after pairing_expires_at.';



COMMENT ON COLUMN "public"."devices"."token_hash" IS 'SHA-256 hash of the device API token. Raw token shown once during pairing.';



COMMENT ON COLUMN "public"."devices"."require_staff_pin" IS 'When true, staff must enter a PIN before using the kiosk.';



