CREATE OR REPLACE VIEW "public"."dish_component_summary" AS
 SELECT "id" AS "dish_id",
    "tenant_id",
    "menu_id",
    "course_number",
    "course_name",
    "public"."get_dish_component_count"("id") AS "component_count",
    ( SELECT "count"(*) AS "count"
           FROM "public"."components"
          WHERE (("components"."dish_id" = "d"."id") AND ("components"."is_make_ahead" = true))) AS "make_ahead_count",
    ( SELECT "count"(*) AS "count"
           FROM "public"."components"
          WHERE (("components"."dish_id" = "d"."id") AND ("components"."recipe_id" IS NOT NULL))) AS "components_with_recipes",
    ( SELECT "count"(*) AS "count"
           FROM "public"."components"
          WHERE (("components"."dish_id" = "d"."id") AND ("components"."recipe_id" IS NULL))) AS "components_without_recipes"
   FROM "public"."dishes" "d";




