CREATE TABLE IF NOT EXISTS "public"."ingredients" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "name" "text" NOT NULL,
    "category" "public"."ingredient_category" NOT NULL,
    "description" "text",
    "default_unit" "text" NOT NULL,
    "is_staple" boolean DEFAULT false NOT NULL,
    "allergen_flags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "dietary_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "average_price_cents" integer,
    "price_unit" "text",
    "last_price_cents" integer,
    "last_price_date" "date",
    "last_purchased_at" timestamp with time zone,
    "preferred_vendor" "text",
    "vendor_notes" "text",
    "archived" boolean DEFAULT false NOT NULL,
    "archived_at" timestamp with time zone,
    "created_by" "uuid",
    "updated_by" "uuid",
    "nutrition_calories_per_100g" numeric(10,2),
    "nutrition_protein_per_100g" numeric(10,2),
    "nutrition_fat_per_100g" numeric(10,2),
    "nutrition_carbs_per_100g" numeric(10,2),
    "nutrition_fiber_per_100g" numeric(10,2),
    "nutrition_sodium_mg_per_100g" numeric(10,2),
    "nutrition_source" "text",
    "nutrition_updated_at" timestamp with time zone,
    "cost_per_unit_cents" integer,
    "unit_type" "text" DEFAULT 'weight'::"text",
    "weight_to_volume_ratio" numeric(8,4),
    "default_yield_pct" integer DEFAULT 100,
    CONSTRAINT "ingredients_average_price_cents_check" CHECK ((("average_price_cents" >= 0) OR ("average_price_cents" IS NULL))),
    CONSTRAINT "ingredients_default_yield_pct_check" CHECK ((("default_yield_pct" IS NULL) OR (("default_yield_pct" > 0) AND ("default_yield_pct" <= 100)))),
    CONSTRAINT "ingredients_last_price_cents_check" CHECK ((("last_price_cents" >= 0) OR ("last_price_cents" IS NULL))),
    CONSTRAINT "ingredients_unit_type_check" CHECK ((("unit_type" IS NULL) OR ("unit_type" = ANY (ARRAY['weight'::"text", 'volume'::"text", 'each'::"text", 'length'::"text"]))))
);




COMMENT ON COLUMN "public"."ingredients"."cost_per_unit_cents" IS 'Canonical cost per default_unit in cents. Updated from price history or manual entry.';



COMMENT ON COLUMN "public"."ingredients"."unit_type" IS 'Classification of the default_unit: weight, volume, each, or length.';



COMMENT ON COLUMN "public"."ingredients"."weight_to_volume_ratio" IS 'Grams per mL for unit conversion (e.g. flour = 0.593, water = 1.0).';



COMMENT ON COLUMN "public"."ingredients"."default_yield_pct" IS 'Default usable yield after standard prep (100 = no loss, 85 = 15% trim loss).';



CREATE TABLE IF NOT EXISTS "public"."recipe_ingredients" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "recipe_id" "uuid" NOT NULL,
