    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "quantity" numeric(10,3) NOT NULL,
    "unit" "text" NOT NULL,
    "preparation_notes" "text",
    "is_optional" boolean DEFAULT false NOT NULL,
    "substitution_notes" "text",
    "sort_order" integer DEFAULT 0 NOT NULL,
    "prep_action" "text",
    "yield_pct" integer DEFAULT 100,
    "computed_cost_cents" integer,
    CONSTRAINT "recipe_ingredients_quantity_check" CHECK (("quantity" > (0)::numeric)),
    CONSTRAINT "recipe_ingredients_yield_pct_check" CHECK ((("yield_pct" IS NULL) OR (("yield_pct" > 0) AND ("yield_pct" <= 100))))
);




COMMENT ON COLUMN "public"."recipe_ingredients"."prep_action" IS 'Prep method applied (e.g. peel, dice, fillet). Drives yield calculation.';



COMMENT ON COLUMN "public"."recipe_ingredients"."yield_pct" IS 'Usable yield after this prep action (100 = no loss). Overrides ingredient default when set.';



COMMENT ON COLUMN "public"."recipe_ingredients"."computed_cost_cents" IS 'Computed: (cost_per_unit * quantity) / (yield_pct / 100). Updated by cascade engine.';



