);




COMMENT ON COLUMN "public"."recipes"."servings" IS 'Number of people this recipe serves';



COMMENT ON COLUMN "public"."recipes"."calories_per_serving" IS 'Manual calorie count per serving (USDA auto-calc also available)';



COMMENT ON COLUMN "public"."recipes"."difficulty" IS 'Difficulty rating 1-5 (1=easy, 5=expert)';



COMMENT ON COLUMN "public"."recipes"."equipment" IS 'Required equipment (e.g. stand mixer, food processor)';



COMMENT ON COLUMN "public"."recipes"."cuisine" IS 'Cuisine classification (Italian, French, etc.)';



COMMENT ON COLUMN "public"."recipes"."meal_type" IS 'Meal type (breakfast, lunch, dinner, etc.)';



COMMENT ON COLUMN "public"."recipes"."season" IS 'Applicable seasons (Spring, Summer, Fall, Winter, Year-Round)';



COMMENT ON COLUMN "public"."recipes"."occasion_tags" IS 'Occasion tags (Date Night, Wedding, Corporate, etc.)';



COMMENT ON COLUMN "public"."recipes"."total_cost_cents" IS 'Computed sum of all ingredient + sub-recipe costs (yield-adjusted). Updated by cascade engine.';



COMMENT ON COLUMN "public"."recipes"."cost_per_serving_cents" IS 'total_cost_cents / yield_quantity. Updated by cascade engine.';



CREATE OR REPLACE VIEW "public"."recipe_cost_summary" AS
 SELECT "id" AS "recipe_id",
    "tenant_id",
    "name" AS "recipe_name",
    "category",
    COALESCE("total_cost_cents", "public"."compute_recipe_cost_cents"("id")) AS "total_ingredient_cost_cents",
    COALESCE("cost_per_serving_cents",
        CASE
            WHEN ("yield_quantity" > (0)::numeric) THEN ((("public"."compute_recipe_cost_cents"("id"))::numeric / "yield_quantity"))::integer
            ELSE NULL::integer
        END) AS "cost_per_portion_cents",
    ( SELECT "count"(*) AS "count"
           FROM "public"."recipe_ingredients"
          WHERE ("recipe_ingredients"."recipe_id" = "r"."id")) AS "ingredient_count",
    ( SELECT ("count"(*) = "count"(COALESCE("i"."cost_per_unit_cents", "i"."last_price_cents")))
           FROM ("public"."recipe_ingredients" "ri"
             JOIN "public"."ingredients" "i" ON (("i"."id" = "ri"."ingredient_id")))
          WHERE ("ri"."recipe_id" = "r"."id")) AS "has_all_prices",
    ( SELECT "max"("i"."last_price_date") AS "max"
           FROM ("public"."recipe_ingredients" "ri"
             JOIN "public"."ingredients" "i" ON (("i"."id" = "ri"."ingredient_id")))
          WHERE ("ri"."recipe_id" = "r"."id")) AS "last_price_updated_at",
    ( SELECT "count"(*) AS "count"
           FROM "public"."recipe_sub_recipes"
          WHERE ("recipe_sub_recipes"."parent_recipe_id" = "r"."id")) AS "sub_recipe_count"
   FROM "public"."recipes" "r"
  WHERE ("archived" = false);




CREATE OR REPLACE VIEW "public"."dish_index_summary" AS
 SELECT "di"."id",
    "di"."tenant_id",
    "di"."name",
    "di"."course",
    "di"."description",
    "di"."dietary_tags",
    "di"."allergen_flags",
    "di"."times_served",
    "di"."first_served",
    "di"."last_served",
    "di"."is_signature",
    "di"."rotation_status",
    "di"."linked_recipe_id",
    "di"."prep_complexity",
    "di"."plating_difficulty",
    "di"."tags",
    "di"."season_affinity",
    "di"."archived",
    "r"."name" AS "recipe_name",
    "rcs"."total_ingredient_cost_cents" AS "recipe_cost_cents",
    "rcs"."cost_per_portion_cents" AS "per_portion_cost_cents",
    COALESCE("fb"."avg_rating", (0)::numeric) AS "avg_rating",
    COALESCE("fb"."feedback_count", (0)::bigint) AS "feedback_count"
   FROM ((("public"."dish_index" "di"
     LEFT JOIN "public"."recipes" "r" ON (("r"."id" = "di"."linked_recipe_id")))
     LEFT JOIN "public"."recipe_cost_summary" "rcs" ON (("rcs"."recipe_id" = "di"."linked_recipe_id")))
     LEFT JOIN ( SELECT "dish_feedback"."dish_id",
            ("avg"("dish_feedback"."rating"))::numeric(3,1) AS "avg_rating",
            "count"(*) AS "feedback_count"
           FROM "public"."dish_feedback"
          GROUP BY "dish_feedback"."dish_id") "fb" ON (("fb"."dish_id" = "di"."id")));




