    CONSTRAINT "equipment_depreciation_schedules_depreciable_basis_cents_check" CHECK (("depreciable_basis_cents" >= 0)),
    CONSTRAINT "equipment_depreciation_schedules_depreciation_method_check" CHECK (("depreciation_method" = ANY (ARRAY['section_179'::"text", 'straight_line'::"text"])))
);




COMMENT ON TABLE "public"."equipment_depreciation_schedules" IS 'Per-asset, per-year depreciation records for Schedule C Line 13 / Form 4562.';



CREATE TABLE IF NOT EXISTS "public"."equipment_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "category" "public"."equipment_category" DEFAULT 'other'::"public"."equipment_category" NOT NULL,
    "purchase_date" "date",
    "purchase_price_cents" integer,
    "current_value_cents" integer,
    "serial_number" "text",
    "notes" "text",
    "maintenance_interval_days" integer,
    "last_maintained_at" "date",
    "status" "text" DEFAULT 'owned'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "depreciation_method" "text",
    "useful_life_years" integer,
    "salvage_value_cents" integer DEFAULT 0,
    "tax_year_placed_in_service" integer,
    "brand" "text",
    "model" "text",
    "canonical_name" "text",
    "asset_state" "text" DEFAULT 'owned'::"text" NOT NULL,
    "quantity_owned" integer DEFAULT 1 NOT NULL,
    "storage_location" "text",
    "source_name" "text",
    "source_kind" "text",
    "source_url" "text",
    "source_sku" "text",
    "source_price_cents" integer,
    "source_last_verified_at" timestamp with time zone,
    CONSTRAINT "equipment_items_asset_state_check" CHECK (("asset_state" = ANY (ARRAY['owned'::"text", 'wishlist'::"text", 'reference'::"text"]))),
    CONSTRAINT "equipment_items_current_value_cents_check" CHECK (("current_value_cents" >= 0)),
    CONSTRAINT "equipment_items_depreciation_method_check" CHECK ((("depreciation_method" IS NULL) OR ("depreciation_method" = ANY (ARRAY['section_179'::"text", 'straight_line'::"text"])))),
    CONSTRAINT "equipment_items_purchase_price_cents_check" CHECK (("purchase_price_cents" >= 0)),
    CONSTRAINT "equipment_items_quantity_owned_check" CHECK (("quantity_owned" > 0)),
    CONSTRAINT "equipment_items_salvage_value_cents_check" CHECK ((("salvage_value_cents" IS NULL) OR ("salvage_value_cents" >= 0))),
    CONSTRAINT "equipment_items_source_kind_check" CHECK ((("source_kind" IS NULL) OR ("source_kind" = ANY (ARRAY['amazon'::"text", 'restaurant_supply'::"text", 'brand_direct'::"text", 'rental_house'::"text", 'local_store'::"text", 'other'::"text"])))),
    CONSTRAINT "equipment_items_source_price_cents_check" CHECK ((("source_price_cents" IS NULL) OR ("source_price_cents" >= 0))),
    CONSTRAINT "equipment_items_status_check" CHECK (("status" = ANY (ARRAY['owned'::"text", 'retired'::"text"]))),
    CONSTRAINT "equipment_items_useful_life_years_check" CHECK ((("useful_life_years" IS NULL) OR ("useful_life_years" > 0)))
);




COMMENT ON TABLE "public"."equipment_items" IS 'Chef-owned equipment inventory with maintenance schedule tracking.';



COMMENT ON COLUMN "public"."equipment_items"."maintenance_interval_days" IS 'How often this item needs maintenance. NULL = no schedule.';



COMMENT ON COLUMN "public"."equipment_items"."last_maintained_at" IS 'Date of last maintenance. Used to compute next due date.';



COMMENT ON COLUMN "public"."equipment_items"."depreciation_method" IS 'section_179 = full deduction in year of purchase. straight_line = cost/useful_life per year.';



COMMENT ON COLUMN "public"."equipment_items"."useful_life_years" IS 'IRS GDS useful life years. Required for straight_line. Defaults: knives/cookware=5, appliances=7.';



COMMENT ON COLUMN "public"."equipment_items"."tax_year_placed_in_service" IS 'Tax year placed in service. Defaults to purchase year if not specified.';



COMMENT ON COLUMN "public"."equipment_items"."canonical_name" IS 'Normalized product name used as the canonical asset identity across chef workflows.';



COMMENT ON COLUMN "public"."equipment_items"."asset_state" IS 'owned = currently in the chef kit, wishlist = planned purchase, reference = canonical recommended item.';



COMMENT ON COLUMN "public"."equipment_items"."source_url" IS 'Primary purchase link for the canonical source of truth for this asset.';



COMMENT ON COLUMN "public"."equipment_items"."source_last_verified_at" IS 'When the source link or price was last manually verified.';



CREATE TABLE IF NOT EXISTS "public"."equipment_rentals" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
