CREATE TABLE IF NOT EXISTS "public"."event_collaborators" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "invited_by_chef_id" "uuid" NOT NULL,
    "role" "text" DEFAULT 'co_host'::"text" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "permissions" "jsonb" DEFAULT '{"can_close_event": false, "can_modify_menu": false, "can_assign_staff": false, "can_view_financials": false, "can_communicate_with_client": false}'::"jsonb" NOT NULL,
    "note" "text",
    "responded_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
