    CONSTRAINT "no_self_collaboration" CHECK (("chef_id" <> "invited_by_chef_id"))
);




COMMENT ON TABLE "public"."event_collaborators" IS 'Cross-tenant chef collaboration on events. A chef invited here gains access to the event based on their role and permissions. Events retain their original tenant_id.';



COMMENT ON COLUMN "public"."event_collaborators"."role" IS 'primary | co_host | sous_chef | observer. Determines default permissions and dashboard visibility.';



COMMENT ON COLUMN "public"."event_collaborators"."permissions" IS 'JSONB with boolean keys: can_modify_menu, can_assign_staff, can_view_financials, can_communicate_with_client, can_close_event.';



