COMMENT ON COLUMN "public"."event_contracts"."body_snapshot" IS 'Rendered Markdown body with all merge fields substituted at generation time. Never updated after signing.';



COMMENT ON COLUMN "public"."event_contracts"."signature_data_url" IS 'Base64-encoded PNG of the client canvas signature.';



COMMENT ON COLUMN "public"."event_contracts"."signer_ip_address" IS 'Client IP at time of signing — legal evidence.';



CREATE TABLE IF NOT EXISTS "public"."event_document_generation_jobs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "event_id" "uuid" NOT NULL,
    "requested_type" "text" NOT NULL,
    "selected_types" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "archive_requested" boolean DEFAULT false NOT NULL,
    "idempotency_key" "text",
    "status" "text" DEFAULT 'started'::"text" NOT NULL,
    "attempts" integer DEFAULT 0 NOT NULL,
    "max_attempts" integer DEFAULT 3 NOT NULL,
    "error_message" "text",
    "result_filename" "text",
    "result_document_type" "text",
    "result_size_bytes" integer,
    "result_metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "completed_at" timestamp with time zone,
