    CONSTRAINT "event_document_generation_jobs_requested_type_check" CHECK (("requested_type" = ANY (ARRAY['summary'::"text", 'grocery'::"text", 'foh'::"text", 'prep'::"text", 'execution'::"text", 'checklist'::"text", 'packing'::"text", 'reset'::"text", 'travel'::"text", 'shots'::"text", 'all'::"text", 'pack'::"text"]))),
    CONSTRAINT "event_document_generation_jobs_result_document_type_check" CHECK ((("result_document_type" IS NULL) OR ("result_document_type" = ANY (ARRAY['summary'::"text", 'grocery'::"text", 'foh'::"text", 'prep'::"text", 'execution'::"text", 'checklist'::"text", 'packing'::"text", 'reset'::"text", 'travel'::"text", 'shots'::"text", 'all'::"text"])))),
    CONSTRAINT "event_document_generation_jobs_result_size_bytes_check" CHECK ((("result_size_bytes" IS NULL) OR ("result_size_bytes" >= 0))),
    CONSTRAINT "event_document_generation_jobs_selected_types_check" CHECK (("selected_types" <@ ARRAY['summary'::"text", 'grocery'::"text", 'foh'::"text", 'prep'::"text", 'execution'::"text", 'checklist'::"text", 'packing'::"text", 'reset'::"text", 'travel'::"text", 'shots'::"text"])),
    CONSTRAINT "event_document_generation_jobs_status_check" CHECK (("status" = ANY (ARRAY['started'::"text", 'succeeded'::"text", 'failed'::"text"])))
);




