CREATE OR REPLACE VIEW "public"."event_financial_summary" AS
SELECT
    NULL::"uuid" AS "event_id",
    NULL::"uuid" AS "tenant_id",
    NULL::integer AS "quoted_price_cents",
    NULL::"public"."payment_status" AS "payment_status",
    NULL::bigint AS "total_paid_cents",
    NULL::bigint AS "total_refunded_cents",
    NULL::bigint AS "net_revenue_cents",
    NULL::bigint AS "total_expenses_cents",
    NULL::integer AS "tip_amount_cents",
    NULL::bigint AS "profit_cents",
    NULL::numeric AS "profit_margin",
    NULL::numeric AS "food_cost_percentage",
    NULL::bigint AS "outstanding_balance_cents";




