    CONSTRAINT "events_price_non_negative" CHECK ((("quoted_price_cents" >= 0) OR ("quoted_price_cents" IS NULL))),
    CONSTRAINT "events_tip_non_negative" CHECK (("tip_amount_cents" >= 0))
);




COMMENT ON TABLE "public"."events" IS 'The canonical event record. Events only exist once inquiry is confirmed and quote is accepted.';



COMMENT ON COLUMN "public"."events"."tenant_id" IS 'FK to chefs.id - tenant scoping';



COMMENT ON COLUMN "public"."events"."allergies" IS 'IMMUTABLE after event creation - safety-critical data';



COMMENT ON COLUMN "public"."events"."status" IS '8-state FSM: draft → proposed → accepted → paid → confirmed → in_progress → completed | cancelled';



COMMENT ON COLUMN "public"."events"."pricing_snapshot" IS 'Frozen pricing at event creation - IMMUTABLE';



COMMENT ON COLUMN "public"."events"."payment_status" IS 'CRITICAL: ONLY written by update_event_payment_status_on_ledger_insert trigger. Application must NEVER set this field directly.';



COMMENT ON COLUMN "public"."events"."referral_partner_id" IS 'Which partner referred this event. Propagated from inquiry on conversion, or set directly for non-inquiry events.';



COMMENT ON COLUMN "public"."events"."partner_location_id" IS 'Which specific partner location this event is at (optional)';



COMMENT ON COLUMN "public"."events"."location_lat" IS 'Latitude from Google Places, for map display';



COMMENT ON COLUMN "public"."events"."location_lng" IS 'Longitude from Google Places, for map display';



COMMENT ON COLUMN "public"."events"."payment_reminder_7d_sent_at" IS 'When the 7-day payment reminder was sent. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."payment_reminder_3d_sent_at" IS 'When the 3-day payment reminder was sent. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."payment_reminder_1d_sent_at" IS 'When the 1-day payment reminder was sent. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."debrief_completed_at" IS 'Timestamp when the chef clicked "Complete Debrief". NULL means not yet completed.';



COMMENT ON COLUMN "public"."events"."chef_outcome_notes" IS 'Free-text chef reflection: what stood out, what to remember next time.';



COMMENT ON COLUMN "public"."events"."chef_outcome_rating" IS '1–5 star rating of how the dinner went overall. Set by chef during debrief.';



COMMENT ON COLUMN "public"."events"."invoice_number" IS 'Human-readable invoice ID (INV-YYYY-NNN). Set once on first payment receipt. Immutable.';



COMMENT ON COLUMN "public"."events"."invoice_issued_at" IS 'Timestamp when the invoice_number was first assigned.';



COMMENT ON COLUMN "public"."events"."menu_approval_status" IS 'Client menu approval state. Updated when chef sends menu and when client responds.';



COMMENT ON COLUMN "public"."events"."menu_revision_notes" IS 'Client notes when requesting menu revisions.';



COMMENT ON COLUMN "public"."events"."financial_closed" IS 'True when the chef has marked this event financially closed (all payments received, all receipts approved).';



COMMENT ON COLUMN "public"."events"."financial_closed_at" IS 'Timestamp when financial_closed was set to true.';



COMMENT ON COLUMN "public"."events"."mileage_miles" IS 'Total miles driven for this event. Used for IRS mileage deduction calculation.';



COMMENT ON COLUMN "public"."events"."client_reminder_7d_sent_at" IS '7-day pre-event reminder email sent to client. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."client_reminder_2d_sent_at" IS '2-day pre-event reminder email sent to client. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."client_reminder_1d_sent_at" IS '1-day (24h) pre-event reminder email sent to client. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."actual_menu_deviations" IS 'Free-text notes on what changed from the proposed menu to what was actually served. Null = no deviations.';



COMMENT ON COLUMN "public"."events"."parking_tolls_cents" IS 'Parking fees and tolls paid for this event. Used in true cost-per-event calculations.';



COMMENT ON COLUMN "public"."events"."inquiry_received_at" IS 'When the inquiry that led to this event was first received. Copied from inquiries.first_contact_at at event creation. Used for booking lead time analytics.';



COMMENT ON COLUMN "public"."events"."food_cost_budget_cents" IS 'Optional chef-set food cost budget in cents. When NULL, the budget is derived from quoted_price_cents × (1 - target_margin_percent). When set, this value overrides the formula.';



COMMENT ON COLUMN "public"."events"."booking_source" IS 'How the event was created: inquiry (standard flow) or instant_book (client paid deposit upfront)';



COMMENT ON COLUMN "public"."events"."review_request_sent_at" IS 'Timestamp when the automated post-event review request email was sent. NULL = not yet sent.';



COMMENT ON COLUMN "public"."events"."client_reminder_30d_sent_at" IS 'Set after 30-day pre-event client reminder email fires. Null = not yet sent.';



COMMENT ON COLUMN "public"."events"."client_reminder_14d_sent_at" IS 'Set after 14-day pre-event client reminder email fires. Null = not yet sent.';



COMMENT ON COLUMN "public"."events"."estimated_food_cost_cents" IS 'NE-calibrated average grocery estimate from the grocery quote panel. Populated when a grocery quote is generated. Null = no estimate yet.';



COMMENT ON COLUMN "public"."events"."retainer_id" IS 'If this event is part of a retainer agreement, links to the retainer';



COMMENT ON COLUMN "public"."events"."retainer_period_id" IS 'Specific billing period this event counts against';



COMMENT ON COLUMN "public"."events"."course_count" IS 'Number of courses for the event. Used by cannabis control packet per-course tracking.';



COMMENT ON COLUMN "public"."events"."cost_needs_refresh" IS 'Set true when upstream ingredient/recipe costs change. Chef reviews before clearing.';



