CREATE OR REPLACE VIEW "public"."event_inventory_variance" AS
 WITH "expected_usage" AS (
         SELECT "e"."id" AS "event_id",
            "e"."tenant_id" AS "chef_id",
            "i"."id" AS "ingredient_id",
            "i"."name" AS "ingredient_name",
            "ri"."unit",
            "sum"(("ri"."quantity" * COALESCE("c"."scale_factor", (1)::numeric))) AS "expected_qty",
            "i"."last_price_cents"
           FROM ((((("public"."events" "e"
             JOIN "public"."menus" "m" ON (("m"."event_id" = "e"."id")))
             JOIN "public"."dishes" "d" ON (("d"."menu_id" = "m"."id")))
             JOIN "public"."components" "c" ON ((("c"."dish_id" = "d"."id") AND ("c"."recipe_id" IS NOT NULL))))
             JOIN "public"."recipe_ingredients" "ri" ON (("ri"."recipe_id" = "c"."recipe_id")))
             JOIN "public"."ingredients" "i" ON (("i"."id" = "ri"."ingredient_id")))
          WHERE ("e"."status" = ANY (ARRAY['completed'::"public"."event_status", 'in_progress'::"public"."event_status"]))
          GROUP BY "e"."id", "e"."tenant_id", "i"."id", "i"."name", "ri"."unit", "i"."last_price_cents"
        ), "actual_usage" AS (
         SELECT "it"."event_id",
            "it"."chef_id",
            "it"."ingredient_id",
            "max"("it"."ingredient_name") AS "ingredient_name",
            "it"."unit",
            "abs"("sum"("it"."quantity")) AS "actual_qty"
           FROM "public"."inventory_transactions" "it"
          WHERE (("it"."event_id" IS NOT NULL) AND ("it"."transaction_type" = 'event_deduction'::"public"."inventory_transaction_type"))
          GROUP BY "it"."event_id", "it"."chef_id", "it"."ingredient_id", "it"."unit"
        )
 SELECT "eu"."event_id",
    "eu"."chef_id",
    "eu"."ingredient_id",
    "eu"."ingredient_name",
    "eu"."unit",
    "eu"."expected_qty",
    COALESCE("au"."actual_qty", (0)::numeric) AS "actual_qty",
    (COALESCE("au"."actual_qty", (0)::numeric) - "eu"."expected_qty") AS "variance_qty",
    "eu"."last_price_cents",
    (((COALESCE("au"."actual_qty", (0)::numeric) - "eu"."expected_qty") * (COALESCE("eu"."last_price_cents", 0))::numeric))::integer AS "variance_cost_cents"
   FROM ("expected_usage" "eu"
     LEFT JOIN "actual_usage" "au" ON ((("eu"."event_id" = "au"."event_id") AND ("eu"."ingredient_id" = "au"."ingredient_id"))));




