CREATE OR REPLACE VIEW "public"."event_rsvp_summary" AS
 SELECT "event_id",
    "tenant_id",
    ("count"(*))::integer AS "total_guests",
    ("count"(*) FILTER (WHERE ("rsvp_status" = 'attending'::"public"."rsvp_status")))::integer AS "attending_count",
    ("count"(*) FILTER (WHERE ("rsvp_status" = 'declined'::"public"."rsvp_status")))::integer AS "declined_count",
    ("count"(*) FILTER (WHERE ("rsvp_status" = 'maybe'::"public"."rsvp_status")))::integer AS "maybe_count",
    ("count"(*) FILTER (WHERE (("rsvp_status" = 'pending'::"public"."rsvp_status") AND (COALESCE("attendance_queue_status", 'none'::"text") <> 'waitlisted'::"text"))))::integer AS "pending_count",
    ("count"(*) FILTER (WHERE (COALESCE("attendance_queue_status", 'none'::"text") = 'waitlisted'::"text")))::integer AS "waitlisted_count",
    ("count"(*) FILTER (WHERE ("plus_one" = true)))::integer AS "plus_one_count",
    ARRAY( SELECT DISTINCT "unnest"("eg2"."dietary_restrictions") AS "unnest"
           FROM "public"."event_guests" "eg2"
          WHERE (("eg2"."event_id" = "eg"."event_id") AND ("eg2"."rsvp_status" = ANY (ARRAY['attending'::"public"."rsvp_status", 'maybe'::"public"."rsvp_status"])) AND ("eg2"."dietary_restrictions" <> '{}'::"text"[]))) AS "all_dietary_restrictions",
    ARRAY( SELECT DISTINCT "unnest"("eg2"."allergies") AS "unnest"
           FROM "public"."event_guests" "eg2"
          WHERE (("eg2"."event_id" = "eg"."event_id") AND ("eg2"."rsvp_status" = ANY (ARRAY['attending'::"public"."rsvp_status", 'maybe'::"public"."rsvp_status"])) AND ("eg2"."allergies" <> '{}'::"text"[]))) AS "all_allergies"
   FROM "public"."event_guests" "eg"
  GROUP BY "event_id", "tenant_id";




