CREATE OR REPLACE VIEW "public"."event_time_summary" AS
 SELECT "id" AS "event_id",
    "tenant_id",
    (EXTRACT(epoch FROM ("shopping_completed_at" - "shopping_started_at")) / (60)::numeric) AS "shopping_duration_minutes",
    (EXTRACT(epoch FROM ("prep_completed_at" - "prep_started_at")) / (60)::numeric) AS "prep_duration_minutes",
    (EXTRACT(epoch FROM ("travel_completed_at" - "travel_started_at")) / (60)::numeric) AS "travel_duration_minutes",
    (EXTRACT(epoch FROM ("service_completed_at" - "service_started_at")) / (60)::numeric) AS "service_duration_minutes",
    (EXTRACT(epoch FROM ("reset_completed_at" - "reset_started_at")) / (60)::numeric) AS "reset_duration_minutes",
    (((((COALESCE(EXTRACT(epoch FROM ("shopping_completed_at" - "shopping_started_at")), (0)::numeric) + COALESCE(EXTRACT(epoch FROM ("prep_completed_at" - "prep_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("travel_completed_at" - "travel_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("service_completed_at" - "service_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("reset_completed_at" - "reset_started_at")), (0)::numeric)) / (60)::numeric) AS "total_time_minutes",
    (((((COALESCE(EXTRACT(epoch FROM ("shopping_completed_at" - "shopping_started_at")), (0)::numeric) + COALESCE(EXTRACT(epoch FROM ("prep_completed_at" - "prep_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("travel_completed_at" - "travel_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("service_completed_at" - "service_started_at")), (0)::numeric)) + COALESCE(EXTRACT(epoch FROM ("reset_completed_at" - "reset_started_at")), (0)::numeric)) / (3600)::numeric) AS "total_time_hours"
   FROM "public"."events";




