    CONSTRAINT "guest_testimonials_food_rating_check" CHECK ((("food_rating" >= 1) AND ("food_rating" <= 5))),
    CONSTRAINT "guest_testimonials_rating_check" CHECK ((("rating" >= 1) AND ("rating" <= 5))),
    CONSTRAINT "guest_testimonials_testimonial_check" CHECK (("char_length"("testimonial") <= 1000))
);




