CREATE OR REPLACE VIEW "public"."ingredient_usage_summary" AS
 SELECT "id" AS "ingredient_id",
    "tenant_id",
    "name" AS "ingredient_name",
    "category",
    ( SELECT "count"(*) AS "count"
           FROM "public"."recipe_ingredients"
          WHERE ("recipe_ingredients"."ingredient_id" = "i"."id")) AS "times_used",
    ( SELECT "array_agg"(DISTINCT "r"."name") AS "array_agg"
           FROM ("public"."recipe_ingredients" "ri"
             JOIN "public"."recipes" "r" ON (("r"."id" = "ri"."recipe_id")))
          WHERE ("ri"."ingredient_id" = "i"."id")) AS "recipes_using",
    ( SELECT "max"("r"."last_cooked_at") AS "max"
           FROM ("public"."recipe_ingredients" "ri"
             JOIN "public"."recipes" "r" ON (("r"."id" = "ri"."recipe_id")))
          WHERE ("ri"."ingredient_id" = "i"."id")) AS "last_used_in_recipe_at"
   FROM "public"."ingredients" "i"
  WHERE ("archived" = false);




CREATE TABLE IF NOT EXISTS "public"."inquiries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid",
    "channel" "public"."inquiry_channel" NOT NULL,
    "status" "public"."inquiry_status" DEFAULT 'new'::"public"."inquiry_status" NOT NULL,
    "source_message" "text",
    "confirmed_date" timestamp with time zone,
    "confirmed_guest_count" integer,
    "confirmed_location" "text",
    "confirmed_occasion" "text",
    "confirmed_budget_cents" integer,
    "confirmed_dietary_restrictions" "text"[],
    "confirmed_service_expectations" "text",
    "confirmed_cannabis_preference" "text",
    "unknown_fields" "jsonb" DEFAULT '[]'::"jsonb",
    "next_action_required" "text",
    "next_action_by" "text",
    "follow_up_due_at" timestamp with time zone,
    "first_contact_at" timestamp with time zone NOT NULL,
    "last_response_at" timestamp with time zone,
    "converted_to_event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "referral_partner_id" "uuid",
    "partner_location_id" "uuid",
    "decline_reason" "text",
    "ghost_at" timestamp with time zone,
    "is_demo" boolean DEFAULT false NOT NULL,
    "budget_range" "text",
    "referral_source" "text",
    "service_style_pref" "text",
    "external_inquiry_id" "text",
    "external_platform" "text",
    "external_link" "text",
    "chef_likelihood" "text",
    "utm_source" "text",
    "utm_medium" "text",
    "utm_campaign" "text",
    "deleted_at" timestamp with time zone,
    "deleted_by" "uuid",
    "service_mode" "public"."booking_service_mode",
    "schedule_request_jsonb" "jsonb",
    "contact_name" "text",
    "contact_email" "text",
    "contact_phone" "text",
    CONSTRAINT "inquiries_chef_likelihood_check" CHECK (("chef_likelihood" = ANY (ARRAY['hot'::"text", 'warm'::"text", 'cold'::"text"]))),
    CONSTRAINT "inquiries_decline_reason_check" CHECK (("decline_reason" = ANY (ARRAY['too_expensive'::"text", 'wrong_date'::"text", 'found_another_chef'::"text", 'no_response'::"text", 'location_too_far'::"text", 'menu_mismatch'::"text", 'other'::"text"]))),
    CONSTRAINT "inquiries_next_action_by_check" CHECK (("next_action_by" = ANY (ARRAY['chef'::"text", 'client'::"text"])))
);




COMMENT ON TABLE "public"."inquiries" IS 'Unified inquiry tracking from all channels (Part 11). Every inquiry becomes a structured record.';



COMMENT ON COLUMN "public"."inquiries"."client_id" IS 'Nullable - inquiry might be from new lead who is not yet a client';



COMMENT ON COLUMN "public"."inquiries"."source_message" IS 'Verbatim original message for context';



COMMENT ON COLUMN "public"."inquiries"."unknown_fields" IS 'Array of blocking questions: ["What time?", "How many guests?"]';



COMMENT ON COLUMN "public"."inquiries"."follow_up_due_at" IS 'When to prompt chef if no response. Update to next interval when follow-up sent. No separate follow_ups table needed.';



COMMENT ON COLUMN "public"."inquiries"."converted_to_event_id" IS 'UUID of event created from this inquiry. FK constraint will be added in Layer 3 when events table exists.';



COMMENT ON COLUMN "public"."inquiries"."referral_partner_id" IS 'Which partner referred this inquiry (orthogonal to channel — channel is HOW they reached out, partner is WHO sent them)';



COMMENT ON COLUMN "public"."inquiries"."partner_location_id" IS 'Which specific partner location this inquiry is associated with (optional)';



COMMENT ON COLUMN "public"."inquiries"."decline_reason" IS 'Why the inquiry did not convert. Set when status = declined or expired. Used for decline reason breakdown analytics.';



COMMENT ON COLUMN "public"."inquiries"."ghost_at" IS 'Timestamp when this inquiry went cold (status = expired). Distinct from declined — ghost means client stopped responding.';



COMMENT ON COLUMN "public"."inquiries"."budget_range" IS 'Client budget range submitted at inquiry time';



COMMENT ON COLUMN "public"."inquiries"."referral_source" IS 'How the client found the chef';



COMMENT ON COLUMN "public"."inquiries"."service_style_pref" IS 'Preferred service style: plated, family_style, cocktail, buffet, flexible';



