CREATE OR REPLACE VIEW "public"."inventory_by_location" AS
 SELECT "it"."chef_id",
    "it"."location_id",
    "sl"."name" AS "location_name",
    "sl"."location_type",
    "it"."ingredient_id",
    "max"("it"."ingredient_name") AS "ingredient_name",
    "it"."unit",
    "sum"("it"."quantity") AS "current_qty"
   FROM ("public"."inventory_transactions" "it"
     LEFT JOIN "public"."storage_locations" "sl" ON (("sl"."id" = "it"."location_id")))
  WHERE ("it"."location_id" IS NOT NULL)
  GROUP BY "it"."chef_id", "it"."location_id", "sl"."name", "sl"."location_type", "it"."ingredient_id", "it"."unit"
 HAVING ("sum"("it"."quantity") <> (0)::numeric);




