    "ingredient_name" "text" NOT NULL,
    "current_qty" numeric(10,3) DEFAULT 0 NOT NULL,
    "par_level" numeric(10,3),
    "unit" "text" NOT NULL,
    "last_counted_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "vendor_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "location_id" "uuid"
);




CREATE OR REPLACE VIEW "public"."inventory_current_stock" AS
 SELECT "it"."chef_id",
    "it"."ingredient_id",
    "max"("it"."ingredient_name") AS "ingredient_name",
    "it"."unit",
    "sum"("it"."quantity") AS "current_qty",
    "ic"."par_level",
    "ic"."vendor_id",
    "max"("it"."created_at") AS "last_movement_at",
    "count"(*) AS "transaction_count"
   FROM ("public"."inventory_transactions" "it"
     LEFT JOIN "public"."inventory_counts" "ic" ON ((("ic"."chef_id" = "it"."chef_id") AND ("ic"."ingredient_id" = "it"."ingredient_id"))))
  GROUP BY "it"."chef_id", "it"."ingredient_id", "it"."unit", "ic"."par_level", "ic"."vendor_id";




CREATE OR REPLACE VIEW "public"."inventory_expiry_alerts" AS
 SELECT "ib"."chef_id",
    "ib"."id" AS "batch_id",
    "ib"."ingredient_id",
    "ib"."ingredient_name",
    "ib"."expiry_date",
    "ib"."remaining_qty",
    "ib"."unit",
    "ib"."unit_cost_cents",
    (("ib"."remaining_qty" * (COALESCE("ib"."unit_cost_cents", 0))::numeric))::integer AS "at_risk_cost_cents",
    "sl"."name" AS "location_name",
        CASE
            WHEN ("ib"."expiry_date" <= CURRENT_DATE) THEN 'expired'::"text"
            WHEN ("ib"."expiry_date" <= (CURRENT_DATE + 3)) THEN 'critical'::"text"
            WHEN ("ib"."expiry_date" <= (CURRENT_DATE + 7)) THEN 'warning'::"text"
            ELSE 'ok'::"text"
        END AS "urgency"
   FROM ("public"."inventory_batches" "ib"
     LEFT JOIN "public"."storage_locations" "sl" ON (("sl"."id" = "ib"."location_id")))
  WHERE ((NOT "ib"."is_depleted") AND ("ib"."expiry_date" IS NOT NULL) AND ("ib"."expiry_date" <= (CURRENT_DATE + '7 days'::interval)));




