CREATE TABLE IF NOT EXISTS "public"."ledger_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "entry_type" "public"."ledger_entry_type" NOT NULL,
    "amount_cents" integer NOT NULL,
    "description" "text" NOT NULL,
    "internal_notes" "text",
    "payment_method" "public"."payment_method" NOT NULL,
    "payment_card_used" "text",
    "transaction_reference" "text",
    "received_at" timestamp with time zone,
    "is_refund" boolean DEFAULT false NOT NULL,
    "refund_reason" "text",
    "refunded_entry_id" "uuid",
    "ledger_sequence" bigint NOT NULL,
    "created_by" "uuid",
    "qb_synced_at" timestamp with time zone,
    "qb_entity_id" "text",
    "currency_code" "text" DEFAULT 'USD'::"text" NOT NULL,
    "exchange_rate_to_base" numeric(12,6) DEFAULT 1.0,
    CONSTRAINT "ledger_amount_nonzero" CHECK (("amount_cents" <> 0)),
    CONSTRAINT "ledger_refund_has_reason" CHECK (((("is_refund" = true) AND ("refund_reason" IS NOT NULL)) OR ("is_refund" = false))),
    CONSTRAINT "ledger_refund_negative" CHECK (((("is_refund" = true) AND ("amount_cents" < 0)) OR (("is_refund" = false) AND ("amount_cents" > 0)))),
    CONSTRAINT "ledger_refund_type_match" CHECK (((("entry_type" = 'refund'::"public"."ledger_entry_type") AND ("is_refund" = true)) OR ("entry_type" <> 'refund'::"public"."ledger_entry_type")))
);




COMMENT ON TABLE "public"."ledger_entries" IS 'CRITICAL: Append-only financial ledger. NEVER update or delete. Only INSERT allowed.';



COMMENT ON COLUMN "public"."ledger_entries"."ledger_sequence" IS 'Immutable sequence number for audit ordering';



CREATE SEQUENCE IF NOT EXISTS "public"."ledger_entries_ledger_sequence_seq"
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;




ALTER SEQUENCE "public"."ledger_entries_ledger_sequence_seq" OWNED BY "public"."ledger_entries"."ledger_sequence";



CREATE TABLE IF NOT EXISTS "public"."loyalty_config" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "points_per_guest" integer DEFAULT 10 NOT NULL,
    "bonus_large_party_threshold" integer DEFAULT 8,
    "bonus_large_party_points" integer DEFAULT 20,
    "milestone_bonuses" "jsonb" DEFAULT '[{"bonus": 50, "events": 5}, {"bonus": 100, "events": 10}]'::"jsonb" NOT NULL,
    "tier_bronze_min" integer DEFAULT 0 NOT NULL,
    "tier_silver_min" integer DEFAULT 200 NOT NULL,
    "tier_gold_min" integer DEFAULT 500 NOT NULL,
    "tier_platinum_min" integer DEFAULT 1000 NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "welcome_points" integer DEFAULT 25 NOT NULL,
    "referral_points" integer DEFAULT 100 NOT NULL,
    "program_mode" "text" DEFAULT 'full'::"text" NOT NULL,
    "earn_mode" "text" DEFAULT 'per_guest'::"text" NOT NULL,
    "points_per_dollar" numeric(5,2) DEFAULT 1.0 NOT NULL,
    "points_per_event" integer DEFAULT 100 NOT NULL,
    CONSTRAINT "loyalty_config_earn_mode_check" CHECK (("earn_mode" = ANY (ARRAY['per_guest'::"text", 'per_dollar'::"text", 'per_event'::"text"]))),
    CONSTRAINT "loyalty_config_program_mode_check" CHECK (("program_mode" = ANY (ARRAY['full'::"text", 'lite'::"text", 'off'::"text"]))),
    CONSTRAINT "loyalty_config_thresholds_ascending" CHECK ((("tier_bronze_min" < "tier_silver_min") AND ("tier_silver_min" < "tier_gold_min") AND ("tier_gold_min" < "tier_platinum_min")))
);




COMMENT ON TABLE "public"."loyalty_config" IS 'Per-tenant loyalty program configuration. One row per chef.';



COMMENT ON COLUMN "public"."loyalty_config"."welcome_points" IS 'Points automatically awarded when a client joins via invitation. Set to 0 to disable.';



COMMENT ON COLUMN "public"."loyalty_config"."referral_points" IS 'Points awarded to the referring client when a referred client completes their first event.';



COMMENT ON COLUMN "public"."loyalty_config"."program_mode" IS 'full = points + tiers + rewards, lite = tiers + recognition only (no points), off = disabled';



COMMENT ON COLUMN "public"."loyalty_config"."earn_mode" IS 'per_guest = X pts per guest, per_dollar = X pts per dollar spent, per_event = flat pts per event';



COMMENT ON COLUMN "public"."loyalty_config"."points_per_dollar" IS 'Points earned per dollar spent (earn_mode = per_dollar)';



COMMENT ON COLUMN "public"."loyalty_config"."points_per_event" IS 'Flat points earned per completed event (earn_mode = per_event)';



CREATE TABLE IF NOT EXISTS "public"."loyalty_reward_redemptions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
