    "reward_type" "text" NOT NULL,
    "points_spent" integer NOT NULL,
    "delivery_status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "event_id" "uuid",
    "delivered_at" timestamp with time zone,
    "delivery_note" "text",
    "redeemed_by" "text" DEFAULT 'client'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reward_value_cents" integer,
    "reward_percent" integer,
    CONSTRAINT "loyalty_reward_redemptions_delivery_status_check" CHECK (("delivery_status" = ANY (ARRAY['pending'::"text", 'delivered'::"text", 'cancelled'::"text"]))),
    CONSTRAINT "loyalty_reward_redemptions_redeemed_by_check" CHECK (("redeemed_by" = ANY (ARRAY['client'::"text", 'chef'::"text"])))
);




COMMENT ON COLUMN "public"."loyalty_reward_redemptions"."reward_value_cents" IS 'Snapshot of loyalty_rewards.reward_value_cents at redemption time (discount_fixed only).';



COMMENT ON COLUMN "public"."loyalty_reward_redemptions"."reward_percent" IS 'Snapshot of loyalty_rewards.reward_percent at redemption time (discount_percent only).';



CREATE TABLE IF NOT EXISTS "public"."loyalty_rewards" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "points_required" integer NOT NULL,
    "reward_type" "public"."loyalty_reward_type" NOT NULL,
    "reward_value_cents" integer,
    "reward_percent" integer,
    "is_active" boolean DEFAULT true NOT NULL,
    "sort_order" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    "updated_by" "uuid",
    CONSTRAINT "loyalty_rewards_points_positive" CHECK (("points_required" > 0)),
    CONSTRAINT "loyalty_rewards_value_check" CHECK (((("reward_type" = 'discount_fixed'::"public"."loyalty_reward_type") AND ("reward_value_cents" > 0)) OR (("reward_type" = 'discount_percent'::"public"."loyalty_reward_type") AND ("reward_percent" > 0) AND ("reward_percent" <= 100)) OR ("reward_type" <> ALL (ARRAY['discount_fixed'::"public"."loyalty_reward_type", 'discount_percent'::"public"."loyalty_reward_type"]))))
);




COMMENT ON TABLE "public"."loyalty_rewards" IS 'Service-denominated reward catalog. The chef never spends money — rewards are time and cooking.';



CREATE TABLE IF NOT EXISTS "public"."loyalty_transactions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "event_id" "uuid",
