    "points" integer NOT NULL,
    "description" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    CONSTRAINT "loyalty_transactions_points_direction" CHECK (((("type" = ANY (ARRAY['earned'::"public"."loyalty_transaction_type", 'bonus'::"public"."loyalty_transaction_type"])) AND ("points" > 0)) OR (("type" = 'redeemed'::"public"."loyalty_transaction_type") AND ("points" < 0)) OR ("type" = ANY (ARRAY['adjustment'::"public"."loyalty_transaction_type", 'expired'::"public"."loyalty_transaction_type"]))))
);




COMMENT ON TABLE "public"."loyalty_transactions" IS 'Append-only ledger of all loyalty point changes. Never update or delete.';



