CREATE OR REPLACE VIEW "public"."menu_cost_summary" AS
 SELECT "m"."id" AS "menu_id",
    "m"."tenant_id",
    "m"."event_id",
    "m"."name" AS "menu_name",
    "public"."get_menu_total_component_count"("m"."id") AS "total_component_count",
    "public"."compute_menu_cost_cents"("m"."id") AS "total_recipe_cost_cents",
        CASE
            WHEN ("e"."guest_count" > 0) THEN ("public"."compute_menu_cost_cents"("m"."id") / "e"."guest_count")
            ELSE NULL::integer
        END AS "cost_per_guest_cents",
        CASE
            WHEN ("e"."quoted_price_cents" > 0) THEN (((("public"."compute_menu_cost_cents"("m"."id"))::numeric / ("e"."quoted_price_cents")::numeric) * (100)::numeric))::numeric(5,2)
            ELSE NULL::numeric
        END AS "food_cost_percentage",
    ( SELECT ("count"(*) = "count"("c"."recipe_id"))
           FROM ("public"."components" "c"
             JOIN "public"."dishes" "d" ON (("d"."id" = "c"."dish_id")))
          WHERE ("d"."menu_id" = "m"."id")) AS "has_all_recipe_costs"
   FROM ("public"."menus" "m"
     LEFT JOIN "public"."events" "e" ON (("e"."id" = "m"."event_id")));




