COMMENT ON TABLE "public"."messages" IS 'Contextual, event-bound communication (Part 12). Messages are permanent records - NEVER deleted once logged. All outbound messages require explicit approval before sending.';



COMMENT ON COLUMN "public"."messages"."event_id" IS 'UUID of related event. FK constraint will be added in Layer 3 when events table exists.';



COMMENT ON COLUMN "public"."messages"."status" IS 'draft → approved → sent for outbound; logged for inbound';



COMMENT ON COLUMN "public"."messages"."direction" IS 'inbound (client → chef) or outbound (chef → client)';



COMMENT ON COLUMN "public"."messages"."approved_by" IS 'Required for outbound messages - NO auto-sending ever';



COMMENT ON COLUMN "public"."messages"."conversation_thread_id" IS 'Optional link to a communication inbox thread for outbound email drafts and sends.';



COMMENT ON COLUMN "public"."messages"."recipient_email" IS 'Resolved recipient email used for outbound email drafts, even when no client record is linked yet.';



CREATE TABLE IF NOT EXISTS "public"."mileage_logs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "log_date" "date" NOT NULL,
    "from_address" "text" NOT NULL,
    "to_address" "text" NOT NULL,
    "miles" numeric(7,2) NOT NULL,
    "purpose" "text" DEFAULT 'other'::"text" NOT NULL,
    "event_id" "uuid",
    "irs_rate_cents_per_mile" integer DEFAULT 73 NOT NULL,
    "deduction_cents" integer GENERATED ALWAYS AS ("round"(("miles" * ("irs_rate_cents_per_mile")::numeric))) STORED,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "tenant_id" "uuid",
    "trip_date" "date",
    "description" "text",
    "from_location" "text",
    "to_location" "text",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "mileage_logs_miles_check" CHECK (("miles" > (0)::numeric)),
    CONSTRAINT "mileage_logs_purpose_check" CHECK (("purpose" = ANY (ARRAY['shopping'::"text", 'event'::"text", 'meeting'::"text", 'admin'::"text", 'equipment'::"text", 'other'::"text"])))
);




COMMENT ON TABLE "public"."mileage_logs" IS 'IRS-compliant mileage log. deduction_cents is computed from miles × irs_rate_cents_per_mile at log time.';



COMMENT ON COLUMN "public"."mileage_logs"."irs_rate_cents_per_mile" IS 'Standard IRS mileage rate in cents at time of entry. 2025 = 70 cents/mile.';



COMMENT ON COLUMN "public"."mileage_logs"."deduction_cents" IS 'Computed deduction = miles × rate. Stored to preserve historical accuracy when rate changes.';



