CREATE TABLE IF NOT EXISTS "public"."notification_delivery_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "notification_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "channel" "text" NOT NULL,
    "status" "text" NOT NULL,
    "error_message" "text",
    "sent_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "notification_delivery_log_channel_check" CHECK (("channel" = ANY (ARRAY['email'::"text", 'push'::"text", 'sms'::"text"]))),
    CONSTRAINT "notification_delivery_log_status_check" CHECK (("status" = ANY (ARRAY['sent'::"text", 'failed'::"text", 'skipped'::"text"])))
);




COMMENT ON TABLE "public"."notification_delivery_log" IS 'Immutable delivery audit log. One row per channel attempt per notification. Used for debugging and settings UI.';



COMMENT ON COLUMN "public"."notification_delivery_log"."channel" IS 'Delivery channel: email, push (browser), or sms.';



COMMENT ON COLUMN "public"."notification_delivery_log"."status" IS 'sent = delivered, failed = error, skipped = not attempted (channel disabled or rate-limited).';



CREATE TABLE IF NOT EXISTS "public"."notification_preferences" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "auth_user_id" "uuid" NOT NULL,
