    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "tier" "text",
    "email_enabled" boolean,
    "push_enabled" boolean,
    "sms_enabled" boolean,
    CONSTRAINT "notification_preferences_tier_check" CHECK (("tier" = ANY (ARRAY['critical'::"text", 'alert'::"text", 'info'::"text"])))
);




COMMENT ON TABLE "public"."notification_preferences" IS 'Per-category toast notification preferences. Missing row = toast enabled (default).';



COMMENT ON COLUMN "public"."notification_preferences"."tier" IS 'Optional tier override for this category. NULL = use DEFAULT_TIER_MAP from tier-config.ts.';



COMMENT ON COLUMN "public"."notification_preferences"."email_enabled" IS 'Email channel override. NULL = inherit from tier default.';



COMMENT ON COLUMN "public"."notification_preferences"."push_enabled" IS 'Browser push channel override. NULL = inherit from tier default.';



COMMENT ON COLUMN "public"."notification_preferences"."sms_enabled" IS 'SMS channel override. NULL = inherit from tier default.';



CREATE TABLE IF NOT EXISTS "public"."notifications" (
