CREATE TABLE IF NOT EXISTS "public"."platform_payouts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "platform_record_id" "uuid" NOT NULL,
    "inquiry_id" "uuid" NOT NULL,
    "event_id" "uuid",
    "platform" "text" NOT NULL,
    "gross_booking_cents" integer,
    "commission_percent" numeric(6,2),
    "commission_amount_cents" integer,
    "net_payout_cents" integer,
    "payout_status" "text" DEFAULT 'untracked'::"text" NOT NULL,
    "payout_arrival_date" "date",
    "payout_reference" "text",
    "notes" "text",
    "source" "text" DEFAULT 'inquiry'::"text" NOT NULL,
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "captured_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "timezone"('utc'::"text", "now"()) NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "timezone"('utc'::"text", "now"()) NOT NULL,
    CONSTRAINT "platform_payouts_commission_amount_cents_check" CHECK ((("commission_amount_cents" IS NULL) OR ("commission_amount_cents" >= 0))),
    CONSTRAINT "platform_payouts_commission_percent_check" CHECK ((("commission_percent" IS NULL) OR (("commission_percent" >= (0)::numeric) AND ("commission_percent" <= (100)::numeric)))),
    CONSTRAINT "platform_payouts_gross_booking_cents_check" CHECK ((("gross_booking_cents" IS NULL) OR ("gross_booking_cents" >= 0))),
