    CONSTRAINT "prospects_scrub_type_check" CHECK (("scrub_type" = ANY (ARRAY['standard'::"text", 'competitor'::"text", 'lookalike'::"text"]))),
    CONSTRAINT "prospects_source_check" CHECK (("source" = ANY (ARRAY['ai_scrub'::"text", 'web_enriched'::"text", 'manual'::"text"]))),
    CONSTRAINT "prospects_status_check" CHECK (("status" = ANY (ARRAY['new'::"text", 'queued'::"text", 'called'::"text", 'follow_up'::"text", 'not_interested'::"text", 'converted'::"text", 'dead'::"text"])))
);




COMMENT ON TABLE "public"."prospects" IS 'Permanent prospect database. Full dossier per prospect — identity, contact, gatekeeper intel, intelligence, call tracking.';



COMMENT ON COLUMN "public"."prospects"."lead_score" IS 'Deterministic 0-100 score computed from structured fields: budget, events, luxury indicators, contact info quality.';



COMMENT ON COLUMN "public"."prospects"."verified" IS 'Whether a web search confirmed this prospect actually exists.';



COMMENT ON COLUMN "public"."prospects"."draft_email" IS 'AI-drafted personalized cold outreach email. Chef reviews and edits before sending.';



COMMENT ON COLUMN "public"."prospects"."news_intel" IS 'Recent news, press, or public events about this prospect gathered during enrichment.';



COMMENT ON COLUMN "public"."prospects"."last_enriched_at" IS 'Timestamp of last web enrichment. NULL = never enriched. Used for staleness detection.';



COMMENT ON COLUMN "public"."prospects"."enrichment_sources" IS 'URLs of pages scraped during enrichment for audit trail.';



COMMENT ON COLUMN "public"."prospects"."event_signals" IS 'Upcoming events detected from the prospect website calendar/events page. Used for outreach timing.';



COMMENT ON COLUMN "public"."prospects"."scrub_type" IS 'How this prospect was generated: standard AI scrub, competitor intelligence, or lookalike expansion.';



COMMENT ON COLUMN "public"."prospects"."lookalike_source_id" IS 'For lookalike scrubs, the prospect this one was modeled after.';



