COMMENT ON TABLE "public"."push_subscriptions" IS 'Web Push API subscription endpoints per user per device. One user may have multiple active subscriptions.';



COMMENT ON COLUMN "public"."push_subscriptions"."endpoint" IS 'Push service URL. Unique identifier for a subscription.';



COMMENT ON COLUMN "public"."push_subscriptions"."p256dh" IS 'Client public key for payload encryption (RFC 8291).';



COMMENT ON COLUMN "public"."push_subscriptions"."auth_key" IS 'Auth secret for payload encryption (RFC 8291).';



COMMENT ON COLUMN "public"."push_subscriptions"."failed_count" IS 'Delivery failure count. Subscription deactivated when >= 5 or on 410 Gone.';



