    "reason" "text",
    "metadata" "jsonb"
);




COMMENT ON TABLE "public"."quote_state_transitions" IS 'Immutable audit trail of quote state changes';



CREATE TABLE IF NOT EXISTS "public"."quotes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "inquiry_id" "uuid",
    "event_id" "uuid",
    "client_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "quote_name" "text",
    "pricing_model" "public"."pricing_model" DEFAULT 'per_person'::"public"."pricing_model" NOT NULL,
    "price_per_person_cents" integer,
    "guest_count_estimated" integer,
    "total_quoted_cents" integer NOT NULL,
    "deposit_required" boolean DEFAULT false NOT NULL,
    "deposit_amount_cents" integer,
    "deposit_percentage" integer,
    "pricing_notes" "text",
    "internal_notes" "text",
    "status" "public"."quote_status" DEFAULT 'draft'::"public"."quote_status" NOT NULL,
    "sent_at" timestamp with time zone,
    "accepted_at" timestamp with time zone,
    "rejected_at" timestamp with time zone,
    "rejected_reason" "text",
    "expired_at" timestamp with time zone,
    "valid_until" "date",
    "pricing_snapshot" "jsonb",
    "snapshot_frozen" boolean DEFAULT false NOT NULL,
    "created_by" "uuid",
    "updated_by" "uuid",
    "expiry_warning_sent_at" timestamp with time zone,
    "negotiation_occurred" boolean DEFAULT false NOT NULL,
    "original_quoted_cents" integer,
    "version" integer DEFAULT 1 NOT NULL,
    "previous_version_id" "uuid",
    "is_superseded" boolean DEFAULT false NOT NULL,
    "lost_reason" "text",
    "lost_notes" "text",
    "lost_recorded_at" timestamp with time zone,
    "deleted_at" timestamp with time zone,
    "deleted_by" "uuid",
    "show_cost_breakdown" boolean DEFAULT false NOT NULL,
    "exclusions_note" "text",
    "addon_total_cents" integer DEFAULT 0,
    "effective_total_cents" integer,
    "cover_photo_url" "text",
    "chef_message" "text",
    CONSTRAINT "quotes_deposit_lte_total" CHECK ((("deposit_amount_cents" <= "total_quoted_cents") OR ("deposit_amount_cents" IS NULL))),
    CONSTRAINT "quotes_deposit_non_negative" CHECK ((("deposit_amount_cents" >= 0) OR ("deposit_amount_cents" IS NULL))),
    CONSTRAINT "quotes_deposit_pct_valid" CHECK (((("deposit_percentage" >= 0) AND ("deposit_percentage" <= 100)) OR ("deposit_percentage" IS NULL))),
    CONSTRAINT "quotes_guest_count_positive" CHECK ((("guest_count_estimated" > 0) OR ("guest_count_estimated" IS NULL))),
    CONSTRAINT "quotes_lost_reason_check" CHECK (("lost_reason" = ANY (ARRAY['price_too_high'::"text", 'chose_another_chef'::"text", 'date_not_available'::"text", 'cuisine_not_right_fit'::"text", 'client_lost_interest'::"text", 'other'::"text"]))),
    CONSTRAINT "quotes_must_link_inquiry_or_event" CHECK ((("inquiry_id" IS NOT NULL) OR ("event_id" IS NOT NULL))),
    CONSTRAINT "quotes_original_quoted_cents_check" CHECK (("original_quoted_cents" > 0)),
    CONSTRAINT "quotes_ppp_positive" CHECK ((("price_per_person_cents" > 0) OR ("price_per_person_cents" IS NULL))),
    CONSTRAINT "quotes_total_positive" CHECK (("total_quoted_cents" > 0))
);




COMMENT ON TABLE "public"."quotes" IS 'Pricing proposals linked to inquiry and/or event';



COMMENT ON COLUMN "public"."quotes"."pricing_snapshot" IS 'Frozen pricing at acceptance - IMMUTABLE after status = accepted';



COMMENT ON COLUMN "public"."quotes"."expiry_warning_sent_at" IS 'When the 48-hour expiry warning email was sent to the client. NULL = not yet sent.';



COMMENT ON COLUMN "public"."quotes"."negotiation_occurred" IS 'True if the quoted price was revised downward after the initial quote. Set manually when chef adjusts price on client request.';



COMMENT ON COLUMN "public"."quotes"."original_quoted_cents" IS 'The original quoted price before any negotiation. Populated when negotiation_occurred = true. Used to compute average discount %.';



COMMENT ON COLUMN "public"."quotes"."version" IS 'Version number for this quote. Starts at 1, increments when the chef creates a revision.';



COMMENT ON COLUMN "public"."quotes"."previous_version_id" IS 'Points to the quote this version supersedes. NULL means first version or standalone.';



COMMENT ON COLUMN "public"."quotes"."is_superseded" IS 'TRUE when a newer version of this quote has been created. Superseded quotes are read-only.';



COMMENT ON COLUMN "public"."quotes"."effective_total_cents" IS 'Base quote total + selected addon total, set at acceptance time.';



COMMENT ON COLUMN "public"."quotes"."cover_photo_url" IS 'Cover photo URL for the interactive proposal hero section.';



COMMENT ON COLUMN "public"."quotes"."chef_message" IS 'Personal message from the chef displayed on the proposal.';



CREATE TABLE IF NOT EXISTS "public"."raffle_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "round_id" "uuid" NOT NULL,
