    "winner_client_id" "uuid",
    "winner_alias" "text",
    "draw_seed" "text",
    "drawn_at" timestamp with time zone,
    "prize_delivered" boolean DEFAULT false NOT NULL,
    "prize_delivered_at" timestamp with time zone,
    "total_entries_at_draw" integer,
    "total_participants_at_draw" integer,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    "winner_entry_id" "uuid",
    "prize_random_draw" "text",
    "prize_top_scorer" "text",
    "prize_most_dedicated" "text",
    "top_scorer_client_id" "uuid",
    "top_scorer_alias" "text",
    "top_scorer_entry_id" "uuid",
    "top_scorer_score" integer,
    "most_dedicated_client_id" "uuid",
    "most_dedicated_alias" "text",
    "most_dedicated_entry_count" integer,
