    CONSTRAINT "raffle_rounds_month_order" CHECK (("month_start" < "month_end"))
);




COMMENT ON TABLE "public"."raffle_rounds" IS 'Monthly raffle rounds. Chef defines a prize, clients earn entries via games, automated drawing selects winner.';



COMMENT ON COLUMN "public"."raffle_rounds"."prize_random_draw" IS 'Prize for random draw winner (main raffle)';



COMMENT ON COLUMN "public"."raffle_rounds"."prize_top_scorer" IS 'Prize for highest game score of the month. NULL = category disabled.';



COMMENT ON COLUMN "public"."raffle_rounds"."prize_most_dedicated" IS 'Prize for most days played. NULL = category disabled.';



COMMENT ON COLUMN "public"."raffle_rounds"."top_scorer_client_id" IS 'Client who achieved the highest single game score this round.';



COMMENT ON COLUMN "public"."raffle_rounds"."most_dedicated_client_id" IS 'Client who played on the most distinct days this round.';



CREATE TABLE IF NOT EXISTS "public"."rebook_tokens" (
