    "used_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."rebook_tokens" IS 'Single-use public rebook links for completed events.';



COMMENT ON COLUMN "public"."rebook_tokens"."token" IS 'Opaque token embedded in /rebook/[token] QR links.';



CREATE TABLE IF NOT EXISTS "public"."receipt_extractions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "receipt_photo_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "store_name" "text",
    "store_location" "text",
    "purchase_date" "date",
    "payment_method" "text",
    "subtotal_cents" integer,
    "tax_cents" integer,
    "total_cents" integer,
    "extraction_confidence" numeric(3,2),
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "receipt_extractions_confidence_range" CHECK ((("extraction_confidence" IS NULL) OR (("extraction_confidence" >= (0)::numeric) AND ("extraction_confidence" <= (1)::numeric)))),
    CONSTRAINT "receipt_extractions_subtotal_non_neg" CHECK ((("subtotal_cents" IS NULL) OR ("subtotal_cents" >= 0))),
    CONSTRAINT "receipt_extractions_tax_non_neg" CHECK ((("tax_cents" IS NULL) OR ("tax_cents" >= 0))),
    CONSTRAINT "receipt_extractions_total_non_neg" CHECK ((("total_cents" IS NULL) OR ("total_cents" >= 0)))
);




COMMENT ON TABLE "public"."receipt_extractions" IS 'Structured header data extracted from a receipt photo. One per photo.';



CREATE TABLE IF NOT EXISTS "public"."receipt_line_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "receipt_extraction_id" "uuid" NOT NULL,
    "event_id" "uuid",
    "tenant_id" "uuid" NOT NULL,
    "description" "text" NOT NULL,
    "price_cents" integer,
    "expense_tag" "text" DEFAULT 'business'::"text" NOT NULL,
    "ingredient_category" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "receipt_line_items_expense_tag_check" CHECK (("expense_tag" = ANY (ARRAY['business'::"text", 'personal'::"text", 'unknown'::"text"]))),
    CONSTRAINT "receipt_line_items_price_non_neg" CHECK ((("price_cents" IS NULL) OR ("price_cents" >= 0)))
);




COMMENT ON TABLE "public"."receipt_line_items" IS 'Individual line items from a receipt. Business items are copied to expenses on approval.';



CREATE TABLE IF NOT EXISTS "public"."receipt_photos" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_id" "uuid",
    "tenant_id" "uuid" NOT NULL,
    "photo_url" "text" NOT NULL,
    "ocr_raw" "text",
    "upload_status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "approved_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "client_id" "uuid",
    "storage_path" "text",
    "notes" "text",
    CONSTRAINT "receipt_photos_upload_status_check" CHECK (("upload_status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'extracted'::"text", 'approved'::"text"])))
);




COMMENT ON TABLE "public"."receipt_photos" IS 'One record per uploaded receipt image. upload_status tracks the OCR pipeline state.';



COMMENT ON COLUMN "public"."receipt_photos"."event_id" IS 'Optional — null for standalone receipts not tied to a specific event.';



COMMENT ON COLUMN "public"."receipt_photos"."client_id" IS 'Optional — direct client link without requiring an event.';



COMMENT ON COLUMN "public"."receipt_photos"."storage_path" IS 'Raw Supabase Storage path for URL regeneration. Null on legacy records.';



COMMENT ON COLUMN "public"."receipt_photos"."notes" IS 'Optional context note, e.g. "Annual equipment purchase" for standalone receipts.';



CREATE TABLE IF NOT EXISTS "public"."recipe_nutrition" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "recipe_id" "uuid" NOT NULL,
    "calories" integer DEFAULT 0 NOT NULL,
    "protein_g" numeric(6,1) DEFAULT 0 NOT NULL,
    "carbs_g" numeric(6,1) DEFAULT 0 NOT NULL,
    "fat_g" numeric(6,1) DEFAULT 0 NOT NULL,
    "fiber_g" numeric(6,1),
    "sodium_mg" numeric(8,1),
    "source" "text" DEFAULT 'manual'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "recipe_nutrition_source_check" CHECK (("source" = ANY (ARRAY['manual'::"text", 'calculated'::"text", 'imported'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."recipe_production_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "recipe_id" "uuid" NOT NULL,
    "produced_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "produced_by" "text",
    "quantity" numeric(10,3) NOT NULL,
    "unit" "text" DEFAULT 'servings'::"text" NOT NULL,
    "best_before" timestamp with time zone,
    "discard_at" timestamp with time zone,
    "batch_notes" "text",
    "event_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."recipe_production_log" IS 'Tracks every production run of a recipe — who made it, quantity, shelf life, notes';



CREATE TABLE IF NOT EXISTS "public"."recipe_shares" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "original_recipe_id" "uuid" NOT NULL,
    "from_chef_id" "uuid" NOT NULL,
    "to_chef_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "note" "text",
    "created_recipe_id" "uuid",
    "responded_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "no_self_share" CHECK (("from_chef_id" <> "to_chef_id")),
    CONSTRAINT "recipe_shares_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'accepted'::"text", 'declined'::"text"])))
);




COMMENT ON TABLE "public"."recipe_shares" IS 'Tracks chef-to-chef recipe sharing. When accepted, a deep copy is created in the receiving chef''s namespace. The original is never modified.';



COMMENT ON COLUMN "public"."recipe_shares"."created_recipe_id" IS 'UUID of the copy created when the share was accepted. NULL until accepted.';



CREATE TABLE IF NOT EXISTS "public"."recipe_step_photos" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "recipe_id" "uuid" NOT NULL,
    "step_number" integer NOT NULL,
    "photo_url" "text" NOT NULL,
    "caption" "text",
    "sort_order" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."recurring_invoice_history" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "schedule_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "invoice_number" "text" NOT NULL,
    "amount_cents" integer NOT NULL,
    "period_start" "date" NOT NULL,
    "period_end" "date" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "paid_at" timestamp with time zone,
    "stripe_payment_intent_id" "text",
    "ledger_entry_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "recurring_invoice_history_amount_cents_check" CHECK (("amount_cents" >= 0)),
    CONSTRAINT "recurring_invoice_history_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'sent'::"text", 'paid'::"text", 'overdue'::"text", 'cancelled'::"text"])))
);




COMMENT ON TABLE "public"."recurring_invoice_history" IS 'Individual invoice instances generated from recurring schedules. Each row = one billing period.';



CREATE TABLE IF NOT EXISTS "public"."recurring_invoices" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "frequency" "text" DEFAULT 'monthly'::"text" NOT NULL,
    "amount_cents" integer NOT NULL,
    "description" "text",
    "next_send_date" "date",
    "last_sent_at" timestamp with time zone,
    "is_active" boolean DEFAULT true NOT NULL,
    "late_fee_cents" integer DEFAULT 0 NOT NULL,
    "late_fee_days" integer DEFAULT 30 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "name" "text",
    "day_of_week" integer,
    "day_of_month" integer,
    "start_date" "date",
    "end_date" "date",
    "is_autopay" boolean DEFAULT false NOT NULL,
    "stripe_payment_method_id" "text",
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    CONSTRAINT "recurring_invoices_amount_cents_check" CHECK (("amount_cents" >= 0)),
    CONSTRAINT "recurring_invoices_day_of_month_check" CHECK ((("day_of_month" IS NULL) OR (("day_of_month" >= 1) AND ("day_of_month" <= 28)))),
    CONSTRAINT "recurring_invoices_day_of_week_check" CHECK ((("day_of_week" IS NULL) OR (("day_of_week" >= 0) AND ("day_of_week" <= 6)))),
    CONSTRAINT "recurring_invoices_frequency_check" CHECK (("frequency" = ANY (ARRAY['weekly'::"text", 'biweekly'::"text", 'monthly'::"text", 'quarterly'::"text"]))),
    CONSTRAINT "recurring_invoices_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'paused'::"text", 'cancelled'::"text"])))
);




COMMENT ON COLUMN "public"."recurring_invoices"."name" IS 'Human-readable label for this recurring billing schedule';



COMMENT ON COLUMN "public"."recurring_invoices"."day_of_week" IS '0=Sunday through 6=Saturday. Used for weekly/biweekly schedules';



COMMENT ON COLUMN "public"."recurring_invoices"."day_of_month" IS '1-28 for monthly schedules. Capped at 28 to avoid month-length issues';



COMMENT ON COLUMN "public"."recurring_invoices"."is_autopay" IS 'If true, automatically charges saved payment method on invoice date';



COMMENT ON COLUMN "public"."recurring_invoices"."stripe_payment_method_id" IS 'Saved Stripe PaymentMethod ID for autopay charges';



COMMENT ON COLUMN "public"."recurring_invoices"."status" IS 'Lifecycle status: active, paused, or cancelled';



CREATE TABLE IF NOT EXISTS "public"."recurring_menu_recommendations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "week_start" "date",
    "recommendation_text" "text" NOT NULL,
    "status" "text" DEFAULT 'sent'::"text" NOT NULL,
    "client_response_notes" "text",
    "sent_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "responded_at" timestamp with time zone,
    "sent_by" "uuid",
    "responded_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "recurring_menu_recommendations_status_check" CHECK (("status" = ANY (ARRAY['sent'::"text", 'approved'::"text", 'revision_requested'::"text"])))
);




COMMENT ON TABLE "public"."recurring_menu_recommendations" IS 'Chef weekly recommendation drafts sent to recurring clients, with client approval/revision status.';



CREATE TABLE IF NOT EXISTS "public"."recurring_schedules" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "frequency" "text" NOT NULL,
    "day_of_week" integer,
    "preferred_time" "text",
    "menu_id" "uuid",
    "guest_count" integer DEFAULT 2,
    "notes" "text",
    "is_active" boolean DEFAULT true,
    "next_occurrence" "date",
    "last_generated_date" "date",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "created_by" "uuid",
    CONSTRAINT "recurring_schedules_day_of_week_check" CHECK ((("day_of_week" >= 0) AND ("day_of_week" <= 6))),
    CONSTRAINT "recurring_schedules_frequency_check" CHECK (("frequency" = ANY (ARRAY['weekly'::"text", 'biweekly'::"text", 'monthly'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."recurring_services" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "service_type" "text" DEFAULT 'weekly_meal_prep'::"text" NOT NULL,
    "frequency" "text" DEFAULT 'weekly'::"text" NOT NULL,
    "day_of_week" "jsonb",
    "typical_guest_count" integer,
    "rate_cents" integer NOT NULL,
    "start_date" "date" NOT NULL,
    "end_date" "date",
    "notes" "text",
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "recurring_services_frequency_check" CHECK (("frequency" = ANY (ARRAY['weekly'::"text", 'biweekly'::"text", 'monthly'::"text"]))),
    CONSTRAINT "recurring_services_rate_cents_check" CHECK (("rate_cents" >= 0)),
    CONSTRAINT "recurring_services_service_type_check" CHECK (("service_type" = ANY (ARRAY['weekly_meal_prep'::"text", 'weekly_dinners'::"text", 'daily_meals'::"text", 'biweekly_prep'::"text", 'other'::"text"]))),
    CONSTRAINT "recurring_services_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'paused'::"text", 'ended'::"text"])))
);




COMMENT ON TABLE "public"."recurring_services" IS 'Ongoing service arrangements with clients (weekly meal prep, standing dinners, etc.)';



CREATE TABLE IF NOT EXISTS "public"."referral_partners" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "partner_type" "public"."partner_type" DEFAULT 'individual'::"public"."partner_type" NOT NULL,
    "status" "public"."partner_status" DEFAULT 'active'::"public"."partner_status" NOT NULL,
    "contact_name" "text",
    "email" "text",
    "phone" "text",
    "website" "text",
    "booking_url" "text",
    "description" "text",
    "cover_image_url" "text",
    "is_showcase_visible" boolean DEFAULT false NOT NULL,
    "showcase_order" integer DEFAULT 0,
    "notes" "text",
    "commission_notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "share_token" "uuid",
    "auth_user_id" "uuid",
    "invite_token" "uuid",
    "invite_sent_at" timestamp with time zone,
    "claimed_at" timestamp with time zone,
    "origin_client_id" "uuid",
    "origin_event_id" "uuid",
    "acquisition_source" "text" DEFAULT 'organic'::"text"
);




COMMENT ON TABLE "public"."referral_partners" IS 'Referral partners (Airbnb hosts, hotels, businesses, platforms, individuals). Each partner is scoped to a chef tenant. Tracks both internal analytics and public showcase data.';



COMMENT ON COLUMN "public"."referral_partners"."booking_url" IS 'External booking link shown on public showcase (e.g., Airbnb listing URL)';



COMMENT ON COLUMN "public"."referral_partners"."is_showcase_visible" IS 'When true, partner appears on chef public profile showcase. When false, only visible internally.';



COMMENT ON COLUMN "public"."referral_partners"."notes" IS 'Internal relationship notes — never exposed publicly';



COMMENT ON COLUMN "public"."referral_partners"."commission_notes" IS 'Internal notes about referral arrangements — never exposed publicly';



COMMENT ON COLUMN "public"."referral_partners"."share_token" IS 'Public share token for the partner contribution report. Generated on demand by the chef. When set, anyone with the URL can view a read-only report of services delivered at this partner''s location(s).';



COMMENT ON COLUMN "public"."referral_partners"."auth_user_id" IS 'Supabase auth user ID — set when partner claims their invite';



COMMENT ON COLUMN "public"."referral_partners"."invite_token" IS 'One-time UUID token for the partner signup link; cleared after claim';



COMMENT ON COLUMN "public"."referral_partners"."claimed_at" IS 'Timestamp when the partner signed up and linked their account';



COMMENT ON COLUMN "public"."referral_partners"."origin_client_id" IS 'The client whose booking first connected this host to the chef';



COMMENT ON COLUMN "public"."referral_partners"."origin_event_id" IS 'The specific event that led to this host becoming a partner';



COMMENT ON COLUMN "public"."referral_partners"."acquisition_source" IS 'How the partnership was established: client_event_referral | direct_outreach | organic';



CREATE TABLE IF NOT EXISTS "public"."referral_request_log" (
