    "reviewed_by_admin" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "remy_abuse_log_severity_check" CHECK (("severity" = ANY (ARRAY['warning'::"text", 'critical'::"text", 'blocked'::"text"])))
);




COMMENT ON TABLE "public"."remy_abuse_log" IS 'Audit trail for Remy guardrail violations. Admin can review flagged incidents.';



CREATE TABLE IF NOT EXISTS "public"."remy_action_audit_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
