    "result_payload" "jsonb",
    "error_message" "text",
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "finished_at" timestamp with time zone,
    "duration_ms" integer,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "remy_action_audit_log_duration_ms_check" CHECK ((("duration_ms" IS NULL) OR ("duration_ms" >= 0))),
    CONSTRAINT "remy_action_audit_log_status_check" CHECK (("status" = ANY (ARRAY['started'::"text", 'success'::"text", 'error'::"text", 'blocked'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."remy_approval_policies" (
