CREATE TABLE IF NOT EXISTS "public"."response_templates" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "category" "text",
    "template_text" "text" NOT NULL,
    "is_active" boolean DEFAULT true,
    "usage_count" integer DEFAULT 0,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "subject" "text" DEFAULT ''::"text" NOT NULL,
    "merge_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL
);




COMMENT ON TABLE "public"."response_templates" IS 'Pre-drafted responses in chef voice. Require chef approval before sending.';



COMMENT ON COLUMN "public"."response_templates"."usage_count" IS 'Incremented each time template is used';



CREATE TABLE IF NOT EXISTS "public"."retainer_periods" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "retainer_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "period_start" "date" NOT NULL,
    "period_end" "date" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "amount_cents" integer NOT NULL,
    "events_used" integer DEFAULT 0 NOT NULL,
    "hours_used" numeric(8,2) DEFAULT 0 NOT NULL,
    "stripe_invoice_id" "text",
    "ledger_entry_id" "uuid",
    "paid_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "period_dates_valid" CHECK (("period_end" > "period_start")),
    CONSTRAINT "retainer_periods_amount_cents_check" CHECK (("amount_cents" >= 0)),
    CONSTRAINT "retainer_periods_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'paid'::"text", 'overdue'::"text", 'void'::"text"])))
);




COMMENT ON TABLE "public"."retainer_periods" IS 'Individual billing periods within a retainer agreement. status tracks payment; usage tracks events/hours consumed.';



CREATE TABLE IF NOT EXISTS "public"."retainers" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "client_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "billing_cycle" "text" DEFAULT 'monthly'::"text" NOT NULL,
    "amount_cents" integer NOT NULL,
    "includes_events_count" integer,
    "includes_hours" numeric(8,2),
    "start_date" "date" NOT NULL,
    "end_date" "date",
    "next_billing_date" "date",
    "stripe_subscription_id" "text",
    "stripe_price_id" "text",
    "notes" "text",
    "terms_summary" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "retainers_amount_cents_check" CHECK (("amount_cents" >= 0)),
    CONSTRAINT "retainers_billing_cycle_check" CHECK (("billing_cycle" = ANY (ARRAY['weekly'::"text", 'biweekly'::"text", 'monthly'::"text"]))),
    CONSTRAINT "retainers_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'active'::"text", 'paused'::"text", 'cancelled'::"text", 'completed'::"text"])))
);




COMMENT ON TABLE "public"."retainers" IS 'Recurring service agreements between chef and client. Financial truth lives in ledger_entries.';



CREATE TABLE IF NOT EXISTS "public"."retirement_contributions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "tax_year" integer NOT NULL,
    "account_type" "text" NOT NULL,
    "contribution_cents" integer NOT NULL,
    "contributed_at" "date",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "retirement_contributions_account_type_check" CHECK (("account_type" = ANY (ARRAY['sep_ira'::"text", 'solo_401k'::"text", 'simple_ira'::"text", 'traditional_ira'::"text"]))),
    CONSTRAINT "retirement_contributions_contribution_cents_check" CHECK (("contribution_cents" >= 0))
);




COMMENT ON TABLE "public"."retirement_contributions" IS 'Tracks self-employment retirement contributions per chef per tax year. Above-the-line deductions (Schedule 1).';



CREATE TABLE IF NOT EXISTS "public"."rsvp_reminder_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "event_id" "uuid" NOT NULL,
    "guest_id" "uuid" NOT NULL,
    "reminder_key" "text" NOT NULL,
    "delivery_channel" "text" DEFAULT 'draft'::"text" NOT NULL,
    "recipient_email" "text",
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."sale_applied_promotions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "sale_id" "uuid" NOT NULL,
    "promotion_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "code" "text" NOT NULL,
    "name" "text" NOT NULL,
    "discount_type" "public"."commerce_promotion_discount_type" NOT NULL,
    "discount_cents" integer NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    CONSTRAINT "sale_applied_promotions_discount_cents_check" CHECK (("discount_cents" > 0))
);




COMMENT ON TABLE "public"."sale_applied_promotions" IS 'Immutable snapshot of promotions applied to each sale.';



CREATE TABLE IF NOT EXISTS "public"."sale_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "sale_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "product_projection_id" "uuid",
    "name" "text" NOT NULL,
    "description" "text",
    "sku" "text",
    "category" "text",
    "unit_price_cents" integer NOT NULL,
    "quantity" integer DEFAULT 1 NOT NULL,
    "discount_cents" integer DEFAULT 0 NOT NULL,
    "line_total_cents" integer NOT NULL,
    "tax_class" "public"."tax_class" DEFAULT 'standard'::"public"."tax_class" NOT NULL,
    "tax_cents" integer DEFAULT 0 NOT NULL,
    "modifiers_applied" "jsonb" DEFAULT '[]'::"jsonb",
    "unit_cost_cents" integer,
    "inventory_deducted" boolean DEFAULT false NOT NULL,
    "sort_order" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "sale_items_discount_cents_check" CHECK (("discount_cents" >= 0)),
    CONSTRAINT "sale_items_quantity_check" CHECK (("quantity" > 0)),
    CONSTRAINT "sale_items_tax_cents_check" CHECK (("tax_cents" >= 0)),
    CONSTRAINT "sale_items_unit_price_cents_check" CHECK (("unit_price_cents" >= 0))
);




COMMENT ON TABLE "public"."sale_items" IS 'Line items on a sale. Frozen snapshot of product at time of sale.';



CREATE TABLE IF NOT EXISTS "public"."sales" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "event_id" "uuid",
    "client_id" "uuid",
    "sale_number" "text",
    "status" "public"."sale_status" DEFAULT 'draft'::"public"."sale_status" NOT NULL,
    "channel" "public"."sale_channel" DEFAULT 'counter'::"public"."sale_channel" NOT NULL,
    "register_session_id" "uuid",
    "subtotal_cents" integer DEFAULT 0 NOT NULL,
    "discount_cents" integer DEFAULT 0 NOT NULL,
    "tax_cents" integer DEFAULT 0 NOT NULL,
    "total_cents" integer DEFAULT 0 NOT NULL,
    "tip_cents" integer DEFAULT 0 NOT NULL,
    "tax_zip_code" "text",
    "tax_rate" numeric(8,6),
    "currency" "text" DEFAULT 'usd'::"text" NOT NULL,
    "voided_at" timestamp with time zone,
    "voided_by" "uuid",
    "void_reason" "text",
    "notes" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    "location_id" "uuid",
    CONSTRAINT "sales_discount_cents_check" CHECK (("discount_cents" >= 0)),
    CONSTRAINT "sales_tax_cents_check" CHECK (("tax_cents" >= 0)),
    CONSTRAINT "sales_tip_cents_check" CHECK (("tip_cents" >= 0)),
    CONSTRAINT "sales_total_cents_check" CHECK (("total_cents" >= 0))
);




COMMENT ON TABLE "public"."sales" IS 'Universal revenue container. Bridges to events via optional event_id.';



CREATE OR REPLACE VIEW "public"."sale_financial_summary" AS
 SELECT "s"."id" AS "sale_id",
    "s"."tenant_id",
    "s"."sale_number",
    "s"."status",
    "s"."channel",
    "s"."total_cents",
    "s"."tax_cents",
    "s"."tip_cents",
    "s"."discount_cents",
    "s"."subtotal_cents",
    COALESCE("pay"."total_paid_cents", (0)::bigint) AS "total_paid_cents",
    COALESCE("pay"."total_tips_cents", (0)::bigint) AS "total_tips_cents",
    COALESCE("ref"."total_refunded_cents", (0)::bigint) AS "total_refunded_cents",
    (("s"."total_cents" - COALESCE("pay"."total_paid_cents", (0)::bigint)) + COALESCE("ref"."total_refunded_cents", (0)::bigint)) AS "balance_due_cents",
    COALESCE("cost"."total_cost_cents", (0)::bigint) AS "total_cost_cents",
    ("s"."total_cents" - COALESCE("cost"."total_cost_cents", (0)::bigint)) AS "gross_profit_cents",
    "s"."created_at",
    "s"."event_id",
    "s"."client_id"
   FROM ((("public"."sales" "s"
     LEFT JOIN LATERAL ( SELECT "sum"("commerce_payments"."amount_cents") FILTER (WHERE ("commerce_payments"."status" = ANY (ARRAY['captured'::"public"."commerce_payment_status", 'settled'::"public"."commerce_payment_status"]))) AS "total_paid_cents",
            "sum"("commerce_payments"."tip_cents") FILTER (WHERE ("commerce_payments"."status" = ANY (ARRAY['captured'::"public"."commerce_payment_status", 'settled'::"public"."commerce_payment_status"]))) AS "total_tips_cents"
           FROM "public"."commerce_payments"
          WHERE ("commerce_payments"."sale_id" = "s"."id")) "pay" ON (true))
     LEFT JOIN LATERAL ( SELECT "sum"("commerce_refunds"."amount_cents") FILTER (WHERE ("commerce_refunds"."status" = 'processed'::"public"."refund_status")) AS "total_refunded_cents"
           FROM "public"."commerce_refunds"
          WHERE ("commerce_refunds"."sale_id" = "s"."id")) "ref" ON (true))
     LEFT JOIN LATERAL ( SELECT "sum"(("sale_items"."unit_cost_cents" * "sale_items"."quantity")) AS "total_cost_cents"
           FROM "public"."sale_items"
          WHERE (("sale_items"."sale_id" = "s"."id") AND ("sale_items"."unit_cost_cents" IS NOT NULL))) "cost" ON (true));




COMMENT ON VIEW "public"."sale_financial_summary" IS 'Per-sale financial summary derived from commerce_payments and commerce_refunds.';



CREATE TABLE IF NOT EXISTS "public"."sales_tax_remittances" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "period" "text" NOT NULL,
    "period_start" "date" NOT NULL,
    "period_end" "date" NOT NULL,
    "amount_remitted_cents" integer NOT NULL,
    "remitted_at" "date" NOT NULL,
    "confirmation_number" "text",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "sales_tax_remittances_amount_remitted_cents_check" CHECK (("amount_remitted_cents" >= 0))
);




CREATE TABLE IF NOT EXISTS "public"."sales_tax_settings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "enabled" boolean DEFAULT false NOT NULL,
    "state" "text",
    "state_rate_bps" integer DEFAULT 0 NOT NULL,
    "local_rate_bps" integer DEFAULT 0 NOT NULL,
    "registration_number" "text",
    "filing_frequency" "text" DEFAULT 'quarterly'::"text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "sales_tax_settings_filing_frequency_check" CHECK (("filing_frequency" = ANY (ARRAY['monthly'::"text", 'quarterly'::"text", 'annually'::"text"]))),
    CONSTRAINT "sales_tax_settings_local_rate_bps_check" CHECK ((("local_rate_bps" >= 0) AND ("local_rate_bps" <= 10000))),
    CONSTRAINT "sales_tax_settings_state_rate_bps_check" CHECK ((("state_rate_bps" >= 0) AND ("state_rate_bps" <= 10000)))
);




COMMENT ON COLUMN "public"."sales_tax_settings"."state_rate_bps" IS 'State sales tax rate in basis points. 625 bps = 6.25%.';



COMMENT ON COLUMN "public"."sales_tax_settings"."local_rate_bps" IS 'Local/county sales tax rate in basis points. Add to state_rate_bps for combined rate.';



CREATE TABLE IF NOT EXISTS "public"."scheduled_calls" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
