    "client_id" "uuid",
    "contact_name" "text",
    "contact_phone" "text",
    "contact_company" "text",
    "call_type" "text" NOT NULL,
    "inquiry_id" "uuid",
    "event_id" "uuid",
    "scheduled_at" timestamp with time zone NOT NULL,
    "duration_minutes" integer DEFAULT 30 NOT NULL,
    "timezone" "text" DEFAULT 'America/New_York'::"text" NOT NULL,
    "title" "text",
    "status" "text" DEFAULT 'scheduled'::"text" NOT NULL,
    "agenda_items" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "prep_notes" "text",
    "outcome_summary" "text",
    "call_notes" "text",
    "next_action" "text",
    "next_action_due_at" timestamp with time zone,
    "actual_duration_minutes" integer,
    "notify_client" boolean DEFAULT false NOT NULL,
    "client_notified_at" timestamp with time zone,
    "reminder_24h_sent_at" timestamp with time zone,
    "reminder_1h_sent_at" timestamp with time zone,
