    "end_month_day" "text" NOT NULL,
    "sensory_anchor" "text",
    "micro_windows" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "context_profiles" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "pantry_and_preserve" "text",
    "chef_energy_reality" "text",
    "proven_wins" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
