);




COMMENT ON TABLE "public"."seasonal_palettes" IS 'Seasonal definition engine — one palette per season per chef.';



COMMENT ON COLUMN "public"."seasonal_palettes"."micro_windows" IS 'Array: [{name, ingredient, start_date (MM-DD), end_date (MM-DD), urgency (high|normal), notes}]';



COMMENT ON COLUMN "public"."seasonal_palettes"."context_profiles" IS 'Array: [{name, kitchen_reality, menu_guardrails, notes}]';



COMMENT ON COLUMN "public"."seasonal_palettes"."proven_wins" IS 'Array: [{dish_name, notes, recipe_id (nullable)}]';



