    CONSTRAINT "sms_messages_message_type_check" CHECK (("message_type" = ANY (ARRAY['order_ready'::"text", 'table_ready'::"text", 'delivery_eta'::"text", 'reservation_confirm'::"text", 'reservation_remind'::"text", 'feedback_request'::"text", 'custom'::"text"]))),
    CONSTRAINT "sms_messages_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'sent'::"text", 'delivered'::"text", 'failed'::"text"])))
