);




COMMENT ON TABLE "public"."sms_send_log" IS 'Rate-limit audit log for SMS notifications. Queried before every SMS send to prevent flooding.';



CREATE TABLE IF NOT EXISTS "public"."social_connected_accounts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "platform" "text" NOT NULL,
    "access_token" "text" NOT NULL,
    "refresh_token" "text",
    "token_expires_at" timestamp with time zone,
    "granted_scopes" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "platform_account_id" "text" NOT NULL,
    "platform_account_name" "text",
    "platform_account_handle" "text",
    "platform_account_type" "text",
    "platform_account_avatar" "text",
    "meta_page_id" "text",
    "meta_page_name" "text",
    "meta_ig_account_id" "text",
    "is_active" boolean DEFAULT true NOT NULL,
    "last_used_at" timestamp with time zone,
    "last_error" "text",
    "error_count" integer DEFAULT 0 NOT NULL,
    "connected_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "last_refreshed_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "social_connected_accounts_platform_check" CHECK (("platform" = ANY (ARRAY['instagram'::"text", 'facebook'::"text", 'tiktok'::"text", 'linkedin'::"text", 'x'::"text", 'pinterest'::"text", 'youtube_shorts'::"text"])))
);




COMMENT ON TABLE "public"."social_connected_accounts" IS 'Stores OAuth credentials and account metadata for each social platform a chef has connected. Tokens are never sent to the browser.';



COMMENT ON COLUMN "public"."social_connected_accounts"."access_token" IS 'OAuth access token. Server-side only — never serialised to client.';



COMMENT ON COLUMN "public"."social_connected_accounts"."refresh_token" IS 'OAuth refresh token if issued by platform. Server-side only.';



COMMENT ON COLUMN "public"."social_connected_accounts"."token_expires_at" IS 'UTC timestamp when access_token expires. Null = non-expiring (rare).';



COMMENT ON COLUMN "public"."social_connected_accounts"."granted_scopes" IS 'Scopes the user actually granted. May be a subset of requested scopes.';



COMMENT ON COLUMN "public"."social_connected_accounts"."platform_account_id" IS 'Opaque platform user or page ID. Used to identify the account when calling APIs.';



COMMENT ON COLUMN "public"."social_connected_accounts"."meta_ig_account_id" IS 'Instagram Business Account ID linked to the chosen Facebook Page. Only populated for the instagram row.';



COMMENT ON COLUMN "public"."social_connected_accounts"."error_count" IS 'Incremented on each publish failure. Reset to 0 on successful publish or token refresh.';



CREATE TABLE IF NOT EXISTS "public"."social_hashtag_sets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
