    "set_name" "text" NOT NULL,
    "hashtags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "pillar" "public"."social_pillar",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."social_media_assets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "updated_by" "uuid",
    "asset_kind" "public"."social_asset_kind" NOT NULL,
    "asset_name" "text" DEFAULT ''::"text" NOT NULL,
    "original_filename" "text" NOT NULL,
    "mime_type" "text" NOT NULL,
    "storage_path" "text" NOT NULL,
    "public_url" "text" NOT NULL,
    "file_size_bytes" bigint DEFAULT 0 NOT NULL,
    "duration_seconds" integer,
    "width_px" integer,
    "height_px" integer,
    "asset_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "usage_context" "text" DEFAULT ''::"text" NOT NULL,
    "is_client_approved" boolean DEFAULT false NOT NULL,
    "is_archived" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "social_media_assets_dimensions_valid" CHECK (((("width_px" IS NULL) OR ("width_px" >= 0)) AND (("height_px" IS NULL) OR ("height_px" >= 0)))),
    CONSTRAINT "social_media_assets_duration_valid" CHECK ((("duration_seconds" IS NULL) OR ("duration_seconds" >= 0))),
    CONSTRAINT "social_media_assets_file_size_valid" CHECK (("file_size_bytes" >= 0))
);




CREATE TABLE IF NOT EXISTS "public"."social_oauth_states" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "platform" "text" NOT NULL,
    "state" "text" NOT NULL,
    "code_verifier" "text",
    "redirect_to" "text",
    "expires_at" timestamp with time zone DEFAULT ("now"() + '00:10:00'::interval) NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."social_oauth_states" IS 'Temporary storage for OAuth PKCE state during social platform connection flows. Expires after 10 minutes.';



CREATE TABLE IF NOT EXISTS "public"."social_platform_credentials" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "platform" "text" NOT NULL,
    "external_account_id" "text" NOT NULL,
    "external_account_name" "text",
    "external_account_username" "text",
    "external_account_avatar_url" "text",
    "access_token" "text" NOT NULL,
    "refresh_token" "text",
    "token_expires_at" timestamp with time zone,
    "additional_data" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "scopes" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "last_used_at" timestamp with time zone,
    "last_error" "text",
    "failed_attempts" smallint DEFAULT 0 NOT NULL,
    "connected_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "disconnected_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "social_platform_credentials_platform_check" CHECK (("platform" = ANY (ARRAY['instagram'::"text", 'facebook'::"text", 'tiktok'::"text", 'linkedin'::"text", 'x'::"text", 'pinterest'::"text", 'youtube_shorts'::"text"])))
);




COMMENT ON TABLE "public"."social_platform_credentials" IS 'OAuth tokens for social media platform connections. Tokens are AES-256-GCM encrypted at the application layer before storage.';



COMMENT ON COLUMN "public"."social_platform_credentials"."access_token" IS 'Encrypted OAuth access token. Format: iv:authTag:ciphertext (all base64). Decrypt server-side using SOCIAL_TOKEN_ENCRYPTION_KEY.';



COMMENT ON COLUMN "public"."social_platform_credentials"."refresh_token" IS 'Encrypted OAuth refresh token, same format. Null for platforms without refresh tokens (Meta long-lived user tokens, Pinterest).';



COMMENT ON COLUMN "public"."social_platform_credentials"."additional_data" IS 'Platform-specific metadata: { page_id, page_access_token } for Facebook; { instagram_user_id, facebook_page_id } for Instagram; { open_id } for TikTok; { urn } for LinkedIn; { default_board_id } for Pinterest; { channel_id } for YouTube.';



COMMENT ON COLUMN "public"."social_platform_credentials"."failed_attempts" IS 'Consecutive failed publish attempts from this credential. Reset to 0 after first success. Chef is notified when this reaches 3.';



CREATE TABLE IF NOT EXISTS "public"."social_post_assets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "post_id" "uuid" NOT NULL,
    "asset_id" "uuid" NOT NULL,
    "is_primary" boolean DEFAULT false NOT NULL,
    "display_order" smallint DEFAULT 1 NOT NULL,
    "created_by" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "social_post_assets_display_order_valid" CHECK (("display_order" >= 1))
);




CREATE TABLE IF NOT EXISTS "public"."social_posts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "updated_by" "uuid",
    "post_code" "text" NOT NULL,
    "target_year" integer NOT NULL,
    "week_number" smallint NOT NULL,
    "slot_number" smallint NOT NULL,
    "schedule_at" timestamp with time zone NOT NULL,
    "editable_until" timestamp with time zone,
    "pillar" "public"."social_pillar" NOT NULL,
    "status" "public"."social_post_status" DEFAULT 'idea'::"public"."social_post_status" NOT NULL,
    "media_type" "public"."social_media_type" DEFAULT 'image'::"public"."social_media_type" NOT NULL,
    "title" "text" DEFAULT ''::"text" NOT NULL,
    "caption_master" "text" DEFAULT ''::"text" NOT NULL,
    "caption_instagram" "text" DEFAULT ''::"text" NOT NULL,
    "caption_facebook" "text" DEFAULT ''::"text" NOT NULL,
    "caption_tiktok" "text" DEFAULT ''::"text" NOT NULL,
    "caption_linkedin" "text" DEFAULT ''::"text" NOT NULL,
    "caption_x" "text" DEFAULT ''::"text" NOT NULL,
    "caption_pinterest" "text" DEFAULT ''::"text" NOT NULL,
    "caption_youtube_shorts" "text" DEFAULT ''::"text" NOT NULL,
    "hashtags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "cta" "text" DEFAULT ''::"text" NOT NULL,
    "offer_link" "text",
    "media_url" "text",
    "platforms" "public"."social_platform"[] DEFAULT '{instagram,facebook,tiktok,linkedin,pinterest,youtube_shorts}'::"public"."social_platform"[] NOT NULL,
    "campaign" "text" DEFAULT ''::"text" NOT NULL,
    "seasonal_flag" boolean DEFAULT false NOT NULL,
    "hot_swap_ready" boolean DEFAULT false NOT NULL,
    "notes" "text" DEFAULT ''::"text" NOT NULL,
    "queued_to_platforms" "public"."social_platform"[] DEFAULT '{}'::"public"."social_platform"[] NOT NULL,
    "published_to_platforms" "public"."social_platform"[] DEFAULT '{}'::"public"."social_platform"[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "mention_handles" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "collaborator_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "location_tag" "text" DEFAULT ''::"text" NOT NULL,
    "alt_text" "text" DEFAULT ''::"text" NOT NULL,
    "thumbnail_time_seconds" integer,
    "thumbnail_url" "text",
    "publish_checklist_notes" "text" DEFAULT ''::"text" NOT NULL,
    "preflight_ready" boolean DEFAULT false NOT NULL,
    "preflight_missing_items" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "publish_attempts" smallint DEFAULT 0 NOT NULL,
    "last_publish_at" timestamp with time zone,
    "last_publish_error" "text",
    "publish_errors" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "published_external_ids" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    CONSTRAINT "social_posts_editable_before_schedule" CHECK ((("editable_until" IS NULL) OR ("editable_until" <= "schedule_at"))),
    CONSTRAINT "social_posts_slot_valid" CHECK ((("slot_number" >= 1) AND ("slot_number" <= 7))),
    CONSTRAINT "social_posts_target_year_valid" CHECK ((("target_year" >= 2020) AND ("target_year" <= 2100))),
    CONSTRAINT "social_posts_thumbnail_seconds_valid" CHECK ((("thumbnail_time_seconds" IS NULL) OR (("thumbnail_time_seconds" >= 0) AND ("thumbnail_time_seconds" <= 3600)))),
    CONSTRAINT "social_posts_title_length" CHECK (("char_length"("title") <= 140)),
    CONSTRAINT "social_posts_week_valid" CHECK ((("week_number" >= 1) AND ("week_number" <= 53)))
);




COMMENT ON TABLE "public"."social_posts" IS 'Annual social content vault rows with platform variants and queue state for each scheduled slot.';



COMMENT ON COLUMN "public"."social_posts"."post_code" IS 'Human-readable slot id (for example 2026-W14-P3).';



COMMENT ON COLUMN "public"."social_posts"."publish_attempts" IS 'Number of times the publishing cron has attempted to publish this post (across all platforms).';



COMMENT ON COLUMN "public"."social_posts"."last_publish_at" IS 'Timestamp of last successful publish to any platform.';



COMMENT ON COLUMN "public"."social_posts"."last_publish_error" IS 'Human-readable last error message, shown to chef in the post editor.';



COMMENT ON COLUMN "public"."social_posts"."publish_errors" IS 'Per-platform error messages from last publish attempt. Keys are SocialPlatform values.';



COMMENT ON COLUMN "public"."social_posts"."published_external_ids" IS 'Per-platform external post IDs after successful publish. Keys are SocialPlatform values.';



CREATE TABLE IF NOT EXISTS "public"."social_queue_settings" (
    "tenant_id" "uuid" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "target_year" integer DEFAULT (EXTRACT(year FROM "now"()))::integer NOT NULL,
    "posts_per_week" smallint DEFAULT 5 NOT NULL,
    "timezone" "text" DEFAULT 'America/New_York'::"text" NOT NULL,
    "queue_days" smallint[] DEFAULT '{1,2,3,4,5}'::smallint[] NOT NULL,
    "queue_times" "text"[] DEFAULT '{11:00,13:00,11:00,13:00,11:00}'::"text"[] NOT NULL,
    "holdout_slots_per_month" smallint DEFAULT 2 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "social_queue_settings_holdout_valid" CHECK ((("holdout_slots_per_month" >= 0) AND ("holdout_slots_per_month" <= 10))),
    CONSTRAINT "social_queue_settings_posts_per_week_valid" CHECK ((("posts_per_week" >= 1) AND ("posts_per_week" <= 14))),
    CONSTRAINT "social_queue_settings_queue_days_range" CHECK (("queue_days" <@ ARRAY[(1)::smallint, (2)::smallint, (3)::smallint, (4)::smallint, (5)::smallint, (6)::smallint, (7)::smallint])),
    CONSTRAINT "social_queue_settings_queue_days_size" CHECK ((("cardinality"("queue_days") >= 1) AND ("cardinality"("queue_days") <= 7))),
    CONSTRAINT "social_queue_settings_queue_shape" CHECK (("cardinality"("queue_days") = "cardinality"("queue_times"))),
    CONSTRAINT "social_queue_settings_queue_time_size" CHECK ((("cardinality"("queue_times") >= 1) AND ("cardinality"("queue_times") <= 7))),
    CONSTRAINT "social_queue_settings_target_year_valid" CHECK ((("target_year" >= 2020) AND ("target_year" <= 2100)))
);




COMMENT ON TABLE "public"."social_queue_settings" IS 'Per-tenant defaults for annual social content planning and rolling queue cadence.';



