CREATE TABLE IF NOT EXISTS "public"."staff_members" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "role" "public"."staff_role" DEFAULT 'other'::"public"."staff_role" NOT NULL,
    "phone" "text",
    "email" "text",
    "hourly_rate_cents" integer DEFAULT 0 NOT NULL,
    "notes" "text",
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "contractor_type" "text" DEFAULT 'contractor'::"text",
    "ytd_payments_cents" integer DEFAULT 0,
    "tin" "text",
    "tin_type" "text",
    "business_name" "text",
    "address_street" "text",
    "address_city" "text",
    "address_state" "text",
    "address_zip" "text",
    "w9_signed_date" "date",
    "w9_document_url" "text",
    "w9_collected" boolean DEFAULT false NOT NULL,
    "kiosk_pin" "text",
    "location_id" "uuid",
    "staff_type" "text" DEFAULT 'regular'::"text" NOT NULL,
    "day_rate_cents" integer,
    "agency_name" "text",
    "payment_terms" "text",
    "tax_id_on_file" boolean DEFAULT false,
    "contract_notes" "text",
    CONSTRAINT "staff_members_contractor_type_check" CHECK (("contractor_type" = ANY (ARRAY['contractor'::"text", 'employee'::"text"]))),
    CONSTRAINT "staff_members_hourly_rate_cents_check" CHECK (("hourly_rate_cents" >= 0)),
    CONSTRAINT "staff_members_payment_terms_check" CHECK ((("payment_terms" IS NULL) OR ("payment_terms" = ANY (ARRAY['on_completion'::"text", 'net_15'::"text", 'net_30'::"text"])))),
    CONSTRAINT "staff_members_staff_type_check" CHECK (("staff_type" = ANY (ARRAY['regular'::"text", 'freelance'::"text"]))),
    CONSTRAINT "staff_members_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'inactive'::"text"]))),
    CONSTRAINT "staff_members_tin_type_check" CHECK ((("tin_type" IS NULL) OR ("tin_type" = ANY (ARRAY['ssn'::"text", 'ein'::"text"]))))
);




COMMENT ON TABLE "public"."staff_members" IS 'Chef''s roster of sous chefs, assistants, and service staff.';



COMMENT ON COLUMN "public"."staff_members"."hourly_rate_cents" IS 'Default hourly rate in cents. Can be overridden per event assignment.';



COMMENT ON COLUMN "public"."staff_members"."contractor_type" IS 'W-9 entity type. Used for Box 3 on 1099-NEC.';



COMMENT ON COLUMN "public"."staff_members"."tin" IS 'Tax Identification Number (SSN or EIN). Display last 4 digits only in UI.';



COMMENT ON COLUMN "public"."staff_members"."tin_type" IS 'ssn = Social Security Number. ein = Employer Identification Number (for LLCs/corps).';



COMMENT ON COLUMN "public"."staff_members"."w9_document_url" IS 'Optional URL to scanned W-9 document in Supabase Storage.';



COMMENT ON COLUMN "public"."staff_members"."w9_collected" IS 'True when a signed W-9 has been received and TIN is on file.';



COMMENT ON COLUMN "public"."staff_members"."kiosk_pin" IS 'SHA-256 hash of the staff member kiosk PIN (4-6 digits). NULL = no PIN set.';



