CREATE TABLE IF NOT EXISTS "public"."tax_settings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "tax_year" integer NOT NULL,
    "filing_status" "text" DEFAULT 'single'::"text" NOT NULL,
    "home_office_sqft" integer,
    "home_total_sqft" integer,
    "quarterly_payments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "home_deduction_method" "text" DEFAULT 'simplified'::"text" NOT NULL,
    "annual_rent_mortgage_cents" integer,
    "annual_utilities_cents" integer,
    "annual_insurance_home_cents" integer,
    "annual_repairs_cents" integer,
    "home_office_notes" "text",
    CONSTRAINT "tax_settings_filing_status_check" CHECK (("filing_status" = ANY (ARRAY['single'::"text", 'married_jointly'::"text", 'married_separately'::"text", 'head_of_household'::"text"]))),
    CONSTRAINT "tax_settings_home_deduction_method_check" CHECK (("home_deduction_method" = ANY (ARRAY['simplified'::"text", 'actual'::"text"])))
);




COMMENT ON TABLE "public"."tax_settings" IS 'Per-chef, per-year tax configuration. Used to personalize quarterly estimates and accountant export.';



COMMENT ON COLUMN "public"."tax_settings"."home_deduction_method" IS 'simplified = $5/sqft up to 300 sqft (max $1,500/yr). actual = office% × home expenses.';



COMMENT ON COLUMN "public"."tax_settings"."annual_rent_mortgage_cents" IS 'Annual rent or mortgage interest paid. Used only when home_deduction_method = actual.';



