CREATE OR REPLACE VIEW "public"."unified_inbox" AS
 SELECT "c"."id",
    "c"."tenant_id",
    'chat'::"text" AS "source",
    "c"."last_message_preview" AS "preview",
    COALESCE("c"."last_message_at", "c"."created_at") AS "activity_at",
    "c"."last_message_sender_id" AS "actor_id",
    NULL::"uuid" AS "conversation_id",
    "c"."inquiry_id",
    "c"."event_id",
    NULL::"uuid" AS "client_id",
    ("c"."context_type")::"text" AS "content_type",
    false AS "is_read"
   FROM "public"."conversations" "c"
  WHERE ("c"."last_message_at" IS NOT NULL)
UNION ALL
 SELECT "m"."id",
    "m"."tenant_id",
    'message'::"text" AS "source",
        CASE
            WHEN (("m"."subject" IS NOT NULL) AND ("m"."subject" <> ''::"text")) THEN (("m"."subject" || ': '::"text") || "left"("m"."body", 150))
            ELSE "left"("m"."body", 200)
        END AS "preview",
    COALESCE("m"."sent_at", "m"."created_at") AS "activity_at",
    "m"."from_user_id" AS "actor_id",
    NULL::"uuid" AS "conversation_id",
    "m"."inquiry_id",
    "m"."event_id",
    "m"."client_id",
    ("m"."channel")::"text" AS "content_type",
    false AS "is_read"
   FROM "public"."messages" "m"
  WHERE ("m"."status" = ANY (ARRAY['sent'::"public"."message_status", 'logged'::"public"."message_status"]))
UNION ALL
 SELECT "ws"."id",
    "ws"."tenant_id",
    'wix'::"text" AS "source",
        CASE
            WHEN ("ws"."submitter_name" IS NOT NULL) THEN ("ws"."submitter_name" || ' submitted a form'::"text")
            WHEN ("ws"."submitter_email" IS NOT NULL) THEN ("ws"."submitter_email" || ' submitted a form'::"text")
            ELSE 'New Wix form submission'::"text"
        END AS "preview",
    "ws"."created_at" AS "activity_at",
    NULL::"uuid" AS "actor_id",
    NULL::"uuid" AS "conversation_id",
    "ws"."inquiry_id",
    NULL::"uuid" AS "event_id",
    "ws"."client_id",
    'wix_form'::"text" AS "content_type",
    ("ws"."status" = 'completed'::"text") AS "is_read"
   FROM "public"."wix_submissions" "ws"
UNION ALL
 SELECT "n"."id",
    "n"."tenant_id",
    'notification'::"text" AS "source",
    COALESCE("n"."body", "n"."title") AS "preview",
    "n"."created_at" AS "activity_at",
    NULL::"uuid" AS "actor_id",
    NULL::"uuid" AS "conversation_id",
    "n"."inquiry_id",
    "n"."event_id",
    "n"."client_id",
    "n"."action" AS "content_type",
    ("n"."read_at" IS NOT NULL) AS "is_read"
   FROM "public"."notifications" "n"
  WHERE ("n"."archived_at" IS NULL);




