CREATE OR REPLACE VIEW "public"."upcoming_ingredient_demand" AS
 WITH "upcoming_events" AS (
         SELECT "e"."id" AS "event_id",
            "e"."tenant_id",
            "e"."event_date",
            "e"."guest_count",
            "e"."occasion"
           FROM "public"."events" "e"
          WHERE (("e"."status" = ANY (ARRAY['confirmed'::"public"."event_status", 'paid'::"public"."event_status"])) AND ("e"."event_date" >= CURRENT_DATE) AND ("e"."event_date" <= (CURRENT_DATE + '30 days'::interval)))
        ), "event_ingredients" AS (
         SELECT "ue"."tenant_id" AS "chef_id",
            "ue"."event_id",
            "ue"."event_date",
            "ue"."occasion",
            "i"."id" AS "ingredient_id",
            "i"."name" AS "ingredient_name",
            "ri"."unit",
            "sum"(("ri"."quantity" * COALESCE("c"."scale_factor", (1)::numeric))) AS "needed_qty",
            "i"."last_price_cents"
           FROM ((((("upcoming_events" "ue"
             JOIN "public"."menus" "m" ON (("m"."event_id" = "ue"."event_id")))
             JOIN "public"."dishes" "d" ON (("d"."menu_id" = "m"."id")))
             JOIN "public"."components" "c" ON ((("c"."dish_id" = "d"."id") AND ("c"."recipe_id" IS NOT NULL))))
             JOIN "public"."recipe_ingredients" "ri" ON (("ri"."recipe_id" = "c"."recipe_id")))
             JOIN "public"."ingredients" "i" ON (("i"."id" = "ri"."ingredient_id")))
          WHERE (NOT "i"."is_staple")
          GROUP BY "ue"."tenant_id", "ue"."event_id", "ue"."event_date", "ue"."occasion", "i"."id", "i"."name", "ri"."unit", "i"."last_price_cents"
        )
 SELECT "chef_id",
    "ingredient_id",
    "ingredient_name",
    "unit",
    "sum"("needed_qty") AS "total_needed_qty",
    "last_price_cents",
    "count"(DISTINCT "event_id") AS "event_count",
    "min"("event_date") AS "first_event_date",
    "array_agg"(DISTINCT "occasion") AS "events"
   FROM "event_ingredients" "ei"
  GROUP BY "chef_id", "ingredient_id", "ingredient_name", "unit", "last_price_cents";




