    CONSTRAINT "vendor_document_uploads_status_check" CHECK (("status" = ANY (ARRAY['uploaded'::"text", 'processing'::"text", 'review'::"text", 'completed'::"text", 'failed'::"text"])))
);




COMMENT ON TABLE "public"."vendor_document_uploads" IS 'Tracks uploaded vendor files and their staged processing status.';



CREATE TABLE IF NOT EXISTS "public"."vendor_invoice_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "vendor_invoice_id" "uuid" NOT NULL,
    "item_name" "text" NOT NULL,
    "quantity" numeric(10,3),
    "unit_price_cents" integer NOT NULL,
    "total_cents" integer NOT NULL,
    "matched_ingredient_id" "uuid",
    "price_changed" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."vendor_invoice_line_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "invoice_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "vendor_item_id" "uuid",
    "ingredient_id" "uuid",
    "description" "text" NOT NULL,
    "quantity" numeric(10,2) DEFAULT 1 NOT NULL,
    "unit_price_cents" integer DEFAULT 0 NOT NULL,
    "total_cents" integer DEFAULT 0 NOT NULL
);




COMMENT ON TABLE "public"."vendor_invoice_line_items" IS 'Line items on vendor invoices. Quantity × unit price = total.';



CREATE TABLE IF NOT EXISTS "public"."vendor_invoices" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "vendor_id" "uuid",
    "invoice_number" "text",
    "invoice_date" "date" NOT NULL,
    "total_cents" integer NOT NULL,
    "photo_url" "text",
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "vendor_invoices_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'matched'::"text", 'disputed'::"text"])))
);




COMMENT ON TABLE "public"."vendor_invoices" IS 'Purchase invoices from vendors. Each has line items for food cost tracking.';



CREATE TABLE IF NOT EXISTS "public"."vendor_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "ingredient_id" "uuid",
    "vendor_sku" "text",
    "vendor_item_name" "text" NOT NULL,
    "unit_price_cents" integer DEFAULT 0 NOT NULL,
    "unit_size" numeric(10,2),
    "unit_measure" "text",
    "last_updated" timestamp with time zone DEFAULT "now"() NOT NULL,
    "notes" "text",
    CONSTRAINT "vendor_items_unit_price_cents_check" CHECK (("unit_price_cents" >= 0))
);




COMMENT ON TABLE "public"."vendor_items" IS 'Per-vendor pricing for ingredients. One-time mapping: vendor catalog item → your ingredient.';



CREATE TABLE IF NOT EXISTS "public"."vendor_preferred_ingredients" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "ingredient_name" "text" NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."vendor_preferred_ingredients" IS 'Maps each ingredient to its preferred vendor for reordering.';



CREATE TABLE IF NOT EXISTS "public"."vendor_price_alert_settings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "price_change_percent_threshold" numeric(8,2) DEFAULT 5.00 NOT NULL,
    "updated_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "vendor_price_alert_settings_price_change_percent_threshol_check" CHECK ((("price_change_percent_threshold" >= (0)::numeric) AND ("price_change_percent_threshold" <= (1000)::numeric)))
);




COMMENT ON TABLE "public"."vendor_price_alert_settings" IS 'Per-vendor threshold used to filter price change alerts.';



CREATE TABLE IF NOT EXISTS "public"."vendor_price_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "item_name" "text" NOT NULL,
    "price_cents" integer NOT NULL,
    "unit" "text" NOT NULL,
    "recorded_at" "date" DEFAULT CURRENT_DATE NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




CREATE TABLE IF NOT EXISTS "public"."vendor_price_points" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "ingredient_id" "uuid",
    "item_name" "text" NOT NULL,
    "price_cents" integer NOT NULL,
    "unit" "text" NOT NULL,
    "recorded_at" "date" DEFAULT CURRENT_DATE NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "vendor_price_points_price_cents_check" CHECK (("price_cents" >= 0))
);




COMMENT ON TABLE "public"."vendor_price_points" IS 'Price point log per item per vendor. Tracks cost trends over time for purchasing decisions.';



COMMENT ON COLUMN "public"."vendor_price_points"."ingredient_id" IS 'Optional FK to ingredients table. item_name always stored for standalone price points.';



CREATE TABLE IF NOT EXISTS "public"."vendors" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "vendor_type" "text" DEFAULT 'grocery'::"text" NOT NULL,
    "phone" "text",
    "email" "text",
    "address" "text",
    "website" "text",
    "notes" "text",
    "is_preferred" boolean DEFAULT false NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reliability_score" numeric(5,2),
    "minimum_order_cents" integer,
    "category" "text",
    "contact_name" "text",
    "rating" integer,
    CONSTRAINT "vendors_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'inactive'::"text"]))),
    CONSTRAINT "vendors_vendor_type_check" CHECK (("vendor_type" = ANY (ARRAY['grocery'::"text", 'specialty'::"text", 'butcher'::"text", 'fishmonger'::"text", 'farm'::"text", 'liquor'::"text", 'equipment'::"text", 'bakery'::"text", 'produce'::"text", 'dairy'::"text", 'other'::"text"])))
);




COMMENT ON TABLE "public"."vendors" IS 'Chef supplier and vendor directory with contact info and preferred status.';



COMMENT ON COLUMN "public"."vendors"."reliability_score" IS 'Computed as on_time_deliveries / total_deliveries * 100. Updated deterministically.';



COMMENT ON COLUMN "public"."vendors"."minimum_order_cents" IS 'Minimum order amount in cents for this vendor.';



CREATE TABLE IF NOT EXISTS "public"."waitlist_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "client_id" "uuid",
    "requested_date" "date" NOT NULL,
    "requested_date_end" "date",
    "occasion" "text",
    "guest_count_estimate" integer,
    "notes" "text",
    "status" "text" DEFAULT 'waiting'::"text" NOT NULL,
    "contacted_at" timestamp with time zone,
    "converted_event_id" "uuid",
    "expires_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "position" integer DEFAULT 0 NOT NULL,
    "guest_phone" "text",
    "table_id" "uuid",
    CONSTRAINT "waitlist_entries_status_check" CHECK (("status" = ANY (ARRAY['waiting'::"text", 'contacted'::"text", 'converted'::"text", 'expired'::"text"])))
);




COMMENT ON TABLE "public"."waitlist_entries" IS 'Walk-in waitlist queue. Tracks position, estimated wait, and status through seating.';



CREATE TABLE IF NOT EXISTS "public"."waste_log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "station_id" "uuid" NOT NULL,
    "component_id" "uuid" NOT NULL,
    "staff_member_id" "uuid",
    "quantity" numeric(10,2) NOT NULL,
    "unit" "text" DEFAULT 'each'::"text" NOT NULL,
    "reason" "public"."waste_reason" DEFAULT 'other'::"public"."waste_reason" NOT NULL,
    "estimated_value_cents" integer DEFAULT 0,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);




COMMENT ON TABLE "public"."waste_log" IS 'Append-only waste/spoilage log. Never deleted. Feeds into food cost accuracy.';



CREATE TABLE IF NOT EXISTS "public"."waste_logs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chef_id" "uuid" NOT NULL,
    "event_id" "uuid",
    "ingredient_name" "text" NOT NULL,
    "quantity" numeric(10,3) NOT NULL,
    "unit" "text" NOT NULL,
