    "reason" "text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "waste_logs_reason_check" CHECK (("reason" = ANY (ARRAY['overcooked'::"text", 'leftover'::"text", 'spoilage'::"text", 'overportioned'::"text", 'trim'::"text", 'mistake'::"text", 'expired'::"text", 'other'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."webhook_deliveries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "endpoint_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "event_type" "text" NOT NULL,
    "payload" "jsonb" NOT NULL,
    "response_status" integer,
    "response_body" "text",
    "attempt_count" integer DEFAULT 1,
    "delivered_at" timestamp with time zone,
    "next_retry_at" timestamp with time zone,
    "status" "text" DEFAULT 'pending'::"text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "webhook_deliveries_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'delivered'::"text", 'failed'::"text", 'retrying'::"text"])))
);




CREATE TABLE IF NOT EXISTS "public"."webhook_endpoints" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "url" "text" NOT NULL,
    "description" "text",
    "events" "text"[] DEFAULT ARRAY['event.completed'::"text", 'payment.received'::"text", 'inquiry.created'::"text"] NOT NULL,
    "is_active" boolean DEFAULT true,
    "secret" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"()
);




CREATE TABLE IF NOT EXISTS "public"."webhook_events" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "provider" "text" NOT NULL,
    "event_type" "text" NOT NULL,
    "provider_event_id" "text",
    "status" "text" DEFAULT 'received'::"text" NOT NULL,
    "result" "jsonb",
    "error_text" "text",
    "payload_size_bytes" integer,
    "received_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "webhook_events_status_check" CHECK (("status" = ANY (ARRAY['received'::"text", 'processed'::"text", 'failed'::"text", 'skipped'::"text"])))
);




COMMENT ON TABLE "public"."webhook_events" IS 'Immutable audit trail of all incoming webhooks. Full payloads are NOT stored here — only event metadata and outcome summaries. Used for debugging, compliance, and payment dispute resolution.';



COMMENT ON COLUMN "public"."webhook_events"."provider_event_id" IS 'The external provider''s own event identifier. For Stripe: the event.id (e.g. evt_1234). For Wix: the wix_submission_id. Allows cross-referencing this log with the provider''s dashboard.';



CREATE TABLE IF NOT EXISTS "public"."website_stats_snapshots" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
