);




COMMENT ON TABLE "public"."website_stats_snapshots" IS 'Monthly website traffic snapshots. Can be entered manually or synced from Vercel Analytics / Plausible.';



CREATE TABLE IF NOT EXISTS "public"."wholesale_accounts" (
