CREATE OR REPLACE VIEW "public"."client_financial_summary" AS
 SELECT "c"."id" AS "client_id",
    "c"."tenant_id",
    "c"."lifetime_value_cents",
    "c"."total_events_count",
    "count"("e"."id") FILTER (WHERE ("e"."status" = 'completed'::"public"."event_status")) AS "total_events_completed",
    "count"("e"."id") FILTER (WHERE ("e"."status" = 'cancelled'::"public"."event_status")) AS "total_events_cancelled",
        CASE
            WHEN ("count"("e"."id") FILTER (WHERE ("e"."status" = 'completed'::"public"."event_status")) > 0) THEN ("c"."lifetime_value_cents" / "count"("e"."id") FILTER (WHERE ("e"."status" = 'completed'::"public"."event_status")))
            ELSE (0)::bigint
        END AS "average_spend_per_event",
    COALESCE("sum"("le"."amount_cents") FILTER (WHERE ("le"."entry_type" = 'tip'::"public"."ledger_entry_type")), (0)::bigint) AS "total_tips_given_cents",
        CASE
            WHEN ("c"."lifetime_value_cents" > 0) THEN ((COALESCE("sum"("le"."amount_cents") FILTER (WHERE ("le"."entry_type" = 'tip'::"public"."ledger_entry_type")), (0)::bigint))::numeric / ("c"."lifetime_value_cents")::numeric)
            ELSE (0)::numeric
        END AS "average_tip_percentage",
    COALESCE("sum"("e"."quoted_price_cents") FILTER (WHERE ("e"."payment_status" <> 'paid'::"public"."payment_status")), (0)::bigint) AS "outstanding_balance_cents",
    "c"."last_event_date",
    "c"."first_event_date",
    (CURRENT_DATE - "c"."last_event_date") AS "days_since_last_event",
    ((CURRENT_DATE - "c"."last_event_date") > 180) AS "is_dormant"
   FROM (("public"."clients" "c"
     LEFT JOIN "public"."events" "e" ON (("e"."client_id" = "c"."id")))
     LEFT JOIN "public"."ledger_entries" "le" ON (("le"."client_id" = "c"."id")))
  GROUP BY "c"."id";



CREATE OR REPLACE VIEW "public"."event_financial_summary" AS
 SELECT "e"."id" AS "event_id",
    "e"."tenant_id",
    "e"."quoted_price_cents",
    "e"."payment_status",
    COALESCE("sum"("le"."amount_cents") FILTER (WHERE ("le"."is_refund" = false)), (0)::bigint) AS "total_paid_cents",
    COALESCE("sum"("abs"("le"."amount_cents")) FILTER (WHERE ("le"."is_refund" = true)), (0)::bigint) AS "total_refunded_cents",
    COALESCE("sum"("le"."amount_cents"), (0)::bigint) AS "net_revenue_cents",
    COALESCE("sum"("ex"."amount_cents"), (0)::bigint) AS "total_expenses_cents",
    "e"."tip_amount_cents",
    (COALESCE("sum"("le"."amount_cents"), (0)::bigint) - COALESCE("sum"("ex"."amount_cents"), (0)::bigint)) AS "profit_cents",
        CASE
            WHEN (COALESCE("sum"("le"."amount_cents"), (0)::bigint) > 0) THEN (((COALESCE("sum"("le"."amount_cents"), (0)::bigint) - COALESCE("sum"("ex"."amount_cents"), (0)::bigint)))::numeric / (COALESCE("sum"("le"."amount_cents"), (1)::bigint))::numeric)
            ELSE (0)::numeric
        END AS "profit_margin",
        CASE
            WHEN (COALESCE("sum"("le"."amount_cents"), (0)::bigint) > 0) THEN ((COALESCE("sum"("ex"."amount_cents"), (0)::bigint))::numeric / (COALESCE("sum"("le"."amount_cents"), (1)::bigint))::numeric)
            ELSE (0)::numeric
        END AS "food_cost_percentage",
    ("e"."quoted_price_cents" - COALESCE("sum"("le"."amount_cents") FILTER (WHERE ("le"."is_refund" = false)), (0)::bigint)) AS "outstanding_balance_cents"
   FROM (("public"."events" "e"
     LEFT JOIN "public"."ledger_entries" "le" ON (("le"."event_id" = "e"."id")))
     LEFT JOIN "public"."expenses" "ex" ON (("ex"."event_id" = "e"."id")))
  GROUP BY "e"."id";



