CREATE POLICY "Anyone can record a scan" ON "public"."qr_scans" FOR INSERT WITH CHECK (true);



CREATE POLICY "Chef can manage own outreach log" ON "public"."prospect_outreach_log" USING (("chef_id" = "auth"."uid"())) WITH CHECK (("chef_id" = "auth"."uid"()));



CREATE POLICY "Chef can manage own production logs" ON "public"."recipe_production_log" USING (("tenant_id" IN ( SELECT "user_roles"."entity_id"
   FROM "public"."user_roles"
  WHERE ("user_roles"."auth_user_id" = "auth"."uid"())))) WITH CHECK (("tenant_id" IN ( SELECT "user_roles"."entity_id"
   FROM "public"."user_roles"
  WHERE ("user_roles"."auth_user_id" = "auth"."uid"()))));



CREATE POLICY "Chef can manage own scheduling rules" ON "public"."chef_scheduling_rules" USING (("tenant_id" IN ( SELECT "user_roles"."entity_id"
   FROM "public"."user_roles"
  WHERE (("user_roles"."auth_user_id" = "auth"."uid"()) AND ("user_roles"."role" = 'chef'::"public"."user_role"))))) WITH CHECK (("tenant_id" IN ( SELECT "user_roles"."entity_id"
